import { useState, useEffect, lazy, Suspense } from "react";
import { Routes, Route, useLocation } from "react-router-dom";
import { useTranslation } from "react-i18next";
import "./App.css";
import "./styles/reduced-motion.css";
import "./styles/print.css";
import { toast } from "react-toastify";

// Critical path - loaded eagerly (needed before first paint)
import Navbar from "./components/navbar/Navbar";
import SkipToContent from "./components/accessibility/SkipToContent";
import OfflineBanner from "./components/common/OfflineBanner";
import OfflineConflictModal from "./components/common/OfflineConflictModal";
import ScrollToTop from "./components/ScrollToTop";
import ErrorBoundary from "./components/common/ErrorBoundary";
import ProtectedRoute from "./components/auth/ProtectedRoute";
import NotificationToastContainer from "./components/common/NotificationProvider";
import { NotificationProvider } from "./context/NotificationContext";
import { AuthProvider } from "./context/AuthContext";
import { MyEventsProvider } from "./context/MyEventsContext";
import { SessionRecoveryProvider } from "./context/SessionRecoveryContext";
import useOfflineSync from "./hooks/useOfflineSync";
import useLenis from "./hooks/useLenis";
import useKeyboardShortcuts from "./hooks/useKeyboardShortcuts";
import { useRoutePrefetch } from "./hooks/useRoutePrefetch";
import PageTransition from "./components/common/PageTransition";
import Breadcrumbs from "./components/common/Breadcrumbs";
import {
  AuthFormSkeleton,
  ExploreEventsSkeleton,
  EventDetailSkeleton,
} from "./components/common/SkeletonLoaders";

// Route-level lazy splits - loaded only when route is visited
const Footer = lazy(() => import("./components/Layout/Footer"));
const Chatbot = lazy(() => import("./components/Chatbot"));
const AppRoutes = lazy(() => import("./components/AppRoutes"));
const EventRegistration = lazy(() => import("./Pages/Events/EventRegistration"));
const SavedEventsPage = lazy(() => import("./Pages/SavedEventsPage"));
const EventRecommendation = lazy(() => import("./Pages/EventRecommendation/EventRecommendation"));
const MatchmakingHub = lazy(() => import("./Pages/Networking/MatchmakingHub"));
const EventDetails = lazy(() => import("./Pages/Events/EventDetails"));
const ExploreEvents = lazy(() => import("./Pages/Events/EventsPage"));
const EventsPage = lazy(() => import("./Pages/Events/EventsPage"));

// Non-critical UI - deferred after first paint
const FluidCursor = lazy(() => import("./components/visual/FluidCursor"));
const KeyboardShortcutsModal = lazy(() => import("./components/common/KeyboardShortcutsModal"));
const OnboardingChecklist = lazy(() => import("./components/user/OnboardingChecklist"));
const FeedbackButton = lazy(() => import("./components/FeedbackButton"));
const ScrollToTopButton = lazy(() => import("./components/ScrollToTopButton"));
const BackToTop = lazy(() => import("./components/common/BackToTop"));
const ReminderChecker = lazy(() => import("./components/reminders/ReminderChecker"));
const SessionRecovery = lazy(() => import("./components/SessionRecovery"));
const ComparativeAnalytics = lazy(() => import("./components/Analytics/ComparativeAnalyticsDashboard"));


const OfflineSyncManager = () => {
  useOfflineSync();
  return null;
};

function App() {
  const { t } = useTranslation();
  const location = useLocation();
  const isDashboardOrAdmin =
    location?.pathname === "/dashboard" || location?.pathname === "/admin";
  const pageLoader = (
    <div className="flex items-center justify-center min-h-screen text-gray-500">
      {t("app.loading")}
    </div>
  );
  const [cursorEnabled, setCursorEnabled] = useState(() => {
    try {
      return localStorage.getItem("cursor") !== "off";
    } catch {
      return true; // fallback safe default
    }
  });
  const [showKeyboardModal, setShowKeyboardModal] = useState(false);
  const [showChatbot, setShowChatbot] = useState(false);
  const [isDesktop, setIsDesktop] = useState(window.innerWidth >= 1024);

  useLenis();
  useRoutePrefetch(); // Predictive route pre-loading

  useKeyboardShortcuts({
    onOpenHelp: () => setShowKeyboardModal(true),
    onCloseHelp: () => setShowKeyboardModal(false),
    isOpen: showKeyboardModal,
  });

  const toggleCursor = () => {
    const newValue = !cursorEnabled;
    setCursorEnabled(newValue);
    try {
      localStorage.setItem("cursor", newValue ? "on" : "off");
    } catch {
      // Ignore storage failures in private browsing or restricted contexts.
    }
  };

  useEffect(() => {
    const timer = setTimeout(() => {
      setShowChatbot(true);
    }, 3000);

    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    const handleResize = () => {
      setIsDesktop(window.innerWidth >= 1024);
    };

    window.addEventListener("resize", handleResize);

    return () => {
      window.removeEventListener("resize", handleResize);
    };
  }, []);

  useEffect(() => {
    const handleCursorPreference = (event) => {
      if (event?.detail?.cursorEnabled !== undefined) {
        setCursorEnabled(event.detail.cursorEnabled);
      }
    };

    window.addEventListener("cursorPreferenceChanged", handleCursorPreference);
    return () => {
      window.removeEventListener("cursorPreferenceChanged", handleCursorPreference);
    };
  }, []);

  useEffect(() => {
    const handleOnline = () => {
      toast.success(t("app.backOnline"), {
        position: "bottom-right",
        autoClose: 4000,
      });
    };
    const handleOffline = () => {
      toast.warning(t("app.offline"), {
        position: "bottom-right",
        autoClose: 5000,
      });
    };

    window.addEventListener("online", handleOnline);
    window.addEventListener("offline", handleOffline);
    if (!navigator.onLine) {
      handleOffline();
    }

    return () => {
      window.removeEventListener("online", handleOnline);
      window.removeEventListener("offline", handleOffline);
    };
  }, [t]);

  return (
    <ErrorBoundary>
      <AuthProvider>
        <NotificationProvider>
          <MyEventsProvider>
            <SessionRecoveryProvider>
              <NotificationToastContainer />
              <Suspense fallback={null}>
                <ReminderChecker />
              </Suspense>
              <OfflineSyncManager />

              <div className="App">
                <SkipToContent />
                <ErrorBoundary level="section" label="Navigation Bar">
                  <Navbar cursorEnabled={cursorEnabled} toggleCursor={toggleCursor} />
                </ErrorBoundary>

                <OfflineBanner />
                <OfflineConflictModal />

                <Suspense fallback={null}>
                  <KeyboardShortcutsModal
                    isOpen={showKeyboardModal}
                    onClose={() => setShowKeyboardModal(false)}
                  />
                </Suspense>

                <Suspense fallback={null}>
                  <OnboardingChecklist />
                </Suspense>

                <Breadcrumbs />

                <main
                  id="main-content"
                  className="relative z-10 min-h-[85vh] bg-bg text-text transition-colors duration-300"
                >
                  <PageTransition>
                    <ErrorBoundary>
                      <Routes location={location} key={location?.pathname || "default"}>
                        <Route
                          path="/register/:id"
                          element={
                            <ProtectedRoute>
                              <Suspense fallback={<AuthFormSkeleton />}>
                                <EventRegistration />
                              </Suspense>
                            </ProtectedRoute>
                          }
                        />
                        <Route
                          path="/explore"
                          element={
                            <Suspense fallback={<ExploreEventsSkeleton />}>
                              <EventsPage />
                            </Suspense>
                          }
                        />
                        <Route
                          path="/events/:id"
                          element={
                            <Suspense fallback={<EventDetailSkeleton />}>
                              <EventDetails />
                            </Suspense>
                          }
                        />
                        {/* TODO: Implement missing auth/dashboard routes
                          Pages do not exist:
                          - ./Pages/auth/Login
                          - ./Pages/auth/Signup
                          - ./Pages/dashboard/Dashboard
                          - ./Pages/Admin/AdminPanel
                          - ./Pages/user/Profile
                        */}
                        <Route
                          path="/event-recommendation"
                          element={<Suspense fallback={null}><EventRecommendation /></Suspense>}
                        />
                        <Route
                          path="/saved-events"
                          element={<Suspense fallback={null}><SavedEventsPage /></Suspense>}
                        />
                        <Route
                          path="/matchmaking"
                          element={
                            <ProtectedRoute>
                              <Suspense fallback={null}><MatchmakingHub /></Suspense>
                            </ProtectedRoute>
                          }
                        />
                        <Route
                          path="*"
                          element={
                            <Suspense fallback={pageLoader}>
                              <AppRoutes />
                            </Suspense>
                          }
                        />

                      </Routes>
                    </ErrorBoundary>
                  </PageTransition>
                </main>

                <ScrollToTop />
                {showChatbot && (
                  <ErrorBoundary level="section" label="Chatbot Assist" silent>
                    <Suspense fallback={null}>
                      <Chatbot />
                    </Suspense>
                  </ErrorBoundary>
                )}

                <ErrorBoundary level="section" label="Footer">
                  <Suspense fallback={null}>
                    {!isDashboardOrAdmin && <Footer />}
                  </Suspense>
                </ErrorBoundary>

                <Suspense fallback={null}>
                  <ScrollToTopButton />
                </Suspense>
                {/* Enhanced back-to-top with progress ring - appears at 400px */}
                <Suspense fallback={null}>
                  <BackToTop />
                </Suspense>
                <Suspense fallback={null}>
                  <FeedbackButton />
                </Suspense>
                <Suspense fallback={null}>
                  <SessionRecovery />
                </Suspense>

                {isDesktop && (
                  <ErrorBoundary level="section" label="Custom Cursor" silent>
                    <Suspense fallback={null}>
                      <FluidCursor enabled={cursorEnabled} />
                    </Suspense>
                </ErrorBoundary>
                )}
              </div>
            </SessionRecoveryProvider>
          </MyEventsProvider>
        </NotificationProvider>
      </AuthProvider>
    </ErrorBoundary>
  );
}
export default App;

import React from 'react';
const AdminPanel = () => <div className="p-6"><h1 className="text-2xl font-bold">Admin Panel</h1></div>;
export default AdminPanel;

import { useCallback, useMemo, useState } from "react";
import { Calendar, dateFnsLocalizer } from "react-big-calendar";
import {
  addDays,
  addHours,
  format,
  getDay,
  isSameDay,
  isSameMonth,
  parse,
  parseISO,
  startOfDay,
  startOfWeek,
} from "date-fns";
import { enUS } from "date-fns/locale";
import {
  CalendarDays,
  ChevronLeft,
  ChevronRight,
  Clock,
  ExternalLink,
  MapPin,
  RefreshCw,
} from "lucide-react";
import { Link } from "react-router-dom";
import { darkTheme } from "../../components/styles/theme";
import { getEventStatus } from "../../utils/eventUtils";
import useCalendarEvents from "./useCalendarEvents";
import { SkeletonBlock } from "../../components/common/SkeletonLoaders";
import EmptyState from "../../components/common/EmptyState";
import "react-big-calendar/lib/css/react-big-calendar.css";
import "./CalendarPage.css";

const locales = {
  "en-US": enUS,
};

const localizer = dateFnsLocalizer({
  format,
  parse,
  startOfWeek: (date) => startOfWeek(date, { weekStartsOn: 0 }),
  getDay,
  locales,
});

const parseTimeString = (value = "") => {
  const trimmed = String(value || "").trim();
  if (!trimmed) return null;

  const ampmMatch = trimmed.match(/^(\d{1,2}):(\d{2})\s*([AP]M)$/i);
  if (ampmMatch) {
    let hours = parseInt(ampmMatch[1], 10);
    const minutes = parseInt(ampmMatch[2], 10);
    const period = ampmMatch[3].toUpperCase();

    if (period === "PM" && hours < 12) hours += 12;
    if (period === "AM" && hours === 12) hours = 0;

    return { hours, minutes };
  }

  const twentyFourMatch = trimmed.match(/^(\d{1,2}):(\d{2})$/);
  if (twentyFourMatch) {
    return {
      hours: parseInt(twentyFourMatch[1], 10),
      minutes: parseInt(twentyFourMatch[2], 10),
    };
  }

  return null;
};

const buildDateTime = (dateValue, timeValue) => {
  if (!dateValue) return null;
  const base = parseISO(dateValue);
  if (Number.isNaN(base.getTime())) return null;

  const timeParts = parseTimeString(timeValue);
  if (!timeParts) return base;

  base.setHours(timeParts.hours, timeParts.minutes, 0, 0);
  return base;
};

const getEventDateRange = (event) => {
  const startDate = event?.startDate || event?.date;
  const endDate = event?.endDate || event?.date || startDate;
  if (!startDate) return null;

  const startTime = event?.startTime || event?.time || "";
  const endTime = event?.endTime || "";

  const start = buildDateTime(startDate, startTime);
  if (!start) return null;

  const hasTime = Boolean(startTime);
  let end = buildDateTime(endDate, endTime);

  if (!end) {
    end = hasTime ? addHours(start, 2) : start;
  }

  if (end < start) {
    end = addHours(start, 1);
  }

  return {
    start: hasTime ? start : startOfDay(start),
    end: hasTime ? end : addDays(startOfDay(end), 1),
    allDay: !hasTime,
  };
};

const toDateKey = (date) => format(date, "yyyy-MM-dd");

const getDateKeysInRange = (start, end) => {
  if (!start || !end) return [];

  const keys = [];
  let cursor = startOfDay(start);
  const last = startOfDay(end);

  while (cursor <= last) {
    keys.push(toDateKey(cursor));
    cursor = addDays(cursor, 1);
  }

  return keys;
};

const CalendarToolbar = ({ label, onNavigate }) => {
  return (
    <div className="flex flex-wrap items-center justify-between gap-3 px-1 py-2">
      <div className="flex items-center gap-2 text-sm font-semibold text-slate-700 dark:text-slate-200">
        <CalendarDays className="h-5 w-5 text-sky-500" />
        <span className="tracking-tight">{label}</span>
      </div>
      <div className="flex items-center gap-2">
        <button
          type="button"
          onClick={() => onNavigate("PREV")}
          className="inline-flex items-center justify-center rounded-full border border-slate-200 bg-white px-3 py-1.5 text-xs font-semibold text-slate-600 transition hover:border-slate-300 hover:text-slate-900 dark:border-slate-700 dark:bg-slate-900 dark:text-slate-200 dark:hover:border-slate-500"
          aria-label="Previous month"
        >
          <ChevronLeft className="h-4 w-4" />
        </button>
        <button
          type="button"
          onClick={() => onNavigate("TODAY")}
          className="inline-flex items-center justify-center rounded-full border border-slate-200 bg-white px-3 py-1.5 text-xs font-semibold text-slate-600 transition hover:border-slate-300 hover:text-slate-900 dark:border-slate-700 dark:bg-slate-900 dark:text-slate-200 dark:hover:border-slate-500"
        >
          Today
        </button>
        <button
          type="button"
          onClick={() => onNavigate("NEXT")}
          className="inline-flex items-center justify-center rounded-full border border-slate-200 bg-white px-3 py-1.5 text-xs font-semibold text-slate-600 transition hover:border-slate-300 hover:text-slate-900 dark:border-slate-700 dark:bg-slate-900 dark:text-slate-200 dark:hover:border-slate-500"
          aria-label="Next month"
        >
          <ChevronRight className="h-4 w-4" />
        </button>
      </div>
    </div>
  );
};

const CalendarPage = () => {
  const { events, isLoading, loadError, refresh } = useCalendarEvents();
  const [selectedDate, setSelectedDate] = useState(startOfDay(new Date()));

  const normalizedEvents = useMemo(
    () => events.map((event) => ({ ...event, status: getEventStatus(event) })),
    [events]
  );

  const upcomingEvents = useMemo(
    () =>
      normalizedEvents.filter((event) => {
        const status = event.status || getEventStatus(event);
        return status !== "past" && status !== "ended";
      }),
    [normalizedEvents]
  );

  const upcomingEventsWithRange = useMemo(
    () =>
      upcomingEvents
        .map((event) => ({ event, range: getEventDateRange(event) }))
        .filter((entry) => entry.range),
    [upcomingEvents]
  );

  const calendarEvents = useMemo(
    () =>
      upcomingEventsWithRange.map(({ event, range }) => ({
        id: event.id,
        title: event.title,
        start: range.start,
        end: range.end,
        allDay: range.allDay,
        resource: event,
      })),
    [upcomingEventsWithRange]
  );

  const eventsByDay = useMemo(() => {
    const map = new Map();

    upcomingEventsWithRange.forEach(({ event, range }) => {
      const endForKeys = range.allDay ? addDays(range.end, -1) : range.end;
      const keys = getDateKeysInRange(range.start, endForKeys);
      const entry = {
        ...event,
        start: range.start,
        end: range.end,
        allDay: range.allDay,
      };

      keys.forEach((key) => {
        if (!map.has(key)) {
          map.set(key, [entry]);
        } else {
          map.get(key).push(entry);
        }
      });
    });

    map.forEach((items) =>
      items.sort((first, second) => first.start - second.start)
    );

    return map;
  }, [upcomingEventsWithRange]);

  const selectedDateKey = toDateKey(selectedDate);
  const selectedEvents = eventsByDay.get(selectedDateKey) || [];

  const handleSelectSlot = useCallback((slotInfo) => {
    setSelectedDate(startOfDay(slotInfo.start));
  }, []);

  const handleSelectEvent = useCallback((calendarEvent) => {
    if (calendarEvent?.start) {
      setSelectedDate(startOfDay(calendarEvent.start));
    }
  }, []);

  const handleNavigate = useCallback(
    (date) => {
      if (!isSameMonth(date, selectedDate)) {
        setSelectedDate(startOfDay(date));
      }
    },
    [selectedDate]
  );

  const dayPropGetter = useCallback(
    (date) => {
      const key = toDateKey(date);
      const hasEvents = eventsByDay.has(key);
      const isSelected = isSameDay(date, selectedDate);
      const classes = [
        hasEvents ? "calendar-day--has-events" : "",
        isSelected ? "calendar-day--selected" : "",
      ]
        .filter(Boolean)
        .join(" ");

      return { className: classes };
    },
    [eventsByDay, selectedDate]
  );

  return (
    <div className={`${darkTheme.section} min-h-screen`}>
      <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-10">
        <div className="flex flex-col gap-6 lg:flex-row lg:items-end lg:justify-between">
          <div>
            <div className="inline-flex items-center gap-2 rounded-full bg-sky-100 px-3 py-1 text-[10px] font-semibold uppercase tracking-[0.2em] text-sky-700 dark:bg-sky-500/10 dark:text-sky-300">
              Calendar View
            </div>
            <h1 className="mt-4 text-3xl sm:text-4xl font-extrabold tracking-tight text-slate-900 dark:text-white">
              Upcoming Events Calendar
            </h1>
            <p className="mt-3 max-w-2xl text-sm text-slate-600 dark:text-slate-400">
              Explore upcoming events in a monthly grid. Tap any date to review what is happening
              that day and jump into the details.
            </p>
          </div>
          <div className="flex flex-wrap items-center gap-3">
            <div className="rounded-full border border-slate-200 bg-white px-4 py-2 text-xs font-semibold text-slate-600 shadow-sm dark:border-slate-700 dark:bg-slate-900 dark:text-slate-300">
              Upcoming events: {upcomingEvents.length}
            </div>
            <button
              type="button"
              onClick={refresh}
              className="inline-flex items-center gap-2 rounded-full bg-slate-900 px-4 py-2 text-xs font-semibold text-white shadow-sm transition hover:bg-slate-800 dark:bg-slate-100 dark:text-slate-900 dark:hover:bg-white"
             aria-label="button">
              <RefreshCw className={`h-4 w-4 ${isLoading ? "animate-spin" : ""}`} />
              Refresh
            </button>
          </div>
        </div>

        {loadError && !isLoading ? (
          <div className="mt-6 rounded-3xl border border-red-200 bg-white p-6 text-sm text-red-700 shadow-sm dark:border-red-500/30 dark:bg-slate-950 dark:text-red-300">
            <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
              <span>{loadError}</span>
              <button
                type="button"
                onClick={refresh}
                className="inline-flex items-center gap-2 rounded-full bg-red-600 px-3 py-1.5 text-xs font-semibold text-white transition hover:bg-red-700"
               aria-label="button">
                Try again
              </button>
            </div>
          </div>
        ) : null}

          <div className="mt-8 grid gap-6 grid-cols-1 lg:grid-cols-2 items-start">
          <div className="eventra-calendar rounded-3xl bg-white/80 p-4 shadow-lg backdrop-blur-sm dark:bg-slate-950/80">
            <div className="h-[450px] lg:h-[620px]">
              <Calendar
                localizer={localizer}
                events={calendarEvents}
                defaultView="month"
                views={["month"]}
                toolbar
                popup
                selectable
                onSelectSlot={handleSelectSlot}
                onSelectEvent={handleSelectEvent}
                onNavigate={handleNavigate}
                dayPropGetter={dayPropGetter}
                components={{ toolbar: CalendarToolbar }}
              />
            </div>
          </div>

          <aside className="rounded-3xl border border-slate-200 bg-white p-5 sm:p-6 shadow-lg dark:border-slate-800 dark:bg-slate-950 mt-2 lg:mt-0">
            <div className="flex items-start justify-between gap-4">
              <div>
                <p className="text-xs font-semibold uppercase tracking-[0.2em] text-slate-400 dark:text-slate-500">
                  Selected Day
                </p>
                <h2 className="mt-2 text-lg font-bold text-slate-900 dark:text-white">
                  {format(selectedDate, "EEEE, MMM d, yyyy")}
                </h2>
              </div>
              <div className="rounded-full bg-slate-100 px-3 py-1 text-xs font-semibold text-slate-600 dark:bg-slate-800 dark:text-slate-300">
                {selectedEvents.length} event{selectedEvents.length === 1 ? "" : "s"}
              </div>
            </div>
            <div className="mt-6 space-y-4">
              {isLoading ? (
                <>
                  <div className="sr-only" role="status" aria-live="polite">
                    Loading events for this day...
                  </div>
                  <div className="space-y-4" aria-hidden="true">
                    {[...Array(2)].map((_, i) => (
                      <div key={i} className="p-4 rounded-2xl border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 animate-pulse">
                        <SkeletonBlock className="h-5 w-3/4 mb-3" />
                        <SkeletonBlock className="h-4 w-1/2" />
                      </div>
                    ))}
                  </div>
                </>
              ) : null}

              {!isLoading && selectedEvents.length === 0 ? (
                <EmptyState
                  compact={true}
                  icon={CalendarDays}
                  title="No events scheduled"
                  description="No upcoming events scheduled for this day."
                />
              ) : null}

              {!isLoading && selectedEvents.length > 0
                ? selectedEvents.map((event) => (
                    <Link
                      to={`/events/${event.id}`}
                      key={event.id}
                      className="block rounded-2xl border border-slate-200 bg-white p-4 shadow-sm transition-all duration-200 hover:border-sky-400 hover:shadow-md hover:scale-[1.01] dark:border-slate-800 dark:bg-slate-900 dark:hover:border-sky-500 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-sky-500 focus-visible:ring-offset-2 dark:focus-visible:ring-offset-slate-950 group"
                    >
                      <div className="flex items-center justify-between">
                        {event.type ? (
                          <span className="inline-flex rounded-[6px] bg-slate-100 dark:bg-slate-800 px-2 py-0.5 text-[9px] font-semibold uppercase tracking-[0.1em] text-slate-500 dark:text-slate-400">
                            {event.type}
                          </span>
                        ) : (
                          <span />
                        )}
                        <ChevronRight className="h-4 w-4 text-slate-400 dark:text-slate-500 transition-transform group-hover:translate-x-0.5" />
                      </div>

                      <h4 className="mt-2 text-[15px] font-bold text-slate-900 dark:text-white line-clamp-2 break-words leading-snug">
                        {event.title}
                      </h4>

                      <div className="mt-3 flex flex-wrap items-center gap-x-4 gap-y-1.5 text-xs text-slate-500 dark:text-slate-400">
                        <span className="inline-flex items-center gap-1 shrink-0">
                          <Clock className="h-3.5 w-3.5 text-sky-500" />
                          {event.time || event.startTime || (event.allDay ? "All day" : "TBD")}
                        </span>
                        <span className="inline-flex items-center gap-1 min-w-0">
                          <MapPin className="h-3.5 w-3.5 text-sky-500 shrink-0" />
                          <span className="truncate max-w-[200px]" title={event.location || "Location TBD"}>
                            {event.location || "Location TBD"}
                          </span>
                        </span>
                      </div>
                    </Link>
                  ))
                : null}
            </div>
          </aside>
