  return (
    <div className="bg-white dark:bg-gray-900 rounded-3xl shadow-xl border border-gray-100 dark:border-gray-800 p-4 sm:p-6 mb-8 overflow-hidden calendar-container">
      <style dangerouslySetInnerHTML={{__html: `
