    clearPresetError();
    setEditingPresetId(preset.id);
    setEditingPresetName(preset.name);
  };

  const handleRenamePreset = (presetId) => {
    const result = renamePreset(presetId, editingPresetName);
    if (!result.error) {
      setEditingPresetId("");
      setEditingPresetName("");
    }
  };

