        const realEvents = res.status === 200 ? res.data : [];
        const suggestions = suggestAlternativeEvents(event, realEvents, myEvents);
        setConflictData({
          conflicts: conflictCheck.conflicts,
          suggestions,
        });
      } catch (err) {
        logger.error("Failed to fetch alternative events", err);
