              style={{ fontFamily: "\"Inter\", system-ui, sans-serif" }}
            >
              <motion.span className="block text-sm font-medium text-gray-500 dark:text-gray-400">
                <RespawningText texts={TAGLINE_TEXTS} />
              </motion.span>

