                <AnimatePresence mode="wait">
                  <motion.span
                    key={phraseIndex}
                    className="block text-2xl font-extrabold text-gray-900 dark:text-white sm:text-3xl md:text-4xl lg:text-5xl"
                    exit={{
                      opacity: 0,
