          </motion.div>

          {!searchTerm.trim() && (
            <ErrorBoundary level="section" label="Statistics">
              <motion.div
                variants={fadeUp}
                style={{ y: isTouch || prefersReducedMotion ? 0 : yStats, willChange: "transform" }}
