          <div className="relative">
            {rank <= 3 && (
              <span
                className={`absolute -inset-0.5 rounded-full blur-xs opacity-75 animate-pulse bg-gradient-to-r ${
                  rank === 1
                    ? "from-yellow-400 to-amber-500"
                    : rank === 2
                    ? "from-slate-200 to-zinc-400"
                    : "from-amber-600 to-orange-500"
                }`}
                aria-hidden="true"
              />
            )}
            <img
