          <span className="font-extrabold">
            <AnimatedCounter value={c.prs} />
          </span>
        </div>
      </td>
    </motion.tr>
  );
}

export default function LeaderboardTable({
  loading,
  error,
  currentContributors,
  sortedContributors,
  ranksMap,
  streaks,
  currentPage,
  totalPages,
  setCurrentPage,
  setSearch,
  setActiveCategory,
  setSortBy,
  streamStatus,
  lastUpdated,
  onRefresh,
}) {
  const renderError = () => (
    <div className="p-8 text-center">
      <p className="text-rose-500 font-medium">{error}</p>
      <button
        onClick={onRefresh}
        className="mt-4 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors"
      >
        Try Again
      </button>
    </div>
  );

  const renderLoading = () => (
    <div role="status" aria-live="polite">
      <span className="sr-only">Loading leaderboard...</span>
      <SkeletonLeaderboard rows={10} />
    </div>
  );

  const renderEmpty = () => (
    <tr>
      <td colSpan={5} className="px-6 py-12 text-center text-slate-500 dark:text-slate-400">
        <div className="flex flex-col items-center gap-3">
          <Search className="w-8 h-8 text-slate-300 dark:text-slate-700" aria-hidden="true" />
          <p className="font-medium">No contributors found</p>
          <p className="text-sm">Try adjusting your search or filters</p>
          <button
            onClick={() => {
              setSearch("");
              setActiveCategory("overall");
              setSortBy("points");
            }}
            className="mt-2 px-4 py-2 text-sm font-medium text-indigo-600 dark:text-indigo-400 hover:text-indigo-700 dark:hover:text-indigo-300 transition-colors"
          >
            Clear filters
          </button>
        </div>
      </td>
    </tr>
  );

  const renderPagination = () => {
    if (totalPages <= 1) return null;

    return (
      <div className="flex justify-between items-center py-4 px-6 border-t border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50">
        <span className="text-xs font-medium text-slate-500">
          Page {currentPage} of {totalPages}
        </span>
        <div className="flex items-center gap-2" role="navigation" aria-label="Pagination">
          <button
            onClick={() => setCurrentPage((p) => Math.max(p - 1, 1))}
            disabled={currentPage === 1}
            className="rounded-lg border border-slate-200 bg-white p-2 text-slate-600 transition-all hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-[#E0E9F2] disabled:opacity-50"
            aria-label="Previous page"
          >
            <ChevronLeft className="w-3 h-3" aria-hidden="true" />
          </button>
          <button
            onClick={() => setCurrentPage((p) => Math.min(p + 1, totalPages))}
            disabled={currentPage === totalPages}
            className="rounded-lg border border-slate-200 bg-white p-2 text-slate-600 transition-all hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-[#E0E9F2] disabled:opacity-50"
            aria-label="Next page"
          >
            <ChevronRight className="w-3 h-3" aria-hidden="true" />
          </button>
        </div>
      </div>
    );
  };

  const renderTable = () => (
    <div className="overflow-x-auto">
      <table className="min-w-full divide-y divide-slate-100">
        <thead className="bg-slate-50/90">
          <tr>
            {["Rank", "Contributor", "Achievement", "Points", "PRs"].map((header) => (
              <th
                key={header}
                scope="col"
                className="px-6 py-4 text-left text-xs font-bold uppercase tracking-[0.18em] text-slate-500"
              >
                {header}
              </th>
            ))}
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-100 bg-white">
          <AnimatePresence mode="popLayout">
            {currentContributors.length > 0 ? (
              currentContributors.map((c, index) => {
                const rank = ranksMap[c.username];
                const badge = getAchievementBadge(rank, c.prs, c.points);
                const streak = streaks[c.username];

                return (
                  <TableRow
                    key={c.username}
                    c={c}
                    rank={rank}
                    badge={badge}
                    streak={streak}
                    index={index}
                  />
                );
              })
            ) : (
              renderEmpty()
            )}
          </AnimatePresence>
        </tbody>
      </table>

      {renderPagination()}
    </div>
  );

  return (
    <section
      className="overflow-hidden rounded-[32px] border border-slate-200/70 bg-white/90 shadow-[0_24px_70px_rgba(15,23,42,0.08)] backdrop-blur-xl"
      aria-labelledby="leaderboard-table-title"
    >
      <h2 id="leaderboard-table-title" className="sr-only">Contributor Rankings</h2>

      {error ? renderError() : loading ? renderLoading() : renderTable()}

      <div className="flex items-center justify-between border-t border-slate-100 bg-slate-50/60 px-6 py-3">
        {lastUpdated && (
          <time className="text-xs font-medium text-slate-500" dateTime={lastUpdated}>
            {lastUpdated}
          </time>
        )}
        <LiveStatusBadge status={streamStatus} />
      </div>
    </section>
  );
}

import { Star, Github, ExternalLink, AlertCircle, GitPullRequest, Cpu, Code2, Layers, Bookmark } from "lucide-react";
import { useState, useEffect, useRef, memo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import useReducedMotion from "../../hooks/useReducedMotion.js";
import { fetchGitHubRepo, getGitHubRepoDetails } from "../../utils/githubApiClient.js";
import { safeJsonParse } from "../../utils/safeJsonParse";
import { useAuth } from "../../context/AuthContext.js";
import { toast } from "react-toastify";
import { projectService } from "../../services/projectService.js";

// Cache Keys & Constants
const CACHE_KEY = "eventra_github_metrics_cache";
const CACHE_TTL = 1 * 60 * 60 * 1000; // 1 hour expiration

// Status Badge Styling Helper
const getStatusColor = (status) => {
  if (!status) return "bg-slate-100 text-white dark:bg-slate-900/50 dark:text-white";
  switch (status.toLowerCase()) {
    case "active":
      return "bg-emerald-100/80 text-white dark:bg-emerald-950/40 dark:text-emerald-300 border border-emerald-200/40 dark:border-emerald-900/30";
    case "maintenance":
      return "bg-amber-100/80 text-white dark:bg-amber-950/40 dark:text-amber-300 border border-amber-200/40 dark:border-amber-900/30";
    case "archived":
      return "bg-rose-100/80 text-white dark:bg-rose-950/40 dark:text-rose-300 border border-rose-200/40 dark:border-rose-900/30";
    default:
      return "bg-sky-100/80 text-white dark:bg-sky-950/40 dark:text-sky-300 border border-sky-200/40 dark:border-sky-900/30";
  }
};

// Difficulty Styling Helper
const getDifficultyColor = (difficulty) => {
  if (!difficulty) return "bg-slate-50 text-white dark:bg-slate-900 dark:text-white border-slate-200/50";
  switch (difficulty.toLowerCase()) {
    case "beginner":
  return "bg-sky-900/40 text-white border-sky-500/30";

case "intermediate":
  return "bg-pink-900/40 text-white border-pink-500/30";

case "advanced":
  return "bg-rose-900/40 text-white border-rose-500/30";

default:
  return "bg-slate-800 text-white border-slate-600";
  }
};

// --- Concentric SVG Technology Rings Component ---
const ConcentricTechRings = ({ techStack }) => {
  const prefersReducedMotion = useReducedMotion();
  const list = techStack && techStack.length > 0 ? techStack.slice(0, 3) : ["React", "CSS", "JS"];

  // Custom visual colors mapped to standard technology types
  const techGradients = [
    { from: "#ec4899", to: "#8b5cf6", name: "PinkViolet" }, // Outer
    { from: "#0ea5e9", to: "#10b981", name: "SkyTeal" },    // Middle
    { from: "#f59e0b", to: "#ef4444", name: "AmberRose" },  // Inner
  ];

  // Preset Sweeps (percentages)
  const sweeps = [65, 45, 25];
  const ringConfigs = [
    { radius: 32, circ: 2 * Math.PI * 32 }, // outer
    { radius: 24, circ: 2 * Math.PI * 24 }, // middle
    { radius: 16, circ: 2 * Math.PI * 16 }, // inner
  ];

  return (
    <div className="flex items-center gap-5 p-4 rounded-2xl bg-slate-50/40 dark:bg-slate-950/35 border border-slate-100/50 dark:border-slate-800/20 backdrop-blur-xs">
      {/* SVG Container */}
      <div className="relative w-[92px] h-[92px] shrink-0">
        <svg className="w-full h-full -rotate-90" viewBox="0 0 88 88">
          <defs>
            {techGradients.map((grad, i) => (
              <linearGradient key={i} id={`grad-${grad.name}`} x1="0%" y1="0%" x2="100%" y2="100%">
                <stop offset="0%" stopColor={grad.from} />
                <stop offset="100%" stopColor={grad.to} />
              </linearGradient>
            ))}
          </defs>

          {/* Underlay / Background concentric circles */}
          {ringConfigs.map((cfg, i) => (
            <circle
              key={`bg-${i}`}
              cx="44"
              cy="44"
              r={cfg.radius}
              className="stroke-slate-200/40 dark:stroke-slate-800/40"
              strokeWidth="4.5"
              fill="none"
            />
          ))}

          {/* Active progress rings with mount animations */}
          {ringConfigs.map((cfg, i) => {
            const pct = sweeps[i];
            const strokeDashoffset = cfg.circ - (cfg.circ * pct) / 100;
            const gradName = techGradients[i].name;

            return (
              <motion.circle
                key={`progress-${i}`}
                cx="44"
                cy="44"
                r={cfg.radius}
                stroke={`url(#grad-${gradName})`}
                strokeWidth="4.5"
                strokeLinecap="round"
                fill="none"
                strokeDasharray={cfg.circ}
                initial={{ strokeDashoffset: cfg.circ }}
                animate={{ strokeDashoffset }}
                transition={{ duration: prefersReducedMotion ? 0 : 1.2, delay: 0.15 * i, ease: "easeOut" }}
              />
            );
          })}
        </svg>
        <div className="absolute inset-0 flex items-center justify-center">
          <Layers className="w-4 h-4 text-indigo-500/70 animate-pulse" />
        </div>
      </div>

      {/* Legend & Breakdown bars */}
      <div className="flex-1 space-y-2.5 min-w-0">
        {list.map((tech, i) => {
          const pct = sweeps[i];
          const grad = techGradients[i];

          return (
            <div key={tech} className="space-y-1">
              <div className="flex items-center justify-between text-[11px] font-black tracking-tight">
                <span className="text-white dark:text-white truncate pr-1">
                  {tech}
                </span>
                <span className="text-white dark:text-white">
                  {pct}%
                </span>
              </div>
              <div className="w-full h-1.5 rounded-full bg-slate-200/40 dark:bg-slate-800/40 overflow-hidden">
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

const ProjectCard = ({ project, index, isBookmarked, onBookmarkToggle }) => {
  useReducedMotion();
  const { token, isAuthenticated } = useAuth();
  const [isLoaded, setIsLoaded] = useState(false);
  const [metrics, setMetrics] = useState(null);
  const [metricsLoading, setMetricsLoading] = useState(true);

  // Mouse Tracking state for dynamic light glow bubble
  const cardRef = useRef(null);
  const [coords, setCoords] = useState({ x: 0, y: 0 });


  const handleMouseMove = (e) => {
    if (!cardRef.current) return;
    const rect = cardRef.current.getBoundingClientRect();
    setCoords({
      x: e.clientX - rect.left,
      y: e.clientY - rect.top,
    });
  };

  const handleIncrementStar = async (e) => {
    e.preventDefault();
    e.stopPropagation();

    if (!isAuthenticated()) {
      toast.error("You must be logged in to upvote a project.");
      return;
    }

    try {
      await projectService.upvoteProject(project.id, {
        headers: {
          Authorization: token
        }
      });

      const repoDetails = getGitHubRepoDetails(project.githubUrl);
      const key = repoDetails ? `${repoDetails.owner}/${repoDetails.repo}` : `mock-${project.id}`;

      setMetrics(prev => {
        const updated = { ...prev, stars: (prev?.stars || 0) + 1 };
        try {
          let cache = {};
          const saved = localStorage.getItem(CACHE_KEY);
          cache = saved ? safeJsonParse(saved, {}) : {};
          cache[key] = { data: updated, timestamp: Date.now() };
          localStorage.setItem(CACHE_KEY, JSON.stringify(cache));
        } catch {}
        return updated;
      });
      toast.success("Project upvoted successfully!");
    } catch (err) {
      const message = err?.data?.message || err?.message || "Failed to upvote project.";
      toast.error(message);
    }
  };

  const handleIncrementFork = (e) => {
    e.preventDefault();
    e.stopPropagation();

    const repoDetails = getGitHubRepoDetails(project.githubUrl);
    const key = repoDetails ? `${repoDetails.owner}/${repoDetails.repo}` : `mock-${project.id}`;

    setMetrics(prev => {
      const updated = { ...prev, forks: (prev?.forks || 0) + 1 };
      try {
        let cache = {};
        const saved = localStorage.getItem(CACHE_KEY);
        cache = saved ? safeJsonParse(saved, {}) : {};
        cache[key] = { data: updated, timestamp: Date.now() };
        localStorage.setItem(CACHE_KEY, JSON.stringify(cache));
      } catch {}
      return updated;
    });
  };

  // GitHub metrics loading with LocalStorage caching system
  useEffect(() => {
    const repoDetails = getGitHubRepoDetails(project.githubUrl);

    if (!repoDetails) {
      // Fallback directly to mock data if there is no valid repo
      setMetrics({
        stars: project.stars || project.upvotes || 0,
        forks: project.forks || 0,
        issues: project.openIssues || 0,
        pullRequests: project.pullRequests || 0,
      });
      setMetricsLoading(false);
      return;
    }

    const { owner, repo } = repoDetails;
    const cacheKeyString = `${owner}/${repo}`;

    const loadMetrics = async () => {
      try {
        let cache = {};
        try {
          const saved = localStorage.getItem(CACHE_KEY);
          cache = saved ? safeJsonParse(saved, {}) : {};
        } catch (e) {
          cache = {};
        }

        const cachedEntry = cache[cacheKeyString];
        if (cachedEntry && Date.now() - cachedEntry.timestamp < CACHE_TTL) {
          setMetrics(cachedEntry.data);
          setMetricsLoading(false);
          return;
        }

        const data = await fetchGitHubRepo({ owner, repo });
        const freshMetrics = {
          stars: data.stargazers_count || 0,
          forks: data.forks_count || 0,
          issues: data.open_issues_count || 0,
          pullRequests: project.pullRequests || 0, // Fallback to mock for PRs since it requires separate endpoint
        };

        // Save entry
        cache[cacheKeyString] = {
          data: freshMetrics,
          timestamp: Date.now(),
        };
        localStorage.setItem(CACHE_KEY, JSON.stringify(cache));

        setMetrics(freshMetrics);
        setMetricsLoading(false);
      } catch {
        setMetrics({
          stars: project.stars || project.upvotes || 0,
          forks: project.forks || 0,
          issues: project.openIssues || 0,
          pullRequests: project.pullRequests || 0,
        });
        setMetricsLoading(false);
      }
    };

    loadMetrics();
  }, [project]);

  if (!project) return null;

  const isValidUrl = (string) => {
    try {
      const parsed = new URL(string);
      return parsed.protocol === "http:" || parsed.protocol === "https:";
    } catch {
      return false;
    }
  };

  const hasValidRepo = project.githubUrl && getGitHubRepoDetails(project.githubUrl);
  const hasValidLiveDemo = project.liveDemo && isValidUrl(project.liveDemo);

  // Header decorative random codes
 const csIcons = [Code2, Cpu, GitPullRequest];
