export default function Chatbot() {
  const { t, i18n } = useTranslation();
  const [isOpen, setIsOpen] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [draft, setDraft] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const [messages, setMessages] = useLocalStorage("eventra_chatbot_history", getInitialMessages(t));
  const replyTimerRef = useRef(null);
  const prevLangRef = useRef(i18n.language);
  const quickPrompts = useMemo(() => getQuickPrompts(t), [t, i18n.language]);

  const clearReplyTimer = useCallback(() => {
    if (replyTimerRef.current) {
      clearTimeout(replyTimerRef.current);
      replyTimerRef.current = null;
    }
  }, []);

  useEffect(() => {
    if (prevLangRef.current !== i18n.language) {
      setMessages(getInitialMessages(t));
      prevLangRef.current = i18n.language;
    }
  }, [i18n.language, setMessages, t]);

  // Expiration check on mount (2 hours threshold)
  useEffect(() => {
    try {
      const lastActive = localStorage.getItem("eventra_chatbot_last_active");
      const twoHours = 2 * 60 * 60 * 1000;
      if (lastActive && Date.now() - parseInt(lastActive, 10) > twoHours) {
        setMessages(getInitialMessages(t));
      }
      localStorage.setItem("eventra_chatbot_last_active", Date.now().toString());
    } catch {
      console.warn("localStorage unavailable for Chatbot expiration check");
    }
  }, [setMessages, t]);

  useEffect(() => {
    return () => {
      clearReplyTimer();
    };
  }, [clearReplyTimer]);

  // Sync last active timestamp when messages change
  useEffect(() => {
    try {
      localStorage.setItem("eventra_chatbot_last_active", Date.now().toString());
    } catch {
      console.warn("localStorage unavailable for Chatbot sync");
    }
  }, [messages]);

  const handleClearConversation = () => {
    toast(
      ({ closeToast }) => (
        <div>
          <p className="text-sm font-semibold mb-2">{t("chatbot.clearHistory")}</p>
          <p className="text-xs text-gray-500 mb-3">{t("chatbot.clearWarning")}</p>
          <div className="flex gap-2">
            <button
              onClick={() => {
                setMessages(getInitialMessages(t));
                toast.success(t("chatbot.clearSuccess"));
                closeToast();
              }}
              className="px-3 py-1.5 bg-red-500 hover:bg-red-600 text-white text-xs font-semibold rounded-lg transition-colors"
            >
              {t("chatbot.clearConfirm")}
            </button>
            <button
              onClick={closeToast}
              className="px-3 py-1.5 bg-gray-200 hover:bg-gray-300 text-gray-700 text-xs font-semibold rounded-lg transition-colors"
            >
              {t("common.cancel")}
            </button>
          </div>
        </div>
      ),
      {
        autoClose: false,
        closeOnClick: false,
        draggable: false,
        closeButton: false,
        position: "top-center",
      }
    );
  };
  // Auto-scroll messages to bottom of container when new ones arrive or state changes
  const chatLogsRef = useRef(null);
  // Auto-scroll messages to bottom when new ones arrive
  const messagesEndRef = useRef(null);
  useEffect(() => {
    if (!isMinimized && isOpen) {
      messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }
  }, [messages, isMinimized, isOpen, isTyping]);

  const handleClose = useCallback(() => {
    clearReplyTimer();
    setIsTyping(false);
    setIsOpen(false);
    setIsMinimized(false);
  }, [clearReplyTimer]);

  // Trap keyboard focus inside the chat panel while it's expanded
  const { containerRef: chatTrapRef } = useFocusTrap(
    isOpen && !isMinimized,
    handleClose
  );

  // Listen for Escape key to close the chatbot (accessibility)
  useEffect(() => {
    const handleKeyDown = (event) => {
      if (event.key === "Escape" && isOpen) {
        handleClose();
      }
    };
    window.addEventListener("keydown", handleKeyDown);
    return () => {
      window.removeEventListener("keydown", handleKeyDown);
    };
  }, [handleClose, isOpen]);

  const wasOpenRef = useRef(false);
  const wasMinimizedRef = useRef(false);

  useEffect(() => {
    if (!isOpen || isMinimized) {
      wasOpenRef.current = isOpen;
      wasMinimizedRef.current = isMinimized;
      return;
    }

    const isOpening = !wasOpenRef.current || wasMinimizedRef.current;
    wasOpenRef.current = isOpen;
    wasMinimizedRef.current = isMinimized;

    const timer = setTimeout(() => {
      if (chatLogsRef.current) {
        chatLogsRef.current.scrollTo({
          top: chatLogsRef.current.scrollHeight,
          behavior: isOpening ? "auto" : "smooth",
        });
      }
    }, isOpening ? 250 : 50);

    return () => clearTimeout(timer);
  }, [messages, isTyping, isMinimized, isOpen]);

  const latestActions = useMemo(() => {
    const latestAssistantMessage = [...messages].reverse().find((m) => m.role === "assistant");
    return latestAssistantMessage?.actions || [];
  }, [messages]);

  const sendMessage = (messageText = draft) => {
    // 🔥 FIX: Guard against React Synthetic Events to prevent fatal .trim() crashes
    const safeText = typeof messageText === "string" ? messageText : draft;
    const cleanMessage = safeText.trim();
    if (!cleanMessage || isTyping) return;

    // Append User Message, pruning the oldest entries when the cap is exceeded.
    setMessages((prev) => {
      const next = [...prev, { role: "user", content: cleanMessage }];
      return next.length > MAX_STORED_MESSAGES ? next.slice(next.length - MAX_STORED_MESSAGES) : next;
    });
    setDraft("");
    setIsTyping(true);

    // Simulated network/AI response latency
    clearReplyTimer();
    replyTimerRef.current = setTimeout(() => {
      const reply = getAssistantReply(cleanMessage, t);
      setMessages((prev) => {
        const next = [...prev, { role: "assistant", content: reply.answer, actions: reply.actions }];
        return next.length > MAX_STORED_MESSAGES ? next.slice(next.length - MAX_STORED_MESSAGES) : next;
      });
      setIsTyping(false);
      replyTimerRef.current = null;
    }, 850);
  };

  const handleOpen = () => {
    setIsOpen(true);
    setIsMinimized(false);
  };

  const handleMinimize = () => setIsMinimized((v) => !v);

  // ── Unified single portal rendering ─────────────────────────────────────────
  return createPortal(
    <>
      {/* Minimized strip / Floating launcher — shown when closed OR minimized */}
      {(!isOpen || isMinimized) && (
        <>
          {/* Minimized strip — only on desktop when minimized */}
          {isOpen && isMinimized && (
            <div
              className="
                fixed bottom-6 right-6 z-[100]
                hidden sm:flex              /* hide strip on mobile, show FAB instead */
                items-center justify-between gap-3
                w-72 rounded-2xl
                border border-slate-700
                bg-slate-950 px-4 py-3
                text-white shadow-2xl
                fixed-floating-widget
                transition-opacity duration-300
              "
              aria-label="Eventra assistant minimized"
            >
              <div className="flex items-center gap-2">
                <div className="flex h-7 w-7 items-center justify-center rounded-full bg-indigo-500">
                  <Sparkles className="h-3.5 w-3.5" aria-hidden="true" />
                </div>
                <div className="flex items-center gap-1">
                  <button
                    type="button"
                    onClick={handleMinimize}
                    className="rounded-xl p-1.5 text-slate-400 hover:bg-white/10 hover:text-white transition-colors focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                    aria-label="Expand assistant"
                  >
                    <ChevronUp className="h-4 w-4" />
                  </button>
                  <button
                    type="button"
                    onClick={handleClose}
                    className="rounded-xl p-1.5 text-slate-400 hover:bg-white/10 hover:text-white transition-colors focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                    aria-label={t("chatbot.close")}
                  >
                    <X className="h-4 w-4" />
                  </button>
                </div>
              </div>
            </div>
          )}

          <motion.button
            onClick={handleOpen}
            whileHover={{ scale: 1.1, rotate: 5 }}
            className={`
              fixed bottom-6 right-6 z-[100]
              flex h-14 w-14 items-center justify-center
              rounded-full bg-gradient-to-br from-indigo-600 to-pink-600 text-white
              shadow-[0_8px_30px_rgb(99,102,241,0.4)]
              hover:shadow-[0_8px_30px_rgb(236,72,153,0.5)]
              focus:outline-none focus:ring-2 focus:ring-indigo-600 focus:ring-offset-2
              transition-all duration-200 hover:scale-110
              fixed-floating-widget
              ${isMinimized ? "sm:hidden" : ""}
            `}
            aria-label={t("chatbot.open")}
          >
            <Bot className="h-6 w-6" />
          </motion.button>
        </>
      )}

      {/* Fully expanded chat popup */}
      <AnimatePresence>
        {isOpen && !isMinimized && (
          <motion.section
            ref={chatTrapRef}
            data-chatbot-open
            data-lenis-prevent
            aria-label="Eventra assistant"
            initial={{ opacity: 0, y: 12 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 12 }}
            transition={{ duration: 0.2 }}
            className="
              fixed bottom-6 right-6 z-[100]
              flex flex-col                        /* KEY FIX: flex column layout */
              w-[calc(100vw-2rem)] max-w-sm sm:max-w-sm
              rounded-2xl
              border border-slate-200 dark:border-slate-700
              bg-white dark:bg-slate-900
              shadow-2xl
              fixed-floating-widget
              transition-opacity duration-300

              /* KEY FIX: constrain total height to viewport so it never overflows.
                 bottom-6 = 1.5rem offset from bottom, so we subtract that + a little breathing room. */
              max-h-[calc(100dvh-2rem)] sm:max-h-[calc(100vh-5rem)]
            "
          >
            {/* ── Header — always visible, never scrolls away ── */}
            <header
              className="
              flex flex-shrink-0 items-center justify-between gap-3
              border-b border-slate-200 dark:border-slate-700
              bg-slate-950 px-4 py-3 text-white
              rounded-t-2xl
            "
            >
              <div className="flex items-center gap-3">
                <div className="flex h-9 w-9 items-center justify-center rounded-full bg-indigo-500">
                  <Sparkles className="h-4 w-4" />
                </div>
                <div>
                  <h2 className="text-sm font-bold">{t("chatbot.title")}</h2>
                  <p className="text-xs text-slate-300">{t("chatbot.subtitle")}</p>
                </div>
              </div>
              <div className="flex items-center gap-1">
                <button
                  type="button"
                  onClick={handleClearConversation}
                  disabled={messages.length <= 1}
                  className="rounded-lg p-2 text-slate-300 hover:bg-white/10 hover:text-red-400 transition-colors focus:ring-2 focus:ring-indigo-500 focus:outline-none disabled:opacity-50 disabled:cursor-not-allowed"
                  title="Clear conversation"
                  aria-label="Clear conversation"
                >
                  <Trash2 className="h-4 w-4" />
                </button>
                <button
                  type="button"
                  onClick={handleMinimize}
                  className="rounded-lg p-2 text-slate-300 hover:bg-white/10 hover:text-white focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                  aria-label={t("chatbot.minimize")}
                >
                  <Minus className="h-4 w-4" />
                </button>
                <button
                  type="button"
                  onClick={handleClose}
                  className="rounded-lg p-2 text-slate-300 hover:bg-white/10 hover:text-white focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                  aria-label={t("chatbot.close")}
                >
                  <X className="h-4 w-4" />
                </button>
              </div>
            </header>

            {/* Messages list */}
            <div
              ref={chatLogsRef}
              className="flex-1 overflow-y-auto px-4 py-4 space-y-4"
              role="log"
              aria-live="polite"
              aria-label="Chat messages"
              data-lenis-prevent
            >
              {messages.map((message, index) => (
                <div
                  key={`${message.role}-${index}`}
                  className={`flex ${message.role === "user" ? "justify-end" : "justify-start"}`}
                >
                  <motion.div
                    initial={{ opacity: 0, scale: 0.9, y: 15 }}
                    animate={{ opacity: 1, scale: 1, y: 0 }}
                    transition={{ type: "spring", stiffness: 300, damping: 20 }}
                    className={`max-w-[85%] rounded-[1.25rem] px-4 py-3 text-sm leading-relaxed shadow-sm ${
                      message.role === "user"
                        ? "bg-gradient-to-r from-indigo-600 to-pink-600 text-white rounded-br-sm"
                        : "bg-slate-100 dark:bg-slate-800/80 backdrop-blur-sm text-slate-800 dark:text-slate-100 rounded-bl-sm border border-slate-200/30 dark:border-slate-700/20"
                    }`}
                  >
                    {message.role === "user" ? (
                      message.content
                    ) : (
                      <div className="chatbot-markdown">
                        {renderMarkdownToReact(message.content)}
                      </div>
                    )}
                  </motion.div>
                </div>
              ))}

              {isTyping && (
                <div className="flex justify-start">
                  <motion.div
                    initial={{ opacity: 0, scale: 0.9, y: 10 }}
                    animate={{ opacity: 1, scale: 1, y: 0 }}
                    className="bg-slate-100 dark:bg-slate-800/80 backdrop-blur-sm rounded-[1.25rem] rounded-bl-sm px-4 py-3.5 flex items-center gap-1.5 border border-slate-200/30 dark:border-slate-700/20 shadow-sm"
                  >
                    <motion.span
                      animate={{ y: [0, -5, 0] }}
                      transition={{ repeat: Infinity, duration: 0.6, delay: 0 }}
                      className="w-2 h-2 rounded-full bg-indigo-500"
                    />
                    <motion.span
                      animate={{ y: [0, -5, 0] }}
                      transition={{ repeat: Infinity, duration: 0.6, delay: 0.15 }}
                      className="w-2 h-2 rounded-full bg-pink-500"
                    />
                    <motion.span
                      animate={{ y: [0, -5, 0] }}
                      transition={{ repeat: Infinity, duration: 0.6, delay: 0.3 }}
                      className="w-2 h-2 rounded-full bg-emerald-500"
                    />
                  </motion.div>
                </div>
              )}

              {/* 🔥 FIX: Added the missing dummy div to act as the scroll target for messagesEndRef */}
              <div ref={messagesEndRef} />
            </div>

            {/* Footer controls */}
            <div
              className="
              flex-shrink-0
              px-4 py-4
              bg-white/90 dark:bg-slate-900/90
              border-t border-slate-200/50 dark:border-slate-800/40
            "
            >
              {/* Quick prompts */}
              <div className="mb-3.5 flex flex-wrap gap-1.5">
                {quickPrompts.map((prompt) => (
                  <button
                    key={prompt}
                    type="button"
                    onClick={() => sendMessage(prompt)}
                    className="rounded-full border border-slate-200/60 dark:border-slate-800/50 bg-slate-50/50 dark:bg-slate-950/40 px-3 py-1.5 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-gradient-to-r hover:from-indigo-600 hover:to-pink-600 hover:text-white hover:border-transparent transition-all duration-300 transform hover:scale-[1.03] focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                  >
                    {prompt}
                  </button>
                ))}
              </div>

              {/* Contextual action links */}
              {latestActions.length > 0 && (
                <div className="mb-3.5 flex flex-wrap gap-2">
                  {latestActions.map(({ label, to, icon: iconName }) => {
                    const Icon = ICON_MAP[iconName];
                    return (
                      <Link
                        key={`${label}-${to}`}
                        to={to}
                        className="inline-flex items-center gap-1.5 rounded-xl bg-slate-900 hover:bg-slate-950 dark:bg-slate-950 dark:hover:bg-black border border-white/10 px-3 py-2 text-xs font-bold text-white hover:scale-[1.03] transition-all duration-300 shadow focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                      >
                        {Icon && <Icon className="h-3.5 w-3.5" />}
                        {label}
                      </Link>
                    );
                  })}
                </div>
              )}

              {/* Input form */}
              <form
                className="flex items-center gap-2"
                onSubmit={(e) => {
                  e.preventDefault();
                  sendMessage();
                }}
              >
                <input
                  value={draft}
                  onChange={(e) => setDraft(e.target.value)}
                  placeholder={t("chatbot.placeholder")}
                  aria-label={t("chatbot.placeholder")}
                  className="min-w-0 flex-1 rounded-xl border border-slate-200/60 dark:border-slate-800/50 bg-slate-50/50 dark:bg-slate-950/30 px-3 py-2.5 text-sm text-slate-900 dark:text-white outline-none focus:border-indigo-500 dark:focus:border-indigo-400 focus:ring-2 focus:ring-indigo-500 focus:outline-none transition-colors"
                />
                <button
                  type="submit"
                  disabled={!draft.trim() || isTyping}
                  aria-label={t("chatbot.send")}
                  title={t("chatbot.send")}
                  className="rounded-xl bg-slate-900 dark:bg-white p-2.5 text-white dark:text-slate-900 hover:bg-slate-800 dark:hover:bg-slate-100 disabled:cursor-not-allowed disabled:opacity-40 transition-all shadow hover:scale-105 active:scale-95 focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                >
                  <Send className="h-4 w-4" />
                </button>
              </form>
            </div>
          </motion.section>
        )}
      </AnimatePresence>
    </>,
    document.body
  );
}

// SECURITY PROTECTION: Escaped dynamic message history to block stored Cross-Site Scripting (XSS) script injections.

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import EventConflictModal from './EventConflictModal';

/**
 * EventConflictModal Test Suite
 *
 * Tests the conflict modal component that displays scheduling conflicts
 * and alternative event suggestions during registration.
 *
 * Test Categories:
 * - Modal Visibility & Rendering
 * - Conflict Display
 * - Alternative Suggestions Display
 * - User Interactions
 * - Accessibility Features
 * - Edge Cases
 * - Dark Mode Support
 */

describe('EventConflictModal', () => {
  // Mock timezone utility
  vi.mock('../utils/timezoneUtils', () => ({
    getUserTimezone: () => 'America/New_York',
    parseEventToUTC: vi.fn((date, time, tz) => {
      const d = new Date(`${date}T${time}`);
      return d.getTime();
    }),
  }));

  // Mock conflict detection utilities
  vi.mock('../utils/conflictDetection', () => ({
    formatTimeRange: (time, duration, date, tz) => `${time} - ${new Date(Date.parse(date) + duration * 60000).toLocaleTimeString()}`,
  }));

  const mockNewEvent = {
    id: '1',
    title: 'React Workshop',
    date: '2025-06-15',
    time: '10:00 AM',
    durationMinutes: 60,
    timezone: 'America/New_York',
  };

  const mockConflictingEvent = {
    id: '2',
    title: 'JavaScript Basics',
    date: '2025-06-15',
    time: '10:30 AM',
    durationMinutes: 90,
    timezone: 'America/New_York',
  };

  const mockAlternativeEvent1 = {
    id: '3',
    title: 'Advanced React',
    date: '2025-06-16',
    time: '2:00 PM',
    durationMinutes: 120,
    timezone: 'America/New_York',
  };

  const mockAlternativeEvent2 = {
    id: '4',
    title: 'Vue Fundamentals',
    date: '2025-06-17',
    time: '10:00 AM',
    durationMinutes: 60,
    timezone: 'America/New_York',
  };

  const defaultProps = {
    isOpen: true,
    newEvent: mockNewEvent,
    conflictingEvents: [mockConflictingEvent],
    suggestedEvents: [mockAlternativeEvent1, mockAlternativeEvent2],
    onCancel: vi.fn(),
    onProceed: vi.fn(),
    onSelectAlternative: vi.fn(),
    strictMode: false,
  };

  beforeEach(() => {
    vi.clearAllMocks();
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  describe('Modal Visibility & Rendering', () => {
    it('should render modal when isOpen is true', () => {
      render(<EventConflictModal {...defaultProps} />);
      expect(screen.getByRole('dialog')).toBeInTheDocument();
      expect(screen.getByText('Scheduling Conflict Detected')).toBeInTheDocument();
    });

    it('should not render modal when isOpen is false', () => {
      render(<EventConflictModal {...defaultProps} isOpen={false} />);
      expect(screen.queryByRole('dialog')).not.toBeInTheDocument();
    });

    it('should display modal with correct ARIA attributes', () => {
      render(<EventConflictModal {...defaultProps} />);
      const dialog = screen.getByRole('dialog');
      expect(dialog).toHaveAttribute('aria-modal', 'true');
      expect(dialog).toHaveAttribute('aria-labelledby', 'modal-title');
    });

    it('should prevent body scroll when modal is open', () => {
      const { rerender } = render(<EventConflictModal {...defaultProps} isOpen={false} />);
      expect(document.body.style.overflow).not.toBe('hidden');

      rerender(<EventConflictModal {...defaultProps} isOpen={true} />);
      expect(document.body.style.overflow).toBe('hidden');

      rerender(<EventConflictModal {...defaultProps} isOpen={false} />);
      expect(document.body.style.overflow).not.toBe('hidden');
    });
  });

  describe('Conflict Display', () => {
    it('should display the new event being registered for', () => {
      render(<EventConflictModal {...defaultProps} />);
      expect(screen.getByText('React Workshop')).toBeInTheDocument();
    });

    it('should display conflicting event information', () => {
      render(<EventConflictModal {...defaultProps} />);
      expect(screen.getByText('JavaScript Basics')).toBeInTheDocument();
    });

    it('should display correct date for conflicting event', () => {
      render(<EventConflictModal {...defaultProps} />);
      const dateElements = screen.getAllByText(/Jun/);
      expect(dateElements.length).toBeGreaterThan(0);
    });

    it('should show correct conflict section header', () => {
      render(<EventConflictModal {...defaultProps} />);
      expect(screen.getByText('Conflicting Event')).toBeInTheDocument();
    });

    it('should show plural "Conflicting Events" for multiple conflicts', () => {
      const multipleConflicts = {
        ...defaultProps,
        conflictingEvents: [mockConflictingEvent, { ...mockConflictingEvent, id: '5', title: 'Another Event' }],
      };
      render(<EventConflictModal {...multipleConflicts} />);
      expect(screen.getByText('Conflicting Events')).toBeInTheDocument();
    });

    it('should display all conflicting events', () => {
      const conflicts = [
        mockConflictingEvent,
        { ...mockConflictingEvent, id: '5', title: 'Meeting', date: '2025-06-15' },
      ];
      render(<EventConflictModal {...defaultProps} conflictingEvents={conflicts} />);
      expect(screen.getByText('JavaScript Basics')).toBeInTheDocument();
      expect(screen.getByText('Meeting')).toBeInTheDocument();
    });

    it('should handle missing event data gracefully', () => {
      const incompleteEvent = { id: '6', title: 'Incomplete Event' };
      render(<EventConflictModal {...defaultProps} conflictingEvents={[incompleteEvent]} />);
      expect(screen.getByText('Incomplete Event')).toBeInTheDocument();
      expect(screen.getByText('TBD')).toBeInTheDocument();
    });

    it('should display timezone information', () => {
      render(<EventConflictModal {...defaultProps} />);
      expect(screen.getByText(/America\/New_York/)).toBeInTheDocument();
    });
  });

  describe('Alternative Suggestions Display', () => {
    it('should display alternative suggestions section when suggestions exist', () => {
      render(<EventConflictModal {...defaultProps} />);
      expect(screen.getByText('Suggested Alternatives')).toBeInTheDocument();
    });

    it('should not display alternative suggestions section when empty', () => {
      render(<EventConflictModal {...defaultProps} suggestedEvents={[]} />);
      expect(screen.queryByText('Suggested Alternatives')).not.toBeInTheDocument();
    });

    it('should display all alternative events', () => {
      render(<EventConflictModal {...defaultProps} />);
      expect(screen.getByText('Advanced React')).toBeInTheDocument();
      expect(screen.getByText('Vue Fundamentals')).toBeInTheDocument();
    });

    it('should display each suggestion as a clickable button', () => {
      render(<EventConflictModal {...defaultProps} />);
      const buttons = screen.getAllByRole('button');
      const alternativeButtons = buttons.filter(btn => 
        btn.textContent.includes('Advanced React') || btn.textContent.includes('Vue Fundamentals')
      );
      expect(alternativeButtons.length).toBe(2);
    });

    it('should display arrow icon for alternative suggestions', () => {
      const { container } = render(<EventConflictModal {...defaultProps} />);
      const arrowIcons = container.querySelectorAll('svg[class*="group-hover"]');
      expect(arrowIcons.length).toBeGreaterThan(0);
    });
  });

  describe('User Interactions', () => {
    it('should call onCancel when cancel button is clicked', async () => {
      const onCancel = vi.fn();
      render(<EventConflictModal {...defaultProps} onCancel={onCancel} />);
      const cancelButton = screen.getByText('Cancel Registration');
      fireEvent.click(cancelButton);
      expect(onCancel).toHaveBeenCalledTimes(1);
    });

    it('should call onProceed when proceed button is clicked', async () => {
      const onProceed = vi.fn();
      render(<EventConflictModal {...defaultProps} onProceed={onProceed} />);
      const proceedButton = screen.getByText('Proceed Anyway');
      fireEvent.click(proceedButton);
      expect(onProceed).toHaveBeenCalledTimes(1);
    });

    it('should call onSelectAlternative when alternative event is clicked', async () => {
      const onSelectAlternative = vi.fn();
      render(<EventConflictModal {...defaultProps} onSelectAlternative={onSelectAlternative} />);
      const advancedReactButton = screen.getByText('Advanced React').closest('button');
      fireEvent.click(advancedReactButton);
      expect(onSelectAlternative).toHaveBeenCalledWith(mockAlternativeEvent1);
    });

    it('should call onCancel when backdrop is clicked', () => {
      const onCancel = vi.fn();
      const { container } = render(<EventConflictModal {...defaultProps} onCancel={onCancel} />);
      const backdrop = container.querySelector('.absolute.inset-0');
      fireEvent.click(backdrop);
      expect(onCancel).toHaveBeenCalledTimes(1);
    });

    it('should call onCancel when close button is clicked', () => {
      const onCancel = vi.fn();
      render(<EventConflictModal {...defaultProps} onCancel={onCancel} />);
      const closeButton = screen.getByLabelText('Close conflict dialog');
      fireEvent.click(closeButton);
      expect(onCancel).toHaveBeenCalledTimes(1);
    });

    it('should call onCancel when Escape key is pressed', async () => {
      const onCancel = vi.fn();
      render(<EventConflictModal {...defaultProps} onCancel={onCancel} />);
      fireEvent.keyDown(window, { key: 'Escape' });
      await waitFor(() => {
        expect(onCancel).toHaveBeenCalled();
      });
    });
  });

  describe('Strict Mode', () => {
    it('should hide proceed button when strictMode is true', () => {
