const DesktopNavLinks = ({ openDropdown, setOpenDropdown }) => {
  const location = useLocation();
  return (
    <div className="hidden lg:flex items-center justify-center flex-1 min-w-0 pl-6">
      {NAV_ITEMS.map((item) => {
        const isActive = item.href
          ? (item.href === "/" ? location.pathname === "/" : location.pathname.startsWith(item.href))
          : item.subItems?.some(s => location.pathname.startsWith(s.href));

        if (item.subItems) {
          return (
            <DesktopNavGroup key={item.name} item={item} isActive={isActive} isOpen={openDropdown === item.name} onToggle={(e) => { e.stopPropagation(); setOpenDropdown(openDropdown === item.name ? null : item.name); }} setOpenDropdown={setOpenDropdown} />
          );
        }
        return <DesktopNavLink key={item.name} item={item} isActive={isActive} />;
      })}
    </div>
  );
};

const Navbar = ({ cursorEnabled, toggleCursor }) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [showProfileDropdown, setShowProfileDropdown] = useState(false);
  const [openDropdown, setOpenDropdown] = useState(null);
  const [showLogoutModal, setShowLogoutModal] = useState(false);
  const [navHeight, setNavHeight] = useState(0);
  const [showCommandPalette, setShowCommandPalette] = useState(false);

  useEffect(() => {
    const handleToggle = () => setShowCommandPalette((prev) => !prev);
    const handleClose = () => setShowCommandPalette(false);

    window.addEventListener("toggleCommandPalette", handleToggle);
    window.addEventListener("closeCommandPalette", handleClose);

    return () => {
      window.removeEventListener("toggleCommandPalette", handleToggle);
      window.removeEventListener("closeCommandPalette", handleClose);
    };
  }, []);

  const drawerRef = useRef(null);
  const closeBtnRef = useRef(null);
  const toggleBtnRef = useRef(null);
  const touchStartXRef = useRef(null);
  const touchCurrentXRef = useRef(null);
  const navRef = useRef(null);

  // 🔥 FIX: Track mounted state for async logout safety
  const isMounted = useRef(true);

  const { user, isAuthenticated, logout } = useAuth();
  const { isDarkMode, toggleTheme, setIsCustomizerOpen } = useTheme();
  const navigate = useNavigate();
  const location = useLocation();

  const { primary: primaryLine, secondary: secondaryLine } = getUserDisplayNames(user);

  useEffect(() => {
    return () => {
      isMounted.current = false;
    };
  }, []);

  const closeAllMenus = () => {
    setShowProfileDropdown(false);
    setIsMobileMenuOpen(false);
    setOpenDropdown(null);
    clearBodyScrollStyles();
    try {
      toggleBtnRef.current?.focus();
    } catch {
      /* ignore */
    }
  };

  useEffect(() => {
    window.dispatchEvent(new CustomEvent("mobileMenuToggle", { detail: isMobileMenuOpen }));
  }, [isMobileMenuOpen]);

  useEffect(() => {
    if (isMobileMenuOpen) {
      setBodyScrollStyles(window.scrollY || 0);
      setTimeout(() => closeBtnRef.current?.focus(), 50);
    } else {
      clearBodyScrollStyles();
    }
    return clearBodyScrollStyles;
  }, [isMobileMenuOpen]);

  useEffect(() => {
    closeAllMenus();
  }, [location.pathname]);

  useEffect(() => {
    if (!isMobileMenuOpen || !drawerRef.current) return;
    const drawer = drawerRef.current;
    const handleKeyDown = (e) => {
      if (e.key === "Escape") {
        e.preventDefault();
        closeAllMenus();
        return;
      }
      if (e.key === "Tab") {
        const focusable = drawer.querySelectorAll(
          'a, button, input, select, textarea, [tabindex]:not([tabindex="-1"])'
        );
        if (!focusable.length) return;
        const first = focusable[0];
        const last = focusable[focusable.length - 1];
        if (e.shiftKey && document.activeElement === first) {
          e.preventDefault();
          last.focus();
        } else if (!e.shiftKey && document.activeElement === last) {
          e.preventDefault();
          first.focus();
        }
      }
    };
    document.addEventListener("keydown", handleKeyDown);
    return () => document.removeEventListener("keydown", handleKeyDown);
  }, [isMobileMenuOpen]);

  useEffect(() => {
    if (navRef.current) setNavHeight(navRef.current.offsetHeight);
    const handleResize = () => {
      if (navRef.current) setNavHeight(navRef.current.offsetHeight);
    };
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const handleTouchStart = (e) => {
    touchStartXRef.current = e.touches[0].clientX;
    touchCurrentXRef.current = e.touches[0].clientX;
  };
  const handleTouchMove = (e) => {
    touchCurrentXRef.current = e.touches[0].clientX;
  };
  const handleTouchEnd = () => {
    const delta = (touchCurrentXRef.current ?? 0) - (touchStartXRef.current ?? 0);
    if (delta > 50) closeAllMenus();
    touchStartXRef.current = null;
    touchCurrentXRef.current = null;
  };

  const handleLogoutClick = () => {
    setShowLogoutModal(true);
    setShowProfileDropdown(false);
  };

  // 🔥 FIX: Made handler async and added unmount safety guards
  const handleConfirmLogout = async () => {
    if (isMounted.current) {
      setShowLogoutModal(false);
    }

    // Await logout to ensure backend token/context clears before navigation
    await logout();

    if (isMounted.current) {
      toast.success("You have been logged out successfully.", {
        className: "custom-toast",
        autoClose: 3000,
      });
      navigate("/");
    }
  };

  const handleCancelLogout = () => setShowLogoutModal(false);

  return (
    <>
      {/* Skip navigation — visible only on keyboard focus, WCAG 2.4.1 */}
      <a
        href="#main-content"
        className="sr-only focus:not-sr-only focus:fixed focus:top-4 focus:left-4 focus:z-50 focus:bg-indigo-600 focus:text-white focus:px-4 focus:py-2 focus:rounded focus:outline-none"
      >
        Skip to main content
      </a>
      <div
        className={`fixed inset-0 z-[100] transition-opacity duration-300 ${
          isMobileMenuOpen || showLogoutModal
            ? "bg-black/60 opacity-100"
            : showProfileDropdown || openDropdown
              ? "bg-transparent opacity-100"
              : "opacity-0 pointer-events-none"
        }`}
        onClick={closeAllMenus}
        aria-hidden="true"
      />
      <nav
        ref={navRef}
        aria-label="Main navigation"
        data-aos="fade-down"
        data-aos-once="true"
        data-aos-duration="1000"
        className="fixed top-2 sm:top-4 left-2 sm:left-4 right-2 sm:right-4 max-w-7xl mx-auto z-[90] shadow-lg shadow-indigo-500/5 bg-white/80 dark:bg-slate-950/80 backdrop-blur-xl border border-gray-200/50 dark:border-slate-800/80 transition-all duration-300 overflow-visible rounded-2xl"
      >
        <div className="neon-navbar-border"></div>

        <div className="max-w-screen-2xl mx-auto flex items-center justify-between min-h-[68px] px-4 md:px-6 xl:px-10 gap-4 w-full overflow-visible">

          {/* Logo */}
          <Link
            to="/"
            className="flex items-center shrink-0 z-20 mr-2 min-w-0"
          >
            <BrandMark />
          </Link>

          {/* Centered Desktop Nav Links */}
          <DesktopNavLinks openDropdown={openDropdown} setOpenDropdown={setOpenDropdown} />

          {/* Right Controls */}
          <div className="hidden lg:flex items-center gap-2 shrink-0 pl-2">
            <motion.button
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
              onClick={() => setShowCommandPalette(true)}
              title="Open Command Palette (⌘K)"
              className="flex items-center gap-2 px-3 py-1.5 rounded-full transition-all duration-300 focus:outline-none bg-zinc-100 dark:bg-zinc-800/80 hover:bg-indigo-50 dark:hover:bg-indigo-900/40 border border-zinc-200/60 dark:border-zinc-700/50 hover:shadow-[0_0_12px_rgba(99,102,241,0.4)] group mr-1"
            >
              <Search className="w-4 h-4 text-zinc-500 dark:text-zinc-400 group-hover:text-indigo-500 dark:group-hover:text-indigo-400" />
              <div className="flex items-center gap-0.5 text-[9px] font-black tracking-widest text-zinc-400 group-hover:text-indigo-500 dark:group-hover:text-indigo-400 uppercase">
                <span>⌘</span>
                <span>K</span>
              </div>
            </motion.button>

            <ThemeToggleButton
              isDarkMode={isDarkMode}
              toggleTheme={toggleTheme}
              isMobile={false}
              setIsCustomizerOpen={setIsCustomizerOpen}
            />

            <CursorToggleButton
              cursorEnabled={cursorEnabled}
              toggleCursor={toggleCursor}
              isMobile={false}
            />

            <div className="w-px h-5 bg-zinc-200 dark:bg-zinc-700"></div>

            {isAuthenticated() ? (
              <UserProfileDropdown
                user={user}
                primaryLine={primaryLine}
                secondaryLine={secondaryLine}
                showProfileDropdown={showProfileDropdown}
                setShowProfileDropdown={setShowProfileDropdown}
                location={location}
                handleLogoutClick={handleLogoutClick}
              />
            ) : (
              <AuthButtons isMobile={false} />
            )}
          </div>

          {/* Mobile Menu Button */}
          <div className="lg:hidden ml-auto">
            <button
              ref={toggleBtnRef}
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              aria-expanded={isMobileMenuOpen}
              aria-controls="mobile-drawer"
              aria-label={isMobileMenuOpen ? "Close navigation" : "Open navigation"}
              className="p-2 rounded-md text-gray-700 dark:text-gray-300 hover:text-black dark:hover:text-white hover:bg-gray-100 dark:hover:bg-white/10"
            >
              <svg
                className="h-5 w-5 sm:h-6 sm:w-6"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M4 6h16M4 12h16M4 18h16"
                />
              </svg>
            </button>
          </div>
        </div>
      </nav>

      <MobileDrawer
        isOpen={isMobileMenuOpen}
        drawerRef={drawerRef}
        openDropdown={openDropdown}
        setOpenDropdown={setOpenDropdown}
        closeAllMenus={closeAllMenus}
        handleTouchStart={handleTouchStart}
        handleTouchMove={handleTouchMove}
        handleTouchEnd={handleTouchEnd}
        closeBtnRef={closeBtnRef}
        handleLogoutClick={handleLogoutClick}
        primaryLine={primaryLine}
        secondaryLine={secondaryLine}
        cursorEnabled={cursorEnabled}
        toggleCursor={toggleCursor}
        navItems={NAV_ITEMS}
      />

      {/* Confirmation Modal */}
      <ConfirmationModal
        isOpen={showLogoutModal}
        onClose={handleCancelLogout}
        onConfirm={handleConfirmLogout}
        title="Logout Confirmation"
        message="Are you sure you want to log out?"
      />

      {/* Global Command Palette */}
      <CommandPalette
        isOpen={showCommandPalette}
        onClose={() => setShowCommandPalette(false)}
        isDarkMode={isDarkMode}
        toggleTheme={toggleTheme}
        cursorEnabled={cursorEnabled}
        toggleCursor={toggleCursor}
        isAuthenticated={isAuthenticated}
        handleLogoutClick={handleLogoutClick}
      />

      <ThemeCustomizer />

      <div style={{ height: navHeight }} />
    </>
  );
};

export default Navbar;

import React, { useState, useEffect } from 'react';

const ScrollToTop = () => {
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    const toggleVisibility = () => {
      // Show button when page is scrolled down past 400px
      if (window.scrollY > 400) {
        setIsVisible(true);
      } else {
        setIsVisible(false);
      }
    };

    window.addEventListener('scroll', toggleVisibility);
    return () => window.removeEventListener('scroll', toggleVisibility);
  }, []);

  const scrollToTop = () => {
    window.scrollTo({
      top: 0,
      behavior: 'smooth',
    });
  };

  if (!isVisible) return null;

  return (
    <button
      onClick={scrollToTop}
      style={{
        position: 'fixed',
        bottom: '30px',
        right: '30px',
        zIndex: 1000,
        width: '45px',
        height: '45px',
        borderRadius: '50%',
        backgroundColor: '#6366f1', // Classic sleek modern theme color (Indigo)
        color: '#ffffff',
        border: 'none',
        cursor: 'pointer',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        boxShadow: '0 4px 12px rgba(0, 0, 0, 0.15)',
        fontSize: '20px',
        transition: 'all 0.3s ease',
      }}
      aria-label="Scroll to top"
      onMouseEnter={(e) => (e.currentTarget.style.transform = 'scale(1.1)')}
      onMouseLeave={(e) => (e.currentTarget.style.transform = 'scale(1)')}
    >
      ▲
    </button>
  );
};

export default ScrollToTop;

import React, { useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { X, Check, Monitor, Sun, Moon } from "lucide-react";
import { useTheme } from "../../context/ThemeContext";

const ThemeCustomizer = () => {
  const {
    isCustomizerOpen,
    setIsCustomizerOpen,
    theme,
    setTheme,
    activeThemeId,
    setActiveThemeId,
    THEMES,
  } = useTheme();

  useEffect(() => {
    if (isCustomizerOpen) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "auto";
    }
    return () => {
      document.body.style.overflow = "auto";
    };
  }, [isCustomizerOpen]);

  if (!isCustomizerOpen) return null;

  const baseThemeOptions = [
    { id: "light", label: "Light", icon: <Sun className="w-5 h-5" /> },
    { id: "dark", label: "Dark", icon: <Moon className="w-5 h-5" /> },
    { id: "system", label: "System", icon: <Monitor className="w-5 h-5" /> },
  ];

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-[200] flex items-center justify-center p-4">
        {/* Backdrop */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={() => setIsCustomizerOpen(false)}
          className="absolute inset-0 bg-black/50 backdrop-blur-sm"
        />

        {/* Modal */}
        <motion.div
          initial={{ opacity: 0, scale: 0.95, y: 20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.95, y: 20 }}
          className="relative w-full max-w-lg bg-white dark:bg-slate-900 rounded-2xl shadow-2xl border border-gray-200 dark:border-slate-800 overflow-hidden flex flex-col max-h-[90vh]"
        >
          {/* Header */}
          <div className="flex items-center justify-between p-6 border-b border-gray-100 dark:border-slate-800">
            <h2 className="text-xl font-bold text-gray-900 dark:text-white">Theme Customizer</h2>
            <button
              onClick={() => setIsCustomizerOpen(false)}
              className="p-2 rounded-full text-gray-500 hover:bg-gray-100 dark:hover:bg-slate-800 dark:text-gray-400 transition-colors"
              aria-label="Close customizer"
            >
              <X className="w-5 h-5" />
            </button>
          </div>

          <div className="p-6 overflow-y-auto space-y-8">
            {/* Base Theme Section */}
            <div className="space-y-4">
              <h3 className="text-sm font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400">
                Base Mode
              </h3>
              <div className="grid grid-cols-3 gap-3">
                {baseThemeOptions.map((option) => {
                  const isActive = theme === option.id;
                  return (
                    <button
                      key={option.id}
                      onClick={() => setTheme(option.id)}
                      className={`flex flex-col items-center justify-center gap-2 p-4 rounded-xl border-2 transition-all ${
                        isActive
                          ? "border-indigo-500 bg-indigo-50 dark:bg-indigo-500/10 text-indigo-600 dark:text-indigo-400"
                          : "border-gray-200 dark:border-slate-700 bg-transparent text-gray-600 dark:text-gray-300 hover:border-indigo-300 dark:hover:border-indigo-700 hover:bg-gray-50 dark:hover:bg-slate-800"
                      }`}
                    >
                      {option.icon}
                      <span className="text-sm font-medium">{option.label}</span>
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Skins / Color Themes Section */}
            <div className="space-y-4">
              <h3 className="text-sm font-semibold uppercase tracking-wider text-gray-500 dark:text-gray-400">
                Color Themes
              </h3>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                {Object.values(THEMES).map((themeOption) => {
                  const isActive = activeThemeId === themeOption.id;
                  return (
                    <button
                      key={themeOption.id}
                      onClick={() => setActiveThemeId(themeOption.id)}
                      className={`flex items-center gap-3 p-4 rounded-xl border-2 transition-all text-left ${
                        isActive
                          ? "border-indigo-500 bg-indigo-50 dark:bg-indigo-500/10"
                          : "border-gray-200 dark:border-slate-700 bg-transparent hover:border-indigo-300 dark:hover:border-indigo-700 hover:bg-gray-50 dark:hover:bg-slate-800"
                      }`}
                    >
                      <div
                        className={`w-8 h-8 rounded-full bg-gradient-to-br ${themeOption.accent} flex items-center justify-center shadow-sm shrink-0`}
                      >
                        {isActive && <Check className="w-4 h-4 text-white" />}
                      </div>
                      <span
                        className={`text-sm font-medium flex-1 truncate ${
                          isActive
                            ? "text-indigo-700 dark:text-indigo-300"
                            : "text-gray-700 dark:text-gray-200"
                        }`}
                      >
                        {themeOption.name}
                      </span>
                    </button>
                  );
                })}
              </div>
            </div>
          </div>
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

export default ThemeCustomizer;

