import React from 'react';
import { useFocusTrap } from '../../hooks/useFocusTrap';

/**
 * FocusTrap
 *
 * A zero-dependency wrapper component that constrains keyboard focus to its
 * children while `isActive` is true, and closes on Escape.
 *
 * Usage:
 *
 *   <FocusTrap isActive={isOpen} onEscape={handleClose}>
 *     <div role="dialog" aria-modal="true" aria-labelledby="dialog-title">
 *       …dialog content…
 *     </div>
 *   </FocusTrap>
 *
 * @param {object}   props
 * @param {boolean}  props.isActive   - Activates the trap when true.
 * @param {Function} props.onEscape   - Called when the Escape key is pressed.
 * @param {React.ReactNode} props.children
 * @param {string}  [props.className] - Optional class forwarded to the wrapper div.
 */
const FocusTrap = ({ isActive, onEscape, children, className = '' }) => {
  const { containerRef } = useFocusTrap(isActive, onEscape);

  return (
    <div ref={containerRef} className={className}>
      {children}
    </div>
  );
};

export default FocusTrap;

import { useState, useRef, useEffect } from 'react';
import { ImageIcon } from 'lucide-react';
import '../../styles/lazy-image.css';

/**
 * LazyImage — Drop-in replacement for <img> with:
 *   - native lazy loading (loading="lazy")
 *   - blur-up placeholder and skeleton shimmer
 *   - low opacity preview fallback
 *   - fade-in transition on load
 *   - layout shift prevention via width, height, and aspectRatio support
 *   - accessibility (a11y) compliance
 *   - broken image fallback error handling
 */
const LazyImage = ({
  src,
  alt = '',
  className = '',
  imgClassName = '',
  width,
  height,
  aspectRatio,
  loading = 'lazy',
  decoding = 'async',
  style,
  imgStyle,
  useWebP = false,
  onError,
  previewSrc,
  ...props
}) => {
  const [loaded, setLoaded] = useState(false);
  const [error, setError] = useState(false);
  const imgRef = useRef(null);

  useEffect(() => {
    // Reset states if src changes
    setLoaded(false);
    setError(false);
  }, [src]);

  // Handle cached images already complete before initial mount
  useEffect(() => {
    if (imgRef.current?.complete && imgRef.current.naturalWidth > 0) {
      setLoaded(true);
    }
  }, [src]);

  const handleLoad = () => {
    setLoaded(true);
  };

  const handleError = (e) => {
    setError(true);
    if (onError) onError(e);
  };

const webpSrc =
  useWebP && src && src.match(/\.(jpe?g|png)$/i)
    ? src.replace(/\.(jpe?g|png)$/i, ".webp")
    : null;

// Resolve container styles to prevent Cumulative Layout Shift (CLS)
const containerStyle = {
  position: "relative",
  overflow: "hidden",
  ...style,
};

if (width !== undefined) {
  containerStyle.width =
    typeof width === "number" ? `${width}px` : width;
}

if (height !== undefined) {
  containerStyle.height =
    typeof height === "number" ? `${height}px` : height;
}

if (aspectRatio) {
  containerStyle.aspectRatio = aspectRatio;
}

const handleOnError = (e) => {
  handleError?.(e);
  onError?.(e);

  e.target.onerror = null;
  e.target.src =
    'data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" width="800" height="400" fill="%23f3f4f6"><rect width="100%" height="100%"/><text x="50%" y="50%" fill="%239ca3af" font-family="sans-serif" font-size="24" text-anchor="middle" dominant-baseline="middle">Image Not Available</text></svg>';
};

const imgElement = (
  <img
    ref={imgRef}
    src={src}
    alt={alt}
    loading={loading}
    decoding={decoding}
    onLoad={(e) => {
      setLoaded(true);
      handleLoad?.(e);
    }}
    onError={handleOnError}
    className={`lazy-img ${
      loaded ? "lazy-img--loaded" : "lazy-img--loading"
    } ${imgClassName || className || ""}`}
    style={{
      width: "100%",
      height: "100%",
      display: "block",
      ...imgStyle,
    }}
    {...props}
  />
);
  return (
    <div className={`lazy-img-container ${className}`} style={containerStyle}>
      {/* Shimmer skeleton layer */}
      {!loaded && <div className="lazy-img-skeleton" />}

      {/* Optional low-opacity blurred preview */}
      {!loaded && previewSrc && (
        <img
          src={previewSrc}
          alt=""
          aria-hidden="true"
          className="lazy-img-preview"
        />
      )}

      {webpSrc ? (
        <picture>
          <source srcSet={webpSrc} type="image/webp" />
          {imgElement}
        </picture>
      ) : (
        imgElement
      )}
    </div>
  );
};

export default LazyImage;

import React, { useEffect } from 'react';
import FocusTrap from './FocusTrap';

/**
 * Modal
 *
 * Accessible modal dialog component.
 *
 * Accessibility features added (issue #5308):
 *  - Focus is trapped inside the modal while it is open (WCAG 2.1 SC 2.1.2).
 *  - Pressing Escape closes the modal (WCAG 2.1 SC 2.1.2 / common pattern).
 *  - Focus returns to the trigger element when the modal closes.
 *  - `role="dialog"`, `aria-modal="true"`, and `aria-labelledby` are set.
 *  - Background scroll is locked while the modal is open.
 *
 * @param {object}   props
 * @param {boolean}  props.isOpen        - Controls visibility.
 * @param {Function} props.onClose       - Called to close the modal.
 * @param {string}  [props.title]        - Modal title text (rendered in header).
 * @param {string}  [props.titleId]      - Optional id for aria-labelledby; auto-generated if omitted.
 * @param {React.ReactNode} props.children
 * @param {string}  [props.className]    - Extra classes for the modal panel.
 * @param {boolean} [props.hideCloseBtn] - Hides the × button when true.
 */
const Modal = ({
  isOpen,
  onClose,
  title,
  titleId = 'modal-title',
  children,
  className = '',
  hideCloseBtn = false,
}) => {
  // Lock background scroll while the modal is open.
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
    return () => {
      document.body.style.overflow = '';
    };
  }, [isOpen]);

  if (!isOpen) return null;

  return (
    /* Backdrop */
    <div
      className="fixed inset-0 z-50 flex items-center justify-center"
      aria-hidden="false"
    >
      {/* Overlay */}
      <div
        className="absolute inset-0 bg-black bg-opacity-50"
        onClick={onClose}
        aria-hidden="true"
      />

      {/* Dialog panel wrapped in FocusTrap */}
      <FocusTrap isActive={isOpen} onEscape={onClose}>
        <div
          role="dialog"
          aria-modal="true"
          aria-labelledby={title ? titleId : undefined}
          className={`relative z-10 w-full max-w-lg rounded-xl bg-white p-6 shadow-xl dark:bg-gray-900 ${className}`}
        >
          {/* Header */}
          {(title || !hideCloseBtn) && (
            <div className="mb-4 flex items-center justify-between">
              {title && (
                <h2
                  id={titleId}
                  className="text-lg font-semibold text-gray-900 dark:text-white"
                >
                  {title}
                </h2>
              )}
              {!hideCloseBtn && (
                <button
                  type="button"
                  onClick={onClose}
                  aria-label="Close modal"
                  className="ml-auto rounded-md p-1 text-gray-400 hover:bg-gray-100 hover:text-gray-600 focus:outline-none focus:ring-2 focus:ring-indigo-500 dark:hover:bg-gray-700 dark:hover:text-gray-300"
                >
                  {/* × icon */}
                  <svg
                    xmlns="http://www.w3.org/2000/svg"
                    className="h-5 w-5"
                    viewBox="0 0 20 20"
                    fill="currentColor"
                    aria-hidden="true"
                  >
                    <path
                      fillRule="evenodd"
                      d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z"
                      clipRule="evenodd"
                    />
                  </svg>
                </button>
              )}
            </div>
          )}

          {/* Body */}
          {children}
        </div>
      </FocusTrap>
    </div>
  );
};

export default Modal;

