      </div>

      <div className="space-y-4 max-h-96 overflow-y-auto mb-6 pr-2">
        {questions.map(q => (
          <div key={q.id} className={`p-4 rounded-lg border ${q.answered ? 'border-emerald-500/30 bg-emerald-900/10' : 'border-slate-700 bg-slate-800'}`}>
