                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 15l7-7 7 7"></path>
                </svg>
                <span className="text-xs font-bold">{q.upvotes}</span>
              </button>
            </div>
            {q.answered && (
              <div className="mt-3 text-xs text-emerald-400 font-medium flex items-center gap-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path>
                </svg>
                Answered Live
              </div>
            )}
          </div>
        ))}
      </div>

      <form onSubmit={submitQuestion} className="relative">
        <input 
          type="text" 
          value={newQuestion}
          onChange={(e) => setNewQuestion(e.target.value)}
          placeholder="Ask a question..."
          className="w-full bg-slate-800 border border-slate-700 rounded-lg py-3 pl-4 pr-12 text-sm focus:outline-none focus:border-blue-500"
        />
        <button 
          type="submit"
          className="absolute right-2 top-1/2 -translate-y-1/2 text-blue-500 hover:text-blue-400 p-2"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8"></path>
          </svg>
        </button>
      </form>
    </div>
  );
};

export default LiveQA;

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const RealtimePolling = ({ eventId }) => {
  const [activePoll, setActivePoll] = useState(null);

  useEffect(() => {
    // Simulated SSE connection for active polls
    const evtSource = new EventSource(`/api/events/${eventId}/polls/stream`);
    evtSource.onmessage = (event) => {
      setActivePoll(JSON.parse(event.data));
    };
    return () => evtSource.close();
  }, [eventId]);

  if (!activePoll) return null;

  return (
    <AnimatePresence>
      <motion.div 
        initial={{ opacity: 0, y: 50 }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, y: 50 }}
        className="fixed bottom-6 right-6 w-80 bg-white dark:bg-gray-900 rounded-2xl shadow-2xl border border-indigo-100 dark:border-indigo-900/30 p-5 z-50"
      >
        <div className="flex items-center gap-2 mb-4">
          <span className="relative flex h-3 w-3">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
            <span className="relative inline-flex rounded-full h-3 w-3 bg-red-500"></span>
          </span>
          <h3 className="text-sm font-bold text-gray-900 dark:text-white uppercase tracking-wider">Live Poll</h3>
        </div>
        <p className="text-sm text-gray-700 dark:text-gray-300 font-medium mb-4">{activePoll.question}</p>
        <div className="space-y-2">
          {activePoll.options.map((opt, i) => (
            <button key={i} className="w-full text-left px-4 py-2 rounded-xl bg-gray-50 hover:bg-indigo-50 dark:bg-gray-800 dark:hover:bg-indigo-900/40 border border-gray-200 dark:border-gray-700 transition-colors text-sm font-medium">
              {opt.text}
            </button>
          ))}
        </div>
      </motion.div>
    </AnimatePresence>
  );
};

export default RealtimePolling;

import React, { useState, useEffect } from 'react';
import { Clock } from 'lucide-react';

const WaitlistPromotionBanner = ({ eventName, expirationTime, onClaim, onDecline }) => {
  const [timeLeft, setTimeLeft] = useState("");

  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date().getTime();
      const distance = expirationTime - now;

      if (distance < 0) {
        clearInterval(timer);
        setTimeLeft("EXPIRED");
        return;
      }

      const hours = Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
      const minutes = Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60));
      const seconds = Math.floor((distance % (1000 * 60)) / 1000);

      setTimeLeft(`${hours}h ${minutes}m ${seconds}s`);
    }, 1000);

    return () => clearInterval(timer);
  }, [expirationTime]);

  if (timeLeft === "EXPIRED") return null;

  return (
    <div className="bg-gradient-to-r from-orange-500 to-amber-500 text-white rounded-lg p-4 shadow-lg flex flex-col md:flex-row items-center justify-between">
      <div className="flex items-center gap-3 mb-3 md:mb-0">
        <div className="bg-white/20 p-2 rounded-full">
          <Clock size={24} />
        </div>
        <div>
          <h4 className="font-bold text-lg">A spot opened up for {eventName}!</h4>
          <p className="text-sm text-orange-100">Claim your spot before the timer runs out.</p>
        </div>
      </div>

      <div className="flex items-center gap-4 w-full md:w-auto">
        <div className="text-xl font-mono font-bold bg-black/20 px-3 py-1 rounded">
          {timeLeft}
        </div>
        <button 
          onClick={onClaim}
          className="bg-white text-orange-600 hover:bg-orange-50 font-bold py-2 px-4 rounded transition shadow"
        >
          Claim Spot
        </button>
        <button 
          onClick={onDecline}
          className="bg-transparent hover:bg-black/10 text-white font-medium py-2 px-3 rounded transition"
        >
          Decline
        </button>
      </div>
    </div>
  );
};

