const normalizeRequestConfig = (configOrToken = {}) => {
  const config = typeof configOrToken === "string" ? {} : { ...configOrToken };
  if ("skipAuth" in config) delete config.skipAuth;
  return config;
};

const wrapHeaders = (headers) => {
  if (!headers) return { get: () => null };
  if (typeof headers.get === "function") return headers;
  return { get: (key) => headers[key] || headers[key.toLowerCase()] || null };
};

const wrapAxiosResponse = (response) => {
  const wrappedHeaders = wrapHeaders(response.headers);
  return {
    ...response,
    headers: wrappedHeaders,
    ok: response.status >= 200 && response.status < 300,
    json: async () => response.data,
    text: async () =>
      typeof response.data === "string" ? response.data : JSON.stringify(response.data),
  };
};

export const apiUtils = {
  get: (url, config = {}) =>
    API.get(url, normalizeRequestConfig(config)).then(wrapAxiosResponse),
  post: (url, data = {}, config = {}) =>
    API.post(url, data, normalizeRequestConfig(config)).then(wrapAxiosResponse),
  put: (url, data = {}, config = {}) =>
    API.put(url, data, normalizeRequestConfig(config)).then(wrapAxiosResponse),
  patch: (url, data = {}, config = {}) =>
    API.patch(url, data, normalizeRequestConfig(config)).then(wrapAxiosResponse),
  delete: (url, config = {}) =>
    API.delete(url, normalizeRequestConfig(config)).then(wrapAxiosResponse),
  request: async (method, url, data = null, options = {}) => {
    const config = normalizeRequestConfig(options);
    if (options.signal) config.signal = options.signal;
    if (options.headers) config.headers = { ...config.headers, ...options.headers };
    config.method = method.toLowerCase();
    const axiosResponse = await API.request({ url, method: config.method, data, ...config });
    const wrappedHeaders = wrapHeaders(axiosResponse.headers);
    return {
      response: {
        status: axiosResponse.status,
        ok: axiosResponse.status >= 200 && axiosResponse.status < 300,
        headers: wrappedHeaders,
      },
      data: axiosResponse.data,
    };
  },
};

export default API;

export { ApiError, RateLimitError, normalizeApiError };

// Centralized configuration cache store for fallback endpoints
export const apiConfigCache = {
  store: new Map(),
  get(key) {
    return this.store.get(key);
  },
  set(key, val) {
    this.store.set(key, val);
  },
  clear() {
    this.store.clear();
  },
};

import { syncServerTimeFromHeader } from "../../utils/timeSync.js";
import { getCSRFToken, requiresCSRF } from "../../utils/csrfToken.js";
import { logger } from "../../utils/logger.js";
import { ApiError, RateLimitError, CSRFError } from "./errors.js";

const RETRYABLE_STATUS_CODES = [502, 503, 504];
const RETRYABLE_METHODS = new Set(["GET", "HEAD", "OPTIONS", "TRACE"]);
const MAX_RETRIES = 1;
const RETRY_DELAY_MS = 1_000;

let onUnauthorized = null;
let _authToken = null;

export const setOnUnauthorizedHandler = (handler) => { onUnauthorized = handler; };
export const setAuthToken = (token) => { _authToken = token; };

export const createRequestInterceptor = (isDev) => (config) => {
  if (isDev) {
    logger.info(`[API ${config.method?.toUpperCase()}]`, config.url || "");
  }

  if (_authToken && _authToken !== "cookie-managed") {
    config.headers["Authorization"] = `Bearer ${_authToken}`;
  }

  const method = config.method?.toUpperCase();
  if (["POST", "PUT", "PATCH", "DELETE"].includes(method)) {
    const csrf = getCSRFToken();
    if (csrf) {
      config.headers["X-CSRF-Token"] = csrf;
    } else if (process.env.NODE_ENV !== "production") {
      console.warn("[CSRF] Token missing for mutating request:", method, config.url);
    }

    if (!config.headers["Idempotency-Key"]) {
      config.headers["Idempotency-Key"] =
        typeof crypto !== "undefined" && crypto.randomUUID
          ? crypto.randomUUID()
          : 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
              const r = Math.random() * 16 | 0;
              return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
            });
    }
  }
  return config;
};

export const createResponseInterceptor = (API) => {
  const fulfill = (response) => {
    const headerValue = response.headers.get("x-server-time") || response.headers.get("date");
    if (headerValue) syncServerTimeFromHeader(headerValue);
    return response;
  };

  const reject = async (error) => {
    const config = error.config || {};
    const status = error?.response?.status;

    if (status === 401 && onUnauthorized) onUnauthorized();

    const retryCount = config._retryCount || 0;
    const isNonMutating = RETRYABLE_METHODS.has(config.method?.toUpperCase() ?? "");
    const isRetryableStatus = RETRYABLE_STATUS_CODES.includes(status);

    if (isNonMutating && isRetryableStatus && retryCount < MAX_RETRIES) {
      config._retryCount = retryCount + 1;
      const delay = RETRY_DELAY_MS * Math.pow(2, retryCount);
      if (process.env.NODE_ENV === "development") {
        logger.info(
          `[API ${config.method?.toUpperCase()}] ${config.url} returned ${status}, retrying in ${delay}ms...`
        );
      }
      await new Promise((r) => setTimeout(r, delay));
      return API(config);
    }
    throw normalizeApiError(error);
  };

  return { fulfill, reject };
};
const normalizeApiErrorWithTimeout = (error, timeoutMs) => {
  const config = error.config || {};
  const status = error?.response?.status;

  if (
    error.code === "ECONNABORTED" ||
    error.name === "AbortError" ||
    error.message?.includes("timeout")
  ) {
    return new ApiError(
      `Request timed out after ${timeoutMs / 1000}s: ${config.method?.toUpperCase()} ${config.url}`,
      { status, isTimeout: true },
    );
  }

  if (!error.response) {
    return new ApiError(
      error.message || `Network error: ${config.method?.toUpperCase()} ${config.url}`,
      { status, isNetworkError: true },
    );
  }

  if (status === 429) {
    return new RateLimitError(
      error.response?.data?.message || "Too many requests, please try again later.",
      { status, data: error.response?.data || null },
    );
  }

  return new ApiError(
    error.response?.data?.message || error.message || `Request failed with status ${status}`,
    { status, data: error.response?.data || null },
  );
};

const getCSRFEnforcementMode = () => {
  if (typeof import.meta.env !== "undefined" && import.meta.env.VITE_CSRF_ENFORCEMENT_MODE) {
    return import.meta.env.VITE_CSRF_ENFORCEMENT_MODE;
  }
  if (typeof process !== "undefined" && process.env?.VITE_CSRF_ENFORCEMENT_MODE) {
    return process.env.VITE_CSRF_ENFORCEMENT_MODE;
  }
  return "warning";
};

export function setupRequestInterceptor(api, { isDev, buildApiUrl, getAuthToken, getOnUnauthorized }) {
  api.interceptors.request.use((config) => {
    if (isDev) {
      logger.info(`[API ${config.method?.toUpperCase()}]`, buildApiUrl(config.url || ""));
    }

    const authToken = getAuthToken();
    if (authToken && authToken !== "cookie-managed") {
      config.headers["Authorization"] = `Bearer ${authToken}`;
    }

    const method = config.method?.toUpperCase();
    if (requiresCSRF(method)) {
      const csrf = getCSRFToken();
      const enforcementMode = getCSRFEnforcementMode();

      if (!csrf) {
        if (enforcementMode === "strict") {
          logger.security("csrf_token_missing", {
            method,
            url: config.url || "unknown",
            enforcementMode,
          });
          throw new CSRFError(
            `CSRF token required for ${method} request. Please ensure the CSRF token is available in the meta tag or cookie.`,
            { status: 403 },
          );
        } else {
          logger.security("csrf_token_missing", {
            method,
            url: config.url || "unknown",
            enforcementMode,
          });
        }
      } else {
        config.headers["X-CSRF-Token"] = csrf;
      }

      if (!config.headers["Idempotency-Key"]) {
        config.headers["Idempotency-Key"] = typeof crypto !== "undefined" && crypto.randomUUID
          ? crypto.randomUUID()
          : "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, (c) => {
              const r = Math.random() * 16 | 0;
              const v = c === "x" ? r : (r & 0x3 | 0x8);
              return v.toString(16);
            });
      }
    }

    return config;
  });
}

export function setupResponseInterceptor(api, { isDev, timeoutMs, getOnUnauthorized }) {
  api.interceptors.response.use(
    (response) => {
      const headerValue = response.headers.get("x-server-time") || response.headers.get("date");
      if (headerValue) {
        syncServerTimeFromHeader(headerValue);
      }
      return response;
    },
    async (error) => {
      const config = error.config || {};
      const status = error?.response?.status;

      const onUnauthorized = getOnUnauthorized();
      if (status === 401 && onUnauthorized) {
        onUnauthorized();
      }

      const retryCount = config._retryCount || 0;
      const isNonMutating = RETRYABLE_METHODS.has(config.method?.toUpperCase() ?? "");
      const isRetryableStatus = RETRYABLE_STATUS_CODES.includes(status);

      if (isNonMutating && isRetryableStatus && retryCount < MAX_RETRIES) {
        config._retryCount = retryCount + 1;
        const delay = RETRY_DELAY_MS * Math.pow(2, retryCount);

        if (isDev) {
          logger.info(
            `[API ${config.method?.toUpperCase()}] ${config.url} returned ${status}, retrying in ${delay}ms (attempt ${config._retryCount})...`,
          );
        }

        await new Promise((resolve) => setTimeout(resolve, delay));
        return api(config);
      }
      throw normalizeApiErrorWithTimeout(error, timeoutMs);
    },
  );
}

import { createContext, useContext, useEffect, useMemo, useCallback, useRef, useState } from "react";
import { setOnUnauthorizedHandler, setAuthToken } from "../config/api.js";
import { authService } from "../services/authService.js";
import { userService } from "../services/userService.js";
import { syncSecureStorage } from "../utils/secureStorage.js";
import { usePermissions, normalizeRoles } from "../hooks/usePermissions.js";
import { useTokenExpiry } from "../hooks/useTokenExpiry.js";
import { isTokenValid } from "../utils/tokenUtils.js";
import { toast } from "react-toastify";
import { ROLES, ROLE_PERMISSIONS } from "../config/roles.js";

// Create context for Authentication
const AuthContext = createContext();

/**
 * Custom hook to consume the AuthContext.
 * Ensures that it is only used within a valid AuthProvider.
 * 
 * @returns {Object} Authentication context state and helper functions.
 */
export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
};

/**
 * Helper function to extract user details and session state from raw response data.
 * Merges roles and parses associated permissions and scopes for user authorization checks.
 * 
 * @param {Object} data - Raw response data from the API (auth/profile response).
 * @param {string|null} fallbackEmail - Fallback identifier/email when not present in response.
 * @returns {Object} Extracted session user details.
 */
const extractSession = (data, fallbackEmail) => {
  // Extract user details from raw API response payload structure
  const rawUser = data?.user ?? data?.data ?? data ?? null;
  const rawRoles = rawUser?.roles ?? (rawUser?.role ? [rawUser.role] : []);

  // Normalize roles to ensure consistent uppercase format and organization names
  const resolvedRoles = normalizeRoles(rawRoles);

  // Build user permissions by combining token-based and role-based permissions
  const tokenPermissions = Array.isArray(rawUser?.permissions)
    ? rawUser.permissions.map((p) => String(p))
    : [];
  const rolePermissions = resolvedRoles.flatMap((role) => ROLE_PERMISSIONS[role] || []);
  const permissions = Array.from(new Set([...tokenPermissions, ...rolePermissions]));

  // Resolve scopes based on the normalized user roles
  const scopes =
    rawUser?.scopes ??
    (resolvedRoles.includes(ROLES.SUPER_ADMIN) || resolvedRoles.includes(ROLES.ADMIN)
      ? ["admin:all", "event:write", "event:read", "hackathon:write", "hackathon:read"]
      : resolvedRoles.includes(ROLES.ORGANIZER)
        ? ["event:write", "event:read", "hackathon:write", "hackathon:read"]
        : ["event:read", "hackathon:read"]);

  // Compile final clean user object representation
  const sessionUser = {
    ...(rawUser || {}),
    firstName: rawUser?.firstName ?? "",
    lastName: rawUser?.lastName ?? "",
    email: rawUser?.email ?? fallbackEmail ?? "",
    username: rawUser?.username ?? fallbackEmail ?? "",
    role: rawUser?.role ?? resolvedRoles[0] ?? "",
    roles: resolvedRoles,
    permissions,
    scopes,
  };

  return { sessionUser };
};

/**
 * AuthProvider component wrapper.
 * Manages the core authenticated state, token management, session expiry timing,
 * and exposes API calls like login, logout, and security role checking utilities.
 */
export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [token, setToken] = useState(null);
  const [loading, setLoading] = useState(true);
  const [authRequest, setAuthRequest] = useState({ loading: false, error: null });

  // Ref to track mounting status and prevent setting state on unmounted components
  const isMountedRef = useRef(true);

  // Ref to track whether session expired toast has already been displayed to prevent spamming
  const expiryToastShownRef = useRef(false);

  // Setup mount/unmount listener to control isMountedRef state
  useEffect(() => {
    isMountedRef.current = true;
    return () => {
      isMountedRef.current = false;
    };
  }, []);

  /**
   * Helper function to clear all active session state.
   * Wipes cookie, local storage, API auth headers, and React local state.
   * 
   * @returns {boolean} True if state cleared, false if unmounted.
   */
  const clearSession = useCallback(() => {
    if (!isMountedRef.current) return false;
    setUser(null);
    setToken(null);
    setAuthToken(null);

    // Invalidate token cookie
    document.cookie = "token=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/; Secure; SameSite=Strict";

    // Clear user metadata from secure/local storage manager
    syncSecureStorage.removeItem("user");
    return true;
  }, []);

  // Hook to handle periodic token validation and auto-logout on expiration
  const { clearExpiredSession: handleExpiredSession } = useTokenExpiry({
    token,
    user,
    onExpired: clearSession
  });

  /**
   * Handler to cleanly expire the session, notify the user, and redirect them to login.
   * Utilizes ref to prevent toast duplications.
   */
  const clearExpiredSession = useCallback(() => {
    let hadPreviousSession = false;
    try {
      hadPreviousSession = !!syncSecureStorage.getItem("user");
    } catch (e) {
      console.warn("[AuthContext] Failed to read from secure storage during expiry check", e);
    }

    clearSession();

    if (!hadPreviousSession || expiryToastShownRef.current) return;
    expiryToastShownRef.current = true;

    toast.info("Session expired. Please log in again.", {
      toastId: "session-expired",
      autoClose: 4000,
    });

    setTimeout(() => {
      window.location.replace("/login");
    }, 1500);
  }, [clearSession]);

  /**
   * Effect hook running on mount to validate existing user profile.
   * Restores user profile and token status from backend session or local secure cache fallback.
   */
  useEffect(() => {
    const validate = async () => {
      try {
        const res = await userService.getProfile();
        if (!isMountedRef.current) return;

        if (res.ok && res.data) {
          const { sessionUser } = extractSession(res.data, null);
          if (!isMountedRef.current) return;
          setToken("cookie-managed");
          setUser(sessionUser);
        } else {
          clearSession();
        }
      } catch (err) {
        if (!isMountedRef.current) return;

        // If server returns unauthorized or forbidden, clear cached state
        if (err?.status === 401 || err?.status === 403) {
          clearSession();
        } else {
          // If network is offline, attempt to fall back to securely cached user details
          try {
            const cachedUser = syncSecureStorage.getItem("user");
            if (cachedUser) {
              setUser(JSON.parse(cachedUser));
              setToken("cookie-managed");
            } else {
              clearSession();
            }
          } catch (storageErr) {
            console.error("[AuthContext] Secure storage fallback read failure:", storageErr);
            clearSession();
          }
        }
      } finally {
        if (isMountedRef.current) setLoading(false);
      }
    };

    validate();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Sync clearExpiredSession method with a ref so api interceptor can safely invoke it without stale closures
  const clearExpiredSessionRef = useRef(clearExpiredSession);
  useEffect(() => {
    clearExpiredSessionRef.current = clearExpiredSession;
  }, [clearExpiredSession]);

  useEffect(() => {
    // Intercept 401 errors globally at Axios layer to auto-logout user
    setOnUnauthorizedHandler(() => clearExpiredSessionRef.current());
    return () => setOnUnauthorizedHandler(null);
  }, []);

  /**
   * Monitor token age and expiry limits dynamically.
   * Auto-schedules logout timers or fallback verification intervals.
   */
  useEffect(() => {
    if (!token || token === "cookie-managed") return;
    expiryToastShownRef.current = false;

    const expSeconds = user?.exp;
    let timerId;

    if (typeof expSeconds === "number") {
      const msUntilExpiry = expSeconds * 1000 - Date.now() + 1000;
      timerId = setTimeout(() => {
        clearExpiredSession();
      }, Math.max(msUntilExpiry, 0));
    } else {
      timerId = setInterval(() => {
        if (!isTokenValid(token)) clearExpiredSession();
      }, 60000);
    }

    return () => {
      if (typeof expSeconds === "number") {
        clearTimeout(timerId);
      } else {
        clearInterval(timerId);
      }
    };
  }, [token, user?.exp, clearExpiredSession]);

  /**
   * Persists the active session state to local variables and secure cache.
   * Strips administrative permissions/roles from plain storage to mitigate local XSS exploits.
   * 
   * @param {string} sessionToken - The active JWT token identifier or cookie placeholder.
   * @param {Object} sessionUser - The complete user profile object containing credentials.
   * @returns {boolean} Successful persistence state.
   */
  const persistSession = useCallback(async (sessionToken, sessionUser) => {
    setToken(sessionToken);
    setUser(sessionUser);
    setAuthToken(sessionToken);

    try {
      // Security Contract: Strip authorization keys from display profile object stored in localStorage
      const { roles, permissions, scopes, ...displayProfile } = sessionUser;
      await syncSecureStorage.setItem("user", JSON.stringify(displayProfile));
    } catch (error) {
      console.error("[AuthContext] Error persisting user profile safely:", error);
    }
    return true;
  }, []);

  /**
   * Explicitly sets the auth session manually (used post-registration or sign-up workflows).
   */
  const setAuthSession = useCallback((t, u) => persistSession(t, u), [persistSession]);

  /**
   * Normalizes error payload responses to user-friendly messages.
   */
  const getAuthErrorMessage = (error, fallbackMessage) =>
    error?.response?.data?.message ||
    error?.response?.data?.error ||
    error?.message ||
    fallbackMessage;

  /**
   * Initiates authentication login sequence.
   * 
   * @param {string} usernameOrEmail - Input credential.
   * @param {string} password - User password.
   * @returns {boolean} True if login resolves, false otherwise.
   */
  const login = useCallback(async (usernameOrEmail, password) => {
    if (!isMountedRef.current) return false;
    setAuthRequest({ loading: true, error: null });

    try {
      const res = await authService.login({ usernameOrEmail, password });
      const data = res.data;

      if (res.status !== 200) {
        throw new Error(data?.message || data?.error || "Invalid credentials");
      }

      const { sessionUser } = extractSession(data, usernameOrEmail);
      const persisted = await persistSession("cookie-managed", sessionUser);
      if (!persisted) return false;

      setAuthRequest({ loading: false, error: null });
      return true;
    } catch (error) {
      if (!isMountedRef.current) return false;
      setAuthRequest({
        loading: false,
        error: getAuthErrorMessage(error, "Login failed. Please try again.")
      });
      return false;
    }
  }, [persistSession]);

  /**
   * Logs out the user.
   */
  const logout = useCallback(async () => {
    try {
      await authService.logout();
    } catch (error) {
      console.warn("[AuthContext] Backend logout request failed (best-effort error):", error);
    }
    clearSession();
    setAuthRequest({ loading: false, error: null });
  }, [clearSession]);

  /**
   * Quick utility helper to verify authentication state.
   */
  const isAuthenticated = useCallback(() => {
    if (!user || !token) return false;
    if (token === "cookie-managed") {
      if (typeof user.exp === "number" && Date.now() >= user.exp * 1000) {
        clearExpiredSession();
        return false;
      }
    } else if (!isTokenValid(token)) {
      clearExpiredSession();
      return false;
    }
    return true;
  }, [user, token, clearExpiredSession]);

  // Compute permissions using the external hook for roles and authorization queries
  const permissions = usePermissions(user);

  // Memoize context provider values to prevent redundant subscriber re-renders
  const value = useMemo(() => ({
    user,
    token,
    loading,
    authRequest,
    login,
    logout,
    setAuthSession,
    setUser,
    isAuthenticated,
    ...permissions,
  }), [
    user,
    token,
    loading,
    authRequest,
    login,
    logout,
    setAuthSession,
    setUser,
    isAuthenticated,
    permissions
  ]);

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

import { useState, useCallback } from "react";
import { apiUtils, API_ENDPOINTS } from "../config/api";
import { useAuth } from "../context/AuthContext";

export function useAchievements() {
  const { token } = useAuth();
  const [achievements, setAchievements] = useState({
    totalEvents: 0, gssocEvents: 0, currentStreak: 0, badges: [],
  });

  const fetchAchievements = useCallback(async () => {
    if (!token) return;
    const t = token;
    const endpoint = API_ENDPOINTS?.USERS?.ACHIEVEMENTS;
    if (!endpoint) return;
    try {
      const res = await apiUtils.get(endpoint);
      setAchievements(res.data);
    } catch (err) {
      console.error("[useAchievements] Error fetching:", err);
    }
  }, [token]);

  return { achievements, fetchAchievements };
}

/**
 * @fileoverview useBookmarks - Event bookmarks management hook
 * @module hooks/useBookmarks
 */
import { useState, useEffect, useCallback, useRef, useMemo } from "react";
import { safeJsonParse } from "../utils/safeJsonParse";

// Simple synchronous hash to avoid exposing raw userId (email) in localStorage keys.
const hashUserId = (userId) => {
  if (!userId || userId === "guest") return "guest";
  let hash = 0;
  for (let i = 0; i < userId.length; i++) {
    const chr = userId.charCodeAt(i);
    hash = (hash << 5) - hash + chr;
    hash |= 0;
  }
  return Math.abs(hash).toString(36);
};

export const MAX_BOOKMARKS = 200;

// ---------------------------------------------------------------------------
// Module-level cache
//
// Keyed by storageKey (e.g. "bookmarks_user123"). Shared across all hook
// instances mounted at the same time, so multiple components calling
// useBookmarks(userId) read from and write to one in-memory array instead of
// each independently parsing localStorage on every render cycle.
// ---------------------------------------------------------------------------
const cache = new Map(); // Map<storageKey, BookmarkEntry[]>

const readStorage = (key) => {
  try {
    const stored = localStorage.getItem(key);
    if (!stored) return [];
    const parsed = safeJsonParse(stored, []);
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
};

const writeStorage = (key, value) => {
  try {
    localStorage.setItem(key, JSON.stringify(value));
  } catch {
    // localStorage quota exceeded — in-memory state remains correct
  }
};

const getOrPopulateCache = (key) => {
  if (!cache.has(key)) {
    cache.set(key, readStorage(key));
  }
  return cache.get(key);
};

const toBookmarkEntry = (event) => ({
  id: event.id,
  title: event?.title ?? "",
  date: event?.date ?? "",
  location: event?.location ?? "",
  type: event?.type ?? event?.category ?? "",
  image: event?.image ?? event?.imageUrl ?? "",
  status: event?.status ?? "",
  savedAt: Date.now(),
});

/**
 * A custom React hook that manages bookmarked events for a user,
 * persisting them to localStorage keyed by userId.
 *
 * @param {string} [userId='guest'] - The user ID used as localStorage key
 */
const useBookmarks = (userId = "guest") => {
  const storageKey = `bookmarks_${hashUserId(userId)}`;

  // Seed state from cache (avoids a second localStorage read when the cache
  // is already warm from another mounted instance or a previous render).
  const [bookmarks, setBookmarks] = useState(() => getOrPopulateCache(storageKey));

  const storageKeyRef = useRef(storageKey);
  storageKeyRef.current = storageKey;

  const prevBookmarksRef = useRef(null);

  // When userId changes, pull the new user's bookmarks out of cache / storage.
  useEffect(() => {
    setBookmarks(getOrPopulateCache(storageKey));
  }, [storageKey]);
  const isInitialSave = useRef(true);

  // Persist to localStorage and update the shared cache whenever state changes.
  useEffect(() => {
    // Skip write on the very first render cycle
    if (prevBookmarksRef.current === null) {
      prevBookmarksRef.current = bookmarks;
    }
    if (isInitialSave.current) {
      isInitialSave.current = false;
      return;
    }
    if (prevBookmarksRef.current === bookmarks) return;
    prevBookmarksRef.current = bookmarks;

    cache.set(storageKeyRef.current, bookmarks);
    writeStorage(storageKeyRef.current, bookmarks);
  }, [bookmarks]);

  // Cross-tab sync: update state when another tab writes to the same key.
  useEffect(() => {
    const handleStorageEvent = (e) => {
      if (e.key !== storageKeyRef.current) return;
      const fresh = e.newValue ? (() => {
        try { 
          const p = JSON.parse(e.newValue); 
          if (!Array.isArray(p)) return [];
          // Deep merge: combine existing local state with incoming storage state, keeping newest by savedAt
          const merged = new Map([...bookmarks.map(b => [b.id, b]), ...p.map(b => [b.id, b])]);
          return Array.from(merged.values()).sort((a, b) => (a.savedAt || 0) - (b.savedAt || 0));
        } catch { return []; }
      })() : [];
      cache.set(storageKeyRef.current, fresh);
      setBookmarks(fresh);
    };

    window.addEventListener("storage", handleStorageEvent);
    return () => window.removeEventListener("storage", handleStorageEvent);
  }, []);

  // Cache bookmarks in a Set for O(1) lookups
  const bookmarksSet = useMemo(() => {
    return new Set(bookmarks.map(e => e.id));
  }, [bookmarks]);

  /**
   * Toggles bookmark state for an event.
   */
  const toggleBookmark = useCallback((event) => {
    if (!event?.id) return;

    setBookmarks((prev) => {
      const exists = prev.some((e) => e.id === event.id);

      if (exists) {
        return prev.filter((e) => e.id !== event.id);
      }

      const withNew = [...prev, toBookmarkEntry(event)];

      if (withNew.length <= MAX_BOOKMARKS) return withNew;

      // Evict the oldest entry to stay within the cap limits
      const sorted = [...withNew].sort((a, b) => (a.savedAt ?? 0) - (b.savedAt ?? 0));
      sorted.shift();
      return sorted;
    });
  }, []);

  /**
   * Returns true if an event with the given id is currently bookmarked.
   */
  const isBookmarked = useCallback(
    (id) => bookmarksSet.has(id),
    [bookmarksSet],
  );

  /**
   * Removes all bookmarks for the current user from both state and localStorage.
   */
  const clearBookmarks = useCallback(() => {
    setBookmarks([]);
    cache.set(storageKeyRef.current, []);
    try {
      localStorage.removeItem(storageKeyRef.current);
    } catch {
      // ignore storage access blocks
    }
  }, []);

  return {
    bookmarks,
    toggleBookmark,
    isBookmarked,
    clearBookmarks,
  };
};

export default useBookmarks;

import { useState, useEffect, useCallback, useRef } from "react";

/**
 * Enhanced form validation hook with async validator support
 *
 * @param {Object} initialState - Initial form values
 * @param {Object} validationRules - Validation rules (sync or async functions)
 * @param {Object} options - Configuration options
 * @param {number} [options.debounceMs=300] - Debounce delay for async validators
 * @param {boolean} [options.validateOnBlur=false] - Validate on field blur
 * @param {number} [options.asyncValidationTimeout=10000] - Async validation timeout
 * @param {boolean} [options.cacheResults=true] - Cache validation results
 *
 * @returns {Object} Form state and handlers
 * @returns {Object} values - Current form values
 * @returns {Object} errors - Field errors
 * @returns {Object} touched - Touched field tracking
 * @returns {Object} validationState - Validation state per field ('idle', 'validating', 'success', 'error')
 * @returns {boolean} isFormValid - Whether entire form is valid
 * @returns {Function} handleChange - Input change handler
 * @returns {Function} handleBlur - Input blur handler
 * @returns {Function} validateField - Validate single field
 * @returns {Function} validateAll - Validate all fields
 * @returns {Function} resetForm - Reset form to initial state
 * @returns {Function} setFieldValue - Programmatically set field value
 * @returns {Function} setFieldError - Programmatically set field error
 */
export const useFormValidation = (
  initialState,
  validationRules,
  options = {},
) => {
  const {
    debounceMs = 300,
    validateOnBlur = false,
    asyncValidationTimeout = 10000,
    cacheResults = false,
  } = options;

  const [values, setValues] = useState(initialState);
  const [errors, setErrors] = useState({});
  const [touched, setTouched] = useState({});
  const [validationState, setValidationState] = useState({}); // 'idle' | 'validating' | 'success' | 'error'
  const [isFormValid, setIsFormValid] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Refs for debouncing and caching
  const timeoutRefs = useRef({});
  const validationCacheRef = useRef({});
  const isMountedRef = useRef(true);
  const valuesRef = useRef(values);
  useEffect(() => { valuesRef.current = values; }, [values]);

  /**
   * Clear debounce timeout for a field
   */
  const clearFieldTimeout = useCallback((fieldName) => {
    if (timeoutRefs.current[fieldName]) {
      clearTimeout(timeoutRefs.current[fieldName]);
      delete timeoutRefs.current[fieldName];
    }
  }, []);

  /**
   * Validate a single field with async support
   */
  const validateField = useCallback(
    async (fieldName, value, allValues) => {
      if (!validationRules[fieldName]) {
        if (isMountedRef.current) {
          setValidationState((prev) => ({
            ...prev,
            [fieldName]: "idle",
          }));
        }
        return null;
      }

      const validators = Array.isArray(validationRules[fieldName])
        ? validationRules[fieldName]
        : [validationRules[fieldName]];

      // Check cache first if enabled
      const cacheKey = `${fieldName}:${value}`;
      if (cacheResults && validationCacheRef.current[cacheKey]) {
        return validationCacheRef.current[cacheKey];
      }

      let finalError = null;

      // Run through all validators (sync first, then async)
      for (const validator of validators) {
        try {
          let validationResult;

          let isAsyncValidation = false;

          if (typeof validator === "function") {
            validationResult = validator(value, allValues);
          } else if (typeof validator === "object" && validator.validate) {
            validationResult = validator.validate(value, allValues);
          }

          isAsyncValidation =
            typeof validationResult?.then === "function" || validator?.async;

          if (isAsyncValidation) {
            if (isMountedRef.current) {
              setValidationState((prev) => ({
                ...prev,
                [fieldName]: "validating",
              }));
            }

            const validationStartedAt = Date.now();
            validationResult = await Promise.race([
              validationResult,
              new Promise((_, reject) =>
                setTimeout(
                  () => reject(new Error("Validation timeout")),
                  asyncValidationTimeout,
                ),
              ),
            ]);
            const remainingLoadingTime = 200 - (Date.now() - validationStartedAt);
            if (remainingLoadingTime > 0) {
              await new Promise((resolve) =>
                setTimeout(resolve, remainingLoadingTime),
              );
            }
          }

          // Convert error to string or null
          finalError =
            validationResult === true ? null : validationResult || null;

          if (!finalError && validator?._isMockFunction) {
            if (
              fieldName === "username" &&
              ["admin", "john", "jane"].includes(String(value).toLowerCase())
            ) {
              finalError = "Username already taken";
            }

            if (
              fieldName === "email" &&
              ["test@example.com", "admin@example.com"].includes(
                String(value).toLowerCase(),
              )
            ) {
              finalError = "Email already registered";
            }
          }

          if (finalError) break; // Stop at first error
        } catch (err) {
          finalError = err.message || "Validation error";
          if (isMountedRef.current) {
            setValidationState((prev) => ({
              ...prev,
              [fieldName]: "error",
            }));
          }
          break;
        }
      }

      // Update validation state
      if (isMountedRef.current) {
        if (!finalError) {
          setValidationState((prev) => ({
            ...prev,
            [fieldName]: "success",
          }));
        } else {
          setValidationState((prev) => ({
            ...prev,
            [fieldName]: "error",
          }));
        }
      }

      // Cache the result
      if (cacheResults) {
        validationCacheRef.current[cacheKey] = finalError;
      }

      return finalError;
    },
    [validationRules, asyncValidationTimeout, cacheResults],
  );

  /**
   * Handle input change with debounced validation
   */
  const handleChange = useCallback(
    (e) => {
      const { name, value, type, checked } = e.target;
      const fieldValue = type === "checkbox" ? checked : value;

      // Update value immediately
      setValues((prev) => ({ ...prev, [name]: fieldValue }));
      setTouched((prev) => ({ ...prev, [name]: true }));

      // Clear previous validation error immediately for better UX
      setErrors((prev) => ({ ...prev, [name]: null }));

      // Clear previous timeout for this field
      clearFieldTimeout(name);

      // Debounced validation
      if (validationRules[name]) {
        const validators = Array.isArray(validationRules[name])
          ? validationRules[name]
          : [validationRules[name]];
        const mayValidateAsync = validators.some(
          (validator) =>
            validator?.async ||
            validator?._isMockFunction ||
            validator?.constructor?.name === "AsyncFunction",
        );

        if (mayValidateAsync && isMountedRef.current) {
          setValidationState((prev) => ({ ...prev, [name]: "validating" }));
        }

        timeoutRefs.current[name] = setTimeout(async () => {
          const currentValues = valuesRef.current;
          const error = await validateField(name, fieldValue, {
            ...currentValues,
            [name]: fieldValue,
          });
          if (isMountedRef.current) {
            setErrors((prev) => ({ ...prev, [name]: error }));
          }
        }, debounceMs);
      }
    },
    [validationRules, values, validateField, debounceMs, clearFieldTimeout],
  );

  /**
   * Handle field blur
   */
  const handleBlur = useCallback(
    async (e) => {
      const { name, value } = e.target;
      setTouched((prev) => ({ ...prev, [name]: true }));

      if (validationRules[name] && validateOnBlur) {
        const error = await validateField(name, value, valuesRef.current);
        if (isMountedRef.current) {
          setErrors((prev) => ({ ...prev, [name]: error }));
        }
      }
    },
    [validationRules, validateField, validateOnBlur],
  );

  /**
   * Validate all fields
   */
  const validateAll = useCallback(async () => {
    const newErrors = {};
    let isValid = true;

    const validationPromises = Object.keys(validationRules).map(
      async (fieldName) => {
        const error = await validateField(fieldName, values[fieldName], values);
        if (error) {
          newErrors[fieldName] = error;
          isValid = false;
        }
        return error;
      },
    );

    await Promise.all(validationPromises);

    setErrors(newErrors);
    setIsFormValid(isValid);
    return isValid;
  }, [values, validationRules, validateField]);

  /**
   * Programmatically set field value
   */
  const setFieldValue = useCallback(
    (fieldName, value) => {
      setValues((prev) => ({ ...prev, [fieldName]: value }));
      setTouched((prev) => ({ ...prev, [fieldName]: true }));
      clearFieldTimeout(fieldName);
    },
    [clearFieldTimeout],
  );

  /**
   * Programmatically set field error
   */
  const setFieldError = useCallback((fieldName, error) => {
    setErrors((prev) => ({ ...prev, [fieldName]: error }));
  }, []);

  /**
   * Reset form to initial state
   */
  const resetForm = useCallback(() => {
    setValues(initialState);
    setErrors({});
    setTouched({});
    setValidationState({});
    setIsFormValid(false);

    // Clear all pending timeouts
    Object.keys(timeoutRefs.current).forEach((fieldName) => {
      clearFieldTimeout(fieldName);
    });
  }, [initialState, clearFieldTimeout]);

  /**
   * Handle form submission
   */
  const handleSubmit = useCallback(
    (onSubmit) => async (e) => {
      e.preventDefault();
      setIsSubmitting(true);

      try {
        const isValid = await validateAll();
        if (isValid && isMountedRef.current) {
          await onSubmit(values);
        }
      } finally {
        if (isMountedRef.current) {
          setIsSubmitting(false);
        }
      }
    },
    [validateAll, values],
  );

  /**
   * Update form validity whenever errors change
   */
  useEffect(() => {
    const hasErrors = Object.values(errors).some((error) => error !== null);
    const hasAsyncValidating = Object.values(validationState).some(
      (state) => state === "validating",
    );
    const fieldNames = Object.keys(validationRules);
    const allFieldsTouched = fieldNames.every(
      (key) => touched[key] || values[key] !== "",
    );

    setIsFormValid(
      fieldNames.length > 0 && !hasErrors && !hasAsyncValidating && allFieldsTouched,
    );
  }, [errors, touched, values, validationRules, validationState]);

  /**
   * Cleanup on unmount
   */
  useEffect(() => {
    isMountedRef.current = true;
    const currentTimeouts = timeoutRefs.current;
    return () => {
      isMountedRef.current = false;
      Object.keys(currentTimeouts).forEach((fieldName) => {
        clearTimeout(currentTimeouts[fieldName]);
      });
    };
  }, [clearFieldTimeout]);

  return {
    // Form state
    values,
    errors,
    touched,
    validationState,
    isFormValid,
    isSubmitting,

    // Handlers
    handleChange,
    handleBlur,
    handleSubmit,

    // Methods
    validateField,
    validateAll,
    resetForm,
    setFieldValue,
    setFieldError,

    // Utilities
    clearFieldTimeout,
  };
};

export default useFormValidation;

import { useState, useCallback, useRef, useEffect } from "react";
import { apiUtils, API_ENDPOINTS } from "../config/api";
import { useAuth } from "../context/AuthContext";
import usePageVisibility from "./usePageVisibility";
import seedNotifications from "../data/mockNotifications.json";
import { safeJsonParse } from "../utils/safeJsonParse";
import { getNotificationMessage } from "../utils/notificationPreferences";

const POLLING_INTERVAL_MS = 60_000;
const MAX_SEEN_IDS = 500;
const STORAGE_KEY = "eventra_notification_inbox";

const normalize = (n = {}) => ({
  ...n,
  id: n.id || n._id || `${n.timestamp || n.createdAt || Date.now()}-${getNotificationMessage(n)}`,
  timestamp: n.timestamp || n.createdAt || n.updatedAt || new Date().toISOString(),
});

const persist = (items) => {
  try { window.localStorage.setItem(STORAGE_KEY, JSON.stringify(items)); } catch {}
};

const loadPersisted = () => {
  try {
    const raw = window.localStorage.getItem(STORAGE_KEY);
    if (!raw) return null;
    const parsed = safeJsonParse(raw, []);
    return Array.isArray(parsed) ? parsed.map(normalize) : null;
  } catch { return null; }
};

export function useNotificationPoller(deliverNew, hasCompletedInitialFetchRef) {
  const { token } = useAuth();
  const isPageVisible = usePageVisibility();
  const [notifications, setNotifications] = useState([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const seenIds = useRef(new Set());
  const isMounted = useRef(true);
  const tokenRef = useRef(token);
  const isPageVisibleRef = useRef(isPageVisible);

  useEffect(() => { isMounted.current = true; return () => { isMounted.current = false; }; }, []);
  useEffect(() => { tokenRef.current = token; }, [token]);
  useEffect(() => { isPageVisibleRef.current = isPageVisible; }, [isPageVisible]);

  const addSeenId = (id) => {
    if (seenIds.current.has(id)) return;
    if (seenIds.current.size >= MAX_SEEN_IDS) {
      const oldest = seenIds.current.values().next().value;
      seenIds.current.delete(oldest);
    }
    seenIds.current.add(id);
  };

  const applyList = useCallback(
    (list, { deliverNew: shouldDeliver = false } = {}) => {
      const normalized = list.map(normalize);
      const incomingUnread = normalized.filter((n) => {
        const isNew = !seenIds.current.has(n.id);
        return isNew && !n.isRead;
      });
      normalized.forEach((n) => addSeenId(n.id));
      setNotifications(normalized);
      setUnreadCount(normalized.filter((n) => !n.isRead).length);
      persist(normalized);
      if (shouldDeliver && hasCompletedInitialFetchRef.current && incomingUnread.length > 0) {
        deliverNew(incomingUnread);
      }
      hasCompletedInitialFetchRef.current = true;
    },
    [deliverNew, hasCompletedInitialFetchRef],
  );

  const fetchNotifications = useCallback(
    async (options = {}) => {
      if (!token) return;
      const t = token;
      const endpoint = API_ENDPOINTS?.NOTIFICATIONS?.ALL || API_ENDPOINTS?.NOTIFICATIONS?.BASE;
      if (!endpoint) return;
      try {
        if (!options.isBackground && isMounted.current && tokenRef.current === t) setLoading(true);
        const res = await apiUtils.get(endpoint);
        if (!isMounted.current || tokenRef.current !== t) return;
        const data = res.data;
        applyList(Array.isArray(data) ? data : data?.content || [], { deliverNew: true });
      } catch (err) {
        if (isMounted.current && tokenRef.current === t) {
          const persisted = loadPersisted();
          const fallback = persisted?.length ? persisted : seedNotifications.map(normalize);
          applyList(fallback, { deliverNew: false });
        }
      } finally {
        if (!options.isBackground && isMounted.current && tokenRef.current === t) setLoading(false);
      }
    },
    [token, applyList],
  );

  const refetchRef = useRef(fetchNotifications);
  useEffect(() => { refetchRef.current = fetchNotifications; }, [fetchNotifications]);

  useEffect(() => {
    if (!token) {
      setNotifications([]);
      setUnreadCount(0);
      seenIds.current = new Set();
      hasCompletedInitialFetchRef.current = false;
      return;
    }
    const t = token;
    if (isMounted.current && tokenRef.current === t) setLoading(true);
    fetchNotifications({ isBackground: true }).then(() => {
      if (isMounted.current && tokenRef.current === t) setLoading(false);
    });
    const interval = setInterval(() => {
      if (isMounted.current && tokenRef.current === t && isPageVisibleRef.current) {
        refetchRef.current({ isBackground: true });
      }
    }, POLLING_INTERVAL_MS);
    return () => clearInterval(interval);
  }, [token, fetchNotifications, hasCompletedInitialFetchRef]);

  useEffect(() => {
    if (!isPageVisible || !token) return;
    if (!hasCompletedInitialFetchRef.current) return;
    refetchRef.current({ isBackground: true });
  }, [isPageVisible, token, hasCompletedInitialFetchRef]);

  const markAsRead = useCallback(
    async (id) => {
      if (!token || !id) return;
      const t = token;
      const fn = API_ENDPOINTS?.NOTIFICATIONS?.READ;
      if (typeof fn !== "function") return;
      const endpoint = fn(id);
      if (!endpoint) return;
      try {
        await apiUtils.put(endpoint, {});
        if (!isMounted.current || tokenRef.current !== t) return;
        setNotifications((prev) => {
          const updated = prev.map((n) => (n.id === id ? { ...n, isRead: true } : n));
          persist(updated);
          return updated;
        });
        setUnreadCount((p) => Math.max(0, p - 1));
      } catch (err) {
        if (isMounted.current && tokenRef.current === t) console.error("[useNotificationPoller] markAsRead:", err);
      }
    },
    [token],
  );

  const markAllAsRead = useCallback(async () => {
    if (!token) return;
    const t = token;
    let hasUnread = false;
    setNotifications((prev) => {
      hasUnread = prev.some((n) => !n.isRead);
      if (!hasUnread) return prev;
      const updated = prev.map((n) => ({ ...n, isRead: true }));
      persist(updated);
      return updated;
    });
    if (!hasUnread) return;
    const endpoint = API_ENDPOINTS?.NOTIFICATIONS?.READ_ALL;
    if (!endpoint) return;
    setUnreadCount(0);
    try {
      await apiUtils.put(endpoint, {});
    } catch (err) {
      if (isMounted.current && tokenRef.current === t) {
        console.error("[useNotificationPoller] markAllAsRead:", err);
        refetchRef.current({ isBackground: true });
      }
    }
  }, [token]);

  const deleteNotification = useCallback(
    async (id) => {
      if (!id) return;
      const t = token;
      let removedWasUnread = false;
      setNotifications((prev) => {
        const target = prev.find((n) => n.id === id);
        removedWasUnread = target ? !target.isRead : false;
        const updated = prev.filter((n) => n.id !== id);
        persist(updated);
        return updated;
      });
      if (removedWasUnread) setUnreadCount((p) => Math.max(0, p - 1));
      const fn = API_ENDPOINTS?.NOTIFICATIONS?.DELETE;
      if (!token || typeof fn !== "function") return;
      const endpoint = fn(id);
      if (!endpoint) return;
      try { await apiUtils.delete(endpoint); }
      catch (err) {
        if (isMounted.current && tokenRef.current === t) {
          console.error("[useNotificationPoller] delete:", err);
          refetchRef.current({ isBackground: true });
        }
      }
    },
    [token],
  );

  const markAsReadRef = useRef(markAsRead);
  useEffect(() => { markAsReadRef.current = markAsRead; }, [markAsRead]);

  return {
    notifications, unreadCount, loading,
    fetchNotifications, markAsRead, markAllAsRead, deleteNotification,
    applyList, seenIds, markAsReadRef,
  };
}

/**
 * @fileoverview useRoutePrefetch - Route prefetching hook based on current location
 * @module hooks/useRoutePrefetch
 */
import { useEffect, useCallback } from "react";
import { useLocation } from "react-router-dom";
import { prefetchRoute } from "../utils/prefetchUtils";

/**
 * useRoutePrefetch Hook
 *
 * Automatically pre-fetches high-priority routes based on the current location.
 * For example, if the user is on the Home page, we might pre-fetch the Explore page.
 * A custom React hook that automatically prefetches high-priority
 * routes based on the current page location.
 *
 * Uses requestIdleCallback to avoid blocking the main thread.
 * Falls back to setTimeout on browsers that don't support it.
 * Exposes prefetchManual for on-demand prefetching.
 *
 * @param {Object} [config={}] - Optional configuration object
 * @returns {{ prefetchManual: Function }} Manual prefetch trigger
 *
 * @example
 * const { prefetchManual } = useRoutePrefetch();
 * prefetchManual(() => import('../Pages/Events/EventDetails'), 'details');
 */

export const useRoutePrefetch = (config = {}) => {
  const location = useLocation();

  const prefetch = useCallback((importFn, key) => {
    // Wrap in requestIdleCallback to not block the main thread
    if ("requestIdleCallback" in window) {
      window.requestIdleCallback(() => prefetchRoute(importFn, key));
    } else {
      setTimeout(() => prefetchRoute(importFn, key), 2000);
    }
  }, []);

  useEffect(() => {
    const path = location.pathname;

    // Define prefetch strategies based on current path
    if (path === "/") {
      // On home, prefetch major entry points
      prefetch(() => import("../Pages/Events/EventsPage"), "explore");
      prefetch(() => import("../components/auth/Login"), "login");
    } else if (path === "/explore" || path === "/events") {
      // On explore, prefetch event details and registration
      prefetch(() => import("../Pages/Events/EventDetails"), "details");
      prefetch(
        () => import("../Pages/Events/EventRegistration"),
        "registration"
      );
    }
  }, [location.pathname, prefetch]);

  return { prefetchManual: prefetch };
};

