/**
 * src/utils/p2pFileTransfer.js
 *
 * A high-fidelity WebRTC Peer-to-Peer (P2P) mesh transfer coordinator.
 * Features:
 *  1. Dynamic chunk-based file caching inside browser IndexedDB.
 *  2. Real WebRTC DataChannel connection establishing over a BroadcastChannel signaling layer.
 *  3. Cross-tab real-time mesh transfer coordination with zero external signaling servers.
 *  4. High-fidelity server download simulation with chunk caching.
 */

// --- IndexedDB Cache Configuration ---
import { logger } from "./logger.js";
const DB_NAME = "eventra_p2p_cache";
const DB_VERSION = 2;
const STORE_NAME = "file_chunks";

let dbInstance = null;

// Initialize IndexedDB
const getDB = () => {
  if (dbInstance) return Promise.resolve(dbInstance);
  if (typeof indexedDB === "undefined") {
    return Promise.reject(new Error("IndexedDB is not available in this environment"));
  }
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);
    request.onupgradeneeded = (e) => {
      const db = e.target.result;
      let store;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        store = db.createObjectStore(STORE_NAME, { keyPath: "chunkId" });
      } else {
        store = e.target.transaction.objectStore(STORE_NAME);
      }
      if (!store.indexNames.contains("fileId")) {
        store.createIndex("fileId", "fileId", { unique: false });
      }
    };
    request.onsuccess = (e) => {
      dbInstance = e.target.result;
      resolve(dbInstance);
    };
    request.onerror = (e) => {
      logger.error("IndexedDB initialization error:", e);
      reject(e);
    };
  });
};

// Helper to attach error/abort handlers to an IndexedDB transaction and request
const attachIdbReadHandlers = (transaction, request, resolve, fallbackValue, functionName) => {
  transaction.onerror = (err) => {
    logger.error(`${functionName} transaction error:`, err);
    resolve(fallbackValue);
  };
  transaction.onabort = (err) => {
    logger.error(`${functionName} transaction aborted:`, err);
    resolve(fallbackValue);
  };
  request.onerror = (err) => {
    logger.error(`${functionName} request error:`, err);
    resolve(fallbackValue);
  };
};

// Check if all chunks for a file exist in IndexedDB
export async function isFileCached(fileId) {
  try {
    const db = await getDB();
    return new Promise((resolve) => {
      const transaction = db.transaction(STORE_NAME, "readonly");
      const store = transaction.objectStore(STORE_NAME);
      const index = store.index("fileId");

      const countRequest = index.count(IDBKeyRange.only(fileId));
      const getRequest = index.get(IDBKeyRange.only(fileId));

      let count = 0;
      let firstChunk = null;
      let completedCount = 0;

      const checkCompletion = () => {
        completedCount++;
        if (completedCount === 2) {
          if (firstChunk && count > 0 && count === firstChunk.totalChunks) {
            resolve(true);
          } else {
            resolve(false);
          }
        }
      };

      transaction.onerror = (err) => {
        logger.error("isFileCached transaction error:", err);
        resolve(false);
      };
      transaction.onabort = (err) => {
        logger.error("isFileCached transaction aborted:", err);
        resolve(false);
      };

      countRequest.onsuccess = (e) => {
        count = e.target.result;
        checkCompletion();
      };
      countRequest.onerror = (err) => {
        logger.error("isFileCached count request error:", err);
        resolve(false);
      };

      getRequest.onsuccess = (e) => {
        firstChunk = e.target.result;
        checkCompletion();
      };
      getRequest.onerror = (err) => {
        logger.error("isFileCached get request error:", err);
        resolve(false);
      };
    });
  } catch (error) {
    logger.error("Failed checking file cache:", error);
    return false;
  }
}

// Retrieve cached file chunks
export async function getCachedFile(fileId) {
  try {
    const db = await getDB();
    return new Promise((resolve) => {
      const transaction = db.transaction(STORE_NAME, "readonly");
      const store = transaction.objectStore(STORE_NAME);
      const index = store.index("fileId");

      const request = index.getAll(IDBKeyRange.only(fileId));

      transaction.onerror = (err) => {
        logger.error("getCachedFile transaction error:", err);
        resolve(null);
      };
      transaction.onabort = (err) => {
        logger.error("getCachedFile transaction aborted:", err);
        resolve(null);
      };
      request.onerror = (err) => {
        logger.error("getCachedFile request error:", err);
        resolve(null);
      };

      request.onsuccess = (e) => {
        const chunks = e.target.result || [];
        if (chunks.length > 0) {
          // Sort chunks by index
          chunks.sort((a, b) => a.chunkIndex - b.chunkIndex);
          resolve(chunks);
        } else {
          resolve(null);
        }
      };
    });
  } catch (error) {
    logger.error("Failed retrieving cached file chunks:", error);
    return null;
  }
}

// Save a chunk to IndexedDB
export async function saveChunkToCache(fileId, fileName, chunkIndex, totalChunks, dataStr) {
  try {
    const db = await getDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORE_NAME, "readwrite");
      const store = transaction.objectStore(STORE_NAME);
      const chunkId = `${fileId}_${chunkIndex}`;

      const record = {
        chunkId,
        fileId,
        fileName,
        chunkIndex,
        totalChunks,
        data: dataStr,
        timestamp: Date.now()
      };

      const request = store.put(record);
      request.onsuccess = () => resolve(true);
      request.onerror = (e) => reject(e);
    });
  } catch (error) {
    logger.error("Failed saving chunk:", error);
    return false;
  }
}

// Mock large file generation and split into chunks to populate cache initially
export async function simulateServerDownload(fileId, fileName, onProgress) {
  // Simulate server latency
  const steps = 10;
  const totalChunks = 5;
  const dummyChunkData = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";

  for (let i = 1; i <= steps; i++) {
    await new Promise(r => setTimeout(r, 250)); // Simulating transfer speed
    if (onProgress) onProgress(Math.round((i / steps) * 100));
  }

  // Once fully downloaded from "server", split and write to IndexedDB cache
  for (let c = 0; c < totalChunks; c++) {
    const chunkStr = Array(1000).fill(dummyChunkData).join("") + `[CHUNK_${c}]`;
    await saveChunkToCache(fileId, fileName, c, totalChunks, chunkStr);
  }

  return true;
}

// Generate unique identifier for signaling peers
const peerId = `peer_${Math.random().toString(36).substring(2, 7)}`;
let signalingChannel = null;

const isBrowser = typeof window !== "undefined";
const webrtcAvailable = isBrowser &&
  typeof RTCPeerConnection !== "undefined" &&
  typeof RTCSessionDescription !== "undefined" &&
  typeof RTCIceCandidate !== "undefined";

// Establish P2P Broadcast Channel for multi-tab signaling
const getSignalingChannel = () => {
  if (!signalingChannel && isBrowser) {
    signalingChannel = new BroadcastChannel("eventra_p2p_mesh");
  }
  return signalingChannel;
};

/**
 * Peer-to-Peer file coordinator utilizing real WebRTC DataChannel
 * and RTCPeerConnection established dynamically between browser tabs.
 */
export class P2PFileTransferCoordinator {
  constructor(fileId, fileName, onStateChange, expectedTotalChunks = null) {
    this.fileId = fileId;
    this.fileName = fileName;
    this.onStateChange = onStateChange;
    this.expectedTotalChunks = expectedTotalChunks;
    this.pc = null;
    this.channel = null;
    this.receivedChunks = [];
    this.bc = getSignalingChannel();
    this.isInitiator = false;
    this.onMessageListener = null;
    this.currentState = null;
    this.queuedRemoteCandidates = [];
  }

  updateState(state, progress = 0, speed = "-", peer = null, count = 1) {
    this.currentState = state;
    if (this.onStateChange) {
      this.onStateChange({
        state, // 'searching', 'connecting', 'transferring', 'completed', 'failed'
        progress,
        speed,
        peer,
        count
      });
    }
  }

  // Set up listeners for the Signaling Channel (BroadcastChannel)
  setupSignaling() {
    this.onMessageListener = async (e) => {
      const msg = e.data;
      if (msg.fileId !== this.fileId) return;

      // Avoid listening to own broadcasts
      if (msg.from === peerId) return;

      switch (msg.type) {
        case "P2P_QUERY":
          // Another peer is looking for a file. Do we have it cached?
          const cached = await isFileCached(this.fileId);
          if (cached) {
            this.bc.postMessage({
              type: "P2P_AVAILABLE",
              fileId: this.fileId,
              from: peerId,
              to: msg.from
            });
          }
          break;

        case "P2P_AVAILABLE":
          // Found a peer who has the file! Connect.
          if (msg.to === peerId && !this.pc) {
            this.connectToPeer(msg.from);
          }
          break;

        case "P2P_OFFER":
          // Received connection offer from initiator peer
          if (msg.to === peerId) {
            await this.handleOffer(msg.offer, msg.from);
          }
          break;

        case "P2P_ANSWER":
          // Received connection answer
          if (msg.to === peerId) {
            await this.handleAnswer(msg.answer);
          }
          break;

        case "P2P_ICE":
          // Received ICE candidate
          if (msg.to === peerId && this.pc) {
            try {
              await this.pc.addIceCandidate(new RTCIceCandidate(msg.candidate));
            } catch (err) {
              logger.error("Error adding ICE candidate:", err);
            }
          }
          break;

        default:
          break;
      }
    };

    if (this.bc) {
      this.bc.addEventListener("message", this.onMessageListener);
    }
  }

  // Initiate search for peers holding the file
  async startP2PSearch() {
    this.setupSignaling();
    this.updateState("searching", 0, "-", null, 0);

    if (!webrtcAvailable) {
      this.updateState("failed");
      return false;
    }

    // Broadcast file request to other tabs
    this.bc.postMessage({
      type: "P2P_QUERY",
      fileId: this.fileId,
      from: peerId
    });

    // We wait 2.5 seconds to discover nearby peers. If none answer, we fail and trigger fallback.
    return new Promise((resolve) => {
      const searchTimeout = setTimeout(() => {
        if (!this.pc || this.currentState === "searching") {
          this.cleanup();
          resolve(false); // No peers found, trigger server fallback
        }
      }, 2500);

      let checkInterval;

      // Add a secondary connection safety timer of 5 seconds total
      const connectionSafetyTimeout = setTimeout(() => {
        if (this.currentState === "connecting" || this.currentState === "searching") {
          this.cleanup();
          clearInterval(checkInterval);
          resolve(false); // WebRTC connection handshakes timed out, fallback to server
        } else if (this.currentState === "completed" || this.currentState === "transferring") {
          clearInterval(checkInterval);
          resolve(true);
        }
      }, 5000);

      // Attach state listener check to resolve immediately if completed
      checkInterval = setInterval(() => {
        if (this.currentState === "completed") {
          clearTimeout(searchTimeout);
          clearTimeout(connectionSafetyTimeout);
          clearInterval(checkInterval);
          resolve(true);
        } else if (this.currentState === "failed") {
          clearTimeout(searchTimeout);
          clearTimeout(connectionSafetyTimeout);
          clearInterval(checkInterval);
          resolve(false);
        }
      }, 200);
    });
  }

  // Initiator builds connection offer to target peer
  async connectToPeer(targetPeerId) {
    if (!webrtcAvailable) {
      this.updateState("failed");
      return;
    }
    this.isInitiator = true;
    this.updateState("connecting", 0, "-", targetPeerId, 1);

    this.pc = new RTCPeerConnection();
    this.queuedRemoteCandidates = [];

    // Create data channel
    this.channel = this.pc.createDataChannel("file-transfer");
    this.setupDataChannel();

    this.pc.onicecandidate = (e) => {
      if (e.candidate) {
        this.bc.postMessage({
          type: "P2P_ICE",
          fileId: this.fileId,
          from: peerId,
          to: targetPeerId,
          candidate: e.candidate
        });
      }
    };

    const offer = await this.pc.createOffer();
    await this.pc.setLocalDescription(offer);

    this.bc.postMessage({
      type: "P2P_OFFER",
      fileId: this.fileId,
      from: peerId,
      to: targetPeerId,
      offer: offer
    });
  }

  // Target peer receives connection offer and replies with answer
  async handleOffer(offer, senderId) {
    if (!webrtcAvailable) {
      this.updateState("failed");
      return;
    }
    this.isInitiator = false;
    this.updateState("connecting", 0, "-", senderId, 1);

    this.pc = new RTCPeerConnection();
    this.queuedRemoteCandidates = [];

    this.pc.ondatachannel = (e) => {
      this.channel = e.channel;
      this.setupDataChannel();
    };

    this.pc.onicecandidate = (e) => {
      if (e.candidate) {
        this.bc.postMessage({
          type: "P2P_ICE",
          fileId: this.fileId,
          from: peerId,
          to: senderId,
          candidate: e.candidate
        });
      }
    };

    await this.pc.setRemoteDescription(new RTCSessionDescription(offer));
    await this.processQueuedCandidates();
    const answer = await this.pc.createAnswer();
    await this.pc.setLocalDescription(answer);

    this.bc.postMessage({
      type: "P2P_ANSWER",
      fileId: this.fileId,
      from: peerId,
      to: senderId,
      answer: answer
    });
  }

  // Initiator sets target's answer description
  async handleAnswer(answer) {
    if (this.pc) {
      await this.pc.setRemoteDescription(new RTCSessionDescription(answer));
      await this.processQueuedCandidates();
    }
  }

  // Process any ICE candidates that were queued before the remote description was applied
  async processQueuedCandidates() {
    if (!this.pc || !this.pc.remoteDescription) return;
    while (this.queuedRemoteCandidates.length > 0) {
      const candidate = this.queuedRemoteCandidates.shift();
      try {
        await this.pc.addIceCandidate(new RTCIceCandidate(candidate));
      } catch (err) {
        console.error("Error adding queued ICE candidate:", err);
      }
    }
  }

  async sendChunks(fileChunks) {
    const total = fileChunks.length;
    const channel = this.channel;
    if (!channel) return;

    // Monitor bufferedAmount and pause sending when the buffer is congested
    channel.bufferedAmountLowThreshold = 65536; // 64 KB

    for (let index = 0; index < total; index++) {
      if (channel.readyState !== "open") {
        break;
      }

      // Check if browser DataChannel buffer is congested
      if (channel.bufferedAmount > channel.bufferedAmountLowThreshold) {
        // Await the drain event asynchronously without blocking the main thread or creating runaway timers
        await new Promise((resolve) => {
          channel.onbufferedamountlow = () => {
            channel.onbufferedamountlow = null;
            resolve();
          };
        });
      }

      if (channel.readyState !== "open") {
        break;
      }

      const chunk = fileChunks[index];
      channel.send(JSON.stringify({
        chunkIndex: chunk.chunkIndex,
        totalChunks: total,
        data: chunk.data
      }));
    }
  }

  // Setup WebRTC DataChannel handlers for transferring chunks
  setupDataChannel() {
    if (!this.channel) return;

    this.channel.onopen = async () => {
      this.updateState("transferring", 0, "15.4 MB/s");

      // If we already have the file cached, we act as the sender!
      if (!this.isInitiator) {
        const fileChunks = await getCachedFile(this.fileId);
        if (fileChunks) {
          this.sendChunks(fileChunks);
        }
      }
    };
this.channel.onmessage = async (e) => {
  let chunkMsg;
  try {
    chunkMsg = JSON.parse(e.data);
  } catch (err) {
    logger.error("Failed to parse incoming P2P message:", err);
    return;
  }

  // ── SECURITY FIX: Validate totalChunks against trusted server value ──
  // If expectedTotalChunks was set from a trusted source, reject any
  // peer message that claims a different totalChunks value.
  if (this.expectedTotalChunks !== null) {
    if (
      typeof chunkMsg.totalChunks !== "number" ||
      chunkMsg.totalChunks !== this.expectedTotalChunks
    ) {
      logger.error(
        `[P2P Security] Chunk count mismatch! Expected ${this.expectedTotalChunks}, ` +
        `peer claims ${chunkMsg.totalChunks}. Dropping chunk and aborting transfer.`
      );
      this.updateState("failed");
      this.cleanup();
      return;
    }
  }

  // Validate chunkIndex is within expected bounds
  const maxChunks = this.expectedTotalChunks ?? chunkMsg.totalChunks;
  if (
    typeof chunkMsg.chunkIndex !== "number" ||
    chunkMsg.chunkIndex < 0 ||
    chunkMsg.chunkIndex >= maxChunks
  ) {
    logger.error(
      `[P2P Security] Invalid chunkIndex ${chunkMsg.chunkIndex} for totalChunks ${maxChunks}. Dropping.`
    );
    return;
  }

  // Reject duplicate chunk indices
  const alreadyReceived = this.receivedChunks.some(
    (c) => c.chunkIndex === chunkMsg.chunkIndex
  );
  if (alreadyReceived) {
    logger.warn(`[P2P Security] Duplicate chunk ${chunkMsg.chunkIndex} received. Dropping.`);
    return;
  }

  this.receivedChunks.push(chunkMsg);

  const progress = Math.round((this.receivedChunks.length / maxChunks) * 100);
  this.updateState("transferring", progress, "18.2 MB/s");

  // Once all chunks are transferred successfully
  if (this.receivedChunks.length === maxChunks) {
    this.receivedChunks.sort((a, b) => a.chunkIndex - b.chunkIndex);

    // Cache chunks to IndexedDB so this tab can now seed the file
    for (const c of this.receivedChunks) {
      await saveChunkToCache(
        this.fileId,
        this.fileName,
        c.chunkIndex,
        maxChunks,
        c.data
      );
    }

    this.updateState("completed", 100, "Finished");
    this.cleanup();
  }
};

    this.channel.onerror = (err) => {
      logger.error("DataChannel error:", err);
      this.updateState("failed");
      this.cleanup();
    };

    this.channel.onclose = () => {
      if (this.currentState !== "completed") {
        this.updateState("failed");
      }
      this.cleanup();
    };
  }

  // Cleanup connections and event listeners
  cleanup() {
    if (this.bc && this.onMessageListener) {
      this.bc.removeEventListener("message", this.onMessageListener);
    }
    if (this.channel) {
      this.channel.close();
      this.channel = null;
    }
    if (this.pc) {
      this.pc.close();
      this.pc = null;
    }
  }
}

const MAX_SCORE = 100;

const normalizeText = (value) =>
  String(value || "")
    .toLowerCase()
    .replace(/&/g, "and")
    .replace(/[^a-z0-9]+/g, " ")
    .trim();

const toTokens = (value) =>
  normalizeText(value).split(/\s+/).filter(Boolean);

const normalizeList = (value) => {
  if (!value) return [];
  return (Array.isArray(value) ? value : [value])
    .flatMap((item) => toTokens(item).length ? [normalizeText(item)] : [])
    .filter(Boolean);
};

const unique = (items) => Array.from(new Set(items.filter(Boolean)));

const getEventId = (event) => String(event?.id ?? event?.eventId ?? event?.title ?? "");

const unwrapEvent = (entry) => entry?.event || entry?.eventSummary || entry || {};

const getEventCategory = (event) => normalizeText(event?.category || event?.type);

const getEventType = (event) => normalizeText(event?.type);

const getEventTags = (event) =>
  unique([
    ...normalizeList(event?.tags),
    ...normalizeList(event?.techStack),
    ...toTokens(event?.title),
    ...toTokens(event?.description),
  ]);

const getLocationParts = (location) =>
  normalizeText(location)
    .split(/\s+/)
    .filter((part) => part.length > 1 && part !== "online");

const createLocationMatcher = (preferredLocation) => {
  const parts = getLocationParts(preferredLocation);
  if (parts.length === 0) return () => false;
  return (eventLocation) =>
    eventLocation && parts.some((part) => eventLocation.includes(part));
};

const buildLocationIndex = (preferredLocation) => {
  const parts = getLocationParts(preferredLocation);
  if (parts.length === 0) return null;
  return { parts, test: (loc) => parts.some((part) => loc.includes(part)) };
};

const getPopularityScore = (event) => {
  const attendees = Number(event?.attendees) || 0;
  const capacity = Number(event?.maxAttendees) || 0;

  if (capacity <= 0) return Math.min(attendees / 10, 10);
  return Math.min((attendees / capacity) * 10, 10);
};

const _tagCache = new Map();
const _cacheOrder = [];
const MAX_CACHE_SIZE = 100;

const _getCachedTags = (event) => {
  const id = getEventId(event);
  if (!id) return [];
  if (_tagCache.has(id)) {
    const tags = _tagCache.get(id);
    const idx = _cacheOrder.indexOf(id);
    if (idx > -1) _cacheOrder.splice(idx, 1);
    _cacheOrder.push(id);
    return tags;
  }
  if (_cacheOrder.length >= MAX_CACHE_SIZE) {
    const oldest = _cacheOrder.shift();
    _tagCache.delete(oldest);
  }
  const tags = getEventTags(event);
  _tagCache.set(id, tags);
  _cacheOrder.push(id);
  return tags;
};

const getSimilarityScore = (candidate, interactedEvents) => {
  if (!interactedEvents.length) return 0;

  const candidateCategory = getEventCategory(candidate);
  const candidateType = getEventType(candidate);
  const candidateTags = new Set(getEventTags(candidate));

  const best = interactedEvents.reduce((bestScore, entry) => {
    const event = unwrapEvent(entry);
    let score = 0;

    if (candidateCategory && candidateCategory === getEventCategory(event)) {
      score += 12;
    }

    if (candidateType && candidateType === getEventType(event)) {
      score += 5;
    }

    const overlap = _getCachedTags(event).filter((tag) => candidateTags.has(tag));
    score += Math.min(overlap.length * 3, 12);

    return Math.max(bestScore, score);
  }, 0);

  return Math.min(best, 25);
};

export const buildInteractionProfile = ({
  registeredEvents = [],
  bookmarkedEvents = [],
  viewedEvents = [],
  location = "",
} = {}) => {
  const weightedEvents = [
    ...registeredEvents.map((entry) => ({ entry, weight: 4 })),
    ...bookmarkedEvents.map((entry) => ({ entry, weight: 3 })),
    ...viewedEvents.map((entry) => ({ entry, weight: 1 })),
  ];

  const categoryWeights = {};
  const typeWeights = {};
  const tagWeights = {};
  const locationCounts = {};
  const interactedIds = new Set();
  const registeredIds = new Set();

  weightedEvents.forEach(({ entry, weight }) => {
    const event = unwrapEvent(entry);
    const id = getEventId(event);
    const category = getEventCategory(event);
    const type = getEventType(event);
    const eventLocation = normalizeText(event.location);

    if (id) interactedIds.add(id);
    if (category) categoryWeights[category] = (categoryWeights[category] || 0) + weight;
    if (type) typeWeights[type] = (typeWeights[type] || 0) + weight;
    if (eventLocation && eventLocation !== "online") {
      locationCounts[eventLocation] = (locationCounts[eventLocation] || 0) + weight;
    }

    getEventTags(event).forEach((tag) => {
      tagWeights[tag] = (tagWeights[tag] || 0) + weight;
    });
  });

  registeredEvents.forEach((entry) => {
    const id = getEventId(unwrapEvent(entry));
    if (id) registeredIds.add(id);
  });

  const topLocation =
    location ||
    Object.entries(locationCounts).sort((a, b) => b[1] - a[1])[0]?.[0] ||
    "";

  return {
    categories: categoryWeights,
    types: typeWeights,
    tags: tagWeights,
    interactedEvents: weightedEvents.map(({ entry }) => unwrapEvent(entry)),
    interactedIds,
    registeredIds,
    location: topLocation,
  };
};

export const calculateRecommendationScore = (
  event,
  userProfile = {},
  interactions = {},
) => {
  if (!event || typeof event !== "object") {
    return { score: 0, reasons: [], breakdown: [] };
  }

  const interactionProfile = interactions.categories
    ? interactions
    : buildInteractionProfile(interactions);

  let score = 0;
  const reasons = [];
  const breakdown = [];

  const addScore = (label, points, reason) => {
    if (points <= 0) return;
    score += points;
    breakdown.push({ label, score: Math.round(points) });
    if (reason) reasons.push(reason);
  };

  const category = getEventCategory(event);
  const type = getEventType(event);
  const eventTags = getEventTags(event);
  const profileInterests = normalizeList(userProfile.interests);
  const profileTypes = normalizeList(userProfile.eventTypes);
  const profileTech = normalizeList(userProfile.techStack);
  const profileLevel = normalizeText(userProfile.level);
  const eventLevel = normalizeText(event.level);

  if (profileInterests.includes(category)) {
    addScore("Profile interest match", 18, "Matches your saved interests");
  }

  if (profileTypes.includes(type)) {
    addScore("Preferred event type", 10, "Fits your preferred event format");
  }

  const profileTechSet = new Set(profileTech);
  const techOverlap = eventTags.filter((tag) => profileTechSet.has(tag));
  addScore(
    "Tech stack overlap",
    Math.min(techOverlap.length * 5, 12),
    "Relevant to your tech stack",
  );

  if (profileLevel && eventLevel && profileLevel === eventLevel) {
    addScore("Experience level fit", 6, "Matches your experience level");
  }

  const categoryAffinity = interactionProfile.categories?.[category] || 0;
  addScore(
    "Category affinity",
    Math.min(categoryAffinity * 4, 18),
    "Similar to categories you engage with",
  );

  const typeAffinity = interactionProfile.types?.[type] || 0;
  addScore(
    "Format affinity",
    Math.min(typeAffinity * 2, 8),
    "Similar to event formats you prefer",
  );

  const tagAffinity = eventTags.reduce(
    (sum, tag) => sum + (interactionProfile.tags?.[tag] || 0),
    0,
  );
  addScore(
    "Interaction tag overlap",
    Math.min(tagAffinity * 1.5, 12),
    "Shares topics with your bookmarks and views",
  );

  addScore(
    "Collaborative item similarity",
    getSimilarityScore(event, interactionProfile.interactedEvents || []),
    "Similar to events in your activity history",
  );

  const matchesArea = createLocationMatcher(interactionProfile.location);
  const localTrending = matchesArea(normalizeText(event?.location));
  if (localTrending) {
    addScore("Trending near you", Math.min(getPopularityScore(event) + 6, 15), "Popular in your area");
  } else if (event.trending || getPopularityScore(event) >= 8) {
    addScore("Platform trending", Math.min(getPopularityScore(event), 10), "Trending among Eventra users");
  }

  const cappedScore = Math.min(Math.round(score), MAX_SCORE);

  return {
    score: cappedScore,
    reasons: unique(reasons).slice(0, 5),
    breakdown,
  };
};

export const getTrendingEventsForArea = (events = [], location = "", limit = 4) => {
  const matchesArea = createLocationMatcher(location);
  return [...events]
    .filter((event) => matchesArea(normalizeText(event?.location)) || event.eventMode === "online")
    .map((event) => ({
      ...event,
      trendingScore: Math.round(getPopularityScore(event) * 10),
    }))
    .sort((a, b) => b.trendingScore - a.trendingScore)
    .slice(0, limit);
};

export const buildPersonalizedRecommendations = ({
  events = [],
  userProfile = {},
  registeredEvents = [],
  bookmarkedEvents = [],
  viewedEvents = [],
  location = "",
  includeInteracted = false,
  limit = 8,
} = {}) => {
  const interactionProfile = buildInteractionProfile({
    registeredEvents,
    bookmarkedEvents,
    viewedEvents,
    location,
  });

  return events
    .reduce((acc, event) => {
      if (includeInteracted || !interactionProfile.registeredIds.has(getEventId(event))) {
        const result = calculateRecommendationScore(event, userProfile, interactionProfile);
        const scored = {
          ...event,
          calculatedMatch: result.score,
          recommendationScore: result.score,
          recommendationReasons: result.reasons,
          breakdown: result.breakdown,
        };
        if (scored.recommendationScore > 0) {
          acc.push(scored);
        }
      }
      return acc;
    }, [])
    .sort((a, b) => b.recommendationScore - a.recommendationScore)
    .slice(0, limit);
};

import { safeJsonParse } from "../utils/safeJsonParse";
const isBrowserStorageAvailable = (storage) => {
  if (!storage) return false;

  try {
    const testKey = "__eventra_storage_test__";
    storage.setItem(testKey, testKey);
    storage.removeItem(testKey);
    return true;
  } catch {
    return false;
  }
};

const createSafeStorage = (getStorage) => {
  const getStorageOrNull = () => {
    try {
      return getStorage();
    } catch {
      return null;
    }
  };

  return {
    get length() {
      try {
        return getStorageOrNull()?.length ?? 0;
      } catch {
        return 0;
      }
    },

    isAvailable() {
      return isBrowserStorageAvailable(getStorageOrNull());
    },

    getItem(key, fallback = null) {
      try {
        return getStorageOrNull()?.getItem(key) ?? fallback;
      } catch {
        return fallback;
      }
    },

    setItem(key, value) {
      try {
        getStorageOrNull()?.setItem(key, value);
        return true;
      } catch {
        return false;
      }
    },

    removeItem(key) {
      try {
        getStorageOrNull()?.removeItem(key);
        return true;
      } catch {
        return false;
      }
    },

    clear() {
      try {
        getStorageOrNull()?.clear();
        return true;
      } catch {
        return false;
      }
    },

    key(index) {
      try {
        return getStorageOrNull()?.key(index) ?? null;
      } catch {
        return null;
      }
    },

    getJson(key, fallback = null) {
      const raw = this.getItem(key);
      if (raw == null) return fallback;

      try {
        return safeJsonParse(raw, {});
      } catch (_) {
        // Stored values can be user-edited or corrupted; callers should keep running.
        return fallback;
      }
    },

    setJson(key, value) {
      try {
        return this.setItem(key, JSON.stringify(value));
      } catch {
        return false;
      }
    },
  };
};

export const safeLocalStorage = createSafeStorage(() =>
  typeof window !== "undefined" ? window.localStorage : null
);

export const safeSessionStorage = createSafeStorage(() =>
  typeof window !== "undefined" ? window.sessionStorage : null
);

export const isLocalStorageAvailable = () => safeLocalStorage.isAvailable();


/**
 * @file secureStorage.js
 * @module utils/secureStorage
 *
 * @description
 * AES-GCM encrypted localStorage wrapper built on the Web Crypto API.
 *
 * **Security model**
 * - The AES-256-GCM key is derived with PBKDF2 (100 000 iterations, SHA-256)
 *   from two random 256-bit values that are generated once per browser and
 *   persisted in localStorage. Neither value is derived from any public
 *   constant such as the origin URL.
 * - Each write uses a fresh random 12-byte IV, so identical values produce
 *   different ciphertext on every call (preventing pattern analysis).
 * - No plaintext is ever written to localStorage. In-flight values (between
 *   the `setItem` call and encryption completion) are held only in the
 *   `pendingWrites` in-memory Map.
 * - If the page is closed before encryption completes the data is not
 *   persisted — data loss is the intentional tradeoff versus silent plaintext
 *   exposure.
 * - If Web Crypto is unavailable (non-HTTPS context, very old browser) the
 *   module degrades gracefully to unencrypted localStorage and
 *   `isEncryptionActive()` returns `false`.
 *
 * **Migration**
 * Earlier versions of this module wrote a `key + ':plaintext'` fallback entry
 * to localStorage before async encryption completed. `cleanupPlaintextFallbacks`
 * runs automatically at module load to remove any such keys left on disk.
 */
// ---------------------------------------------------------------------------
// AES-GCM Encryption Engine (Web Crypto API)
// ---------------------------------------------------------------------------

/**
 * Centralized cryptographic configuration.
 * All magic numbers and algorithm parameters are defined here for easy
 * maintenance and future upgrades.
 *
 * @constant {Object}
 */
const CRYPTO_CONFIG = {
  VERSION: 1,
  ALGORITHM: 'AES-GCM',
  KEY_LENGTH: 256,
  IV_LENGTH: 12,
  PBKDF2_ITERATIONS: 100_000,
  PBKDF2_HASH: 'SHA-256',
  SECRET_BYTE_LENGTH: 32, // 256-bit
};

// Legacy constants for backward compatibility
const CRYPTO_ALGORITHM = CRYPTO_CONFIG.ALGORITHM;
const KEY_LENGTH = CRYPTO_CONFIG.KEY_LENGTH;
const IV_LENGTH = CRYPTO_CONFIG.IV_LENGTH;

const PBKDF2_ITERATIONS = CRYPTO_CONFIG.PBKDF2_ITERATIONS;

const isCryptoAvailable = () => {
  try {
    return (
      typeof window !== 'undefined' &&
      typeof crypto !== 'undefined' &&
      typeof crypto.subtle !== 'undefined' &&
      typeof crypto.getRandomValues === 'function' &&
      window.isSecureContext !== false
    );
  } catch {
    return false;
  }
};

const cryptoSupported = isCryptoAvailable();

// ---------------------------------------------------------------------------
// Per-browser random material — two independent 256-bit random values, each
// generated once on first use and persisted in localStorage.
//
// KEY MATERIAL (eventra:key-material) — used as the PBKDF2 "password".
//   The previous implementation used window.location.origin here, which is a
//   fully public value. Any attacker who knows the deployed origin (e.g.
//   https://eventra.sandeepvashishtha.in) could precompute PBKDF2 offline for
//   any salt they read from localStorage. Replacing the origin with a random
//   secret means an attacker needs to read this value from the browser's
//   localStorage before they can derive the key — raising the bar from
//   "anyone who knows the URL" to "anyone who can read this user's localStorage".
//
// SALT (eventra:key-salt) — used as the PBKDF2 salt.
//   Per PBKDF2 spec the salt prevents identical passwords from producing the
//   same key across different users/sessions. Keeping it random and per-browser
//   ensures two Eventra instances never share a key even if they somehow end up
//   with the same key-material value.
//
// Together: AES key = PBKDF2(password=random256, salt=random256, iter=100k)
//   An attacker who cannot read localStorage cannot derive the key regardless
//   of how much compute they have. An XSS attacker who CAN read localStorage
//   still faces 100k PBKDF2 iterations to reconstruct the key — this is the
//   best achievable protection for a purely client-side encryption scheme.
// ---------------------------------------------------------------------------

const MATERIAL_STORAGE_KEY = 'eventra:key-material';
const SALT_STORAGE_KEY = 'eventra:key-salt';
const KEY_METADATA_KEY = 'eventra:key-metadata';
const SECRET_BYTE_LENGTH = CRYPTO_CONFIG.SECRET_BYTE_LENGTH;

/** Generate or restore a random 256-bit secret from localStorage. */
const getOrCreateSecret = (storageKey) => {
  try {
    const stored = localStorage.getItem(storageKey);
    if (stored) {
      return Uint8Array.from(atob(stored), (c) => c.charCodeAt(0));
    }
  } catch {
    // localStorage unavailable — fall through to generate a session-scoped value
  }

  const secret = crypto.getRandomValues(new Uint8Array(SECRET_BYTE_LENGTH));
  try {
    localStorage.setItem(storageKey, btoa(String.fromCharCode(...secret)));
  } catch {
    // Persistence failure: this session's encryption will work, but the key
    // will not survive a page reload. Graceful degradation.
  }
  return secret;
};

// Both values are initialised eagerly at module load so every call to
// getDerivedKey() within a page session operates on the same key.
const DERIVED_KEY_MATERIAL = cryptoSupported ? getOrCreateSecret(MATERIAL_STORAGE_KEY) : null;
const DERIVED_KEY_SALT = cryptoSupported ? getOrCreateSecret(SALT_STORAGE_KEY) : null;

/**
 * Initialize or load key metadata.
 * Stores non-sensitive cryptographic parameters separately from encrypted data.
 *
 * @private
 */
const initializeKeyMetadata = () => {
  try {
    const stored = localStorage.getItem(KEY_METADATA_KEY);
    if (stored) {
      return JSON.parse(stored);
    }
  } catch (_e) {
    // localStorage unavailable or corrupted
  }

  // Create new metadata
  const metadata = {
    version: CRYPTO_CONFIG.VERSION,
    createdAt: new Date().toISOString(),
    iterations: CRYPTO_CONFIG.PBKDF2_ITERATIONS,
    algorithm: CRYPTO_CONFIG.ALGORITHM,
    keyLength: CRYPTO_CONFIG.KEY_LENGTH,
  };

  try {
    localStorage.setItem(KEY_METADATA_KEY, JSON.stringify(metadata));
  } catch (_e) {
    // Persistence failure - non-critical
  }

  return metadata;
};

let _keyMetadata = initializeKeyMetadata();
let _keyPromise = null;

const getDerivedKey = () => {
  if (_keyPromise) return _keyPromise;

  _keyPromise = (async () => {
    // Import the random per-browser key material as the PBKDF2 "password".
    // This replaces the previous window.location.origin usage, which was a
    // public value that allowed any attacker who knew the origin to precompute
    // PBKDF2 offline once they obtained the salt.
    const keyMaterial = await crypto.subtle.importKey(
      'raw',
      DERIVED_KEY_MATERIAL,
      'PBKDF2',
      false,
      ['deriveKey'],
    );

    // Use the iteration count from metadata for future compatibility
    const iterations = _keyMetadata?.iterations || CRYPTO_CONFIG.PBKDF2_ITERATIONS;

    return crypto.subtle.deriveKey(
      {
        name: 'PBKDF2',
        salt: DERIVED_KEY_SALT,
        iterations: iterations,
        hash: CRYPTO_CONFIG.PBKDF2_HASH,
      },
      keyMaterial,
      { name: CRYPTO_ALGORITHM, length: KEY_LENGTH },
      false,
      ['encrypt', 'decrypt'],
    );
  })();

  return _keyPromise;
};

/**
 * Encrypt a value with versioned payload structure.
 * Returns a JSON string containing version, IV, and ciphertext.
 *
 * @private
 * @param {string} storageKey - The localStorage key (used as additional data)
 * @param {string} plaintext - The plaintext value to encrypt
 * @returns {Promise<string>} JSON string with versioned payload
 */
const encryptValue = async (storageKey, plaintext) => {
  const key = await getDerivedKey();
  const encoder = new TextEncoder();
  const iv = crypto.getRandomValues(new Uint8Array(IV_LENGTH));
  const encrypted = await crypto.subtle.encrypt(
    { name: CRYPTO_ALGORITHM, iv, additionalData: encoder.encode(storageKey) },
    key,
    encoder.encode(plaintext),
  );
  const ivBase64 = btoa(String.fromCharCode(...iv));
  const ctBase64 = btoa(String.fromCharCode(...new Uint8Array(encrypted)));

  // Versioned payload structure
  const payload = {
    version: CRYPTO_CONFIG.VERSION,
    iv: ivBase64,
    ciphertext: ctBase64,
  };

  return JSON.stringify(payload);
};

/**
 * Decrypt a value, handling both legacy and versioned payloads.
 * Legacy format: `ivBase64:ctBase64`
 * Versioned format: JSON with version, iv, ciphertext fields
 *
 * @private
 * @param {string} storageKey - The localStorage key (used as additional data)
 * @param {string} stored - The stored encrypted value
 * @returns {Promise<string>} Decrypted plaintext
 */
const decryptValue = async (storageKey, stored) => {
  const key = await getDerivedKey();
  const encoder = new TextEncoder();

  // Try to parse as JSON (new versioned format)
  try {
    const payload = JSON.parse(stored);
    if (payload.version && payload.iv && payload.ciphertext) {
      // Versioned payload - use migration framework if needed
      return await decryptVersionedPayload(storageKey, payload, key);
    }
  } catch (_e) {
    // Not JSON or invalid - fall through to legacy format
  }

  // Legacy format: ivBase64:ctBase64
  const colonIdx = stored.indexOf(':');
  if (colonIdx === -1) throw new Error('Invalid ciphertext format');
  const ivBase64 = stored.slice(0, colonIdx);
  const ctBase64 = stored.slice(colonIdx + 1);
  const iv = Uint8Array.from(atob(ivBase64), (c) => c.charCodeAt(0));
  const ciphertext = Uint8Array.from(atob(ctBase64), (c) => c.charCodeAt(0));
  const decrypted = await crypto.subtle.decrypt(
    { name: CRYPTO_ALGORITHM, iv, additionalData: encoder.encode(storageKey) },
    key,
    ciphertext,
  );
  return new TextDecoder().decode(decrypted);
};

/**
 * Decrypt a versioned payload using the appropriate migration handler.
 *
 * @private
 * @param {string} storageKey - The localStorage key
 * @param {Object} payload - The versioned payload object
 * @param {CryptoKey} key - The decryption key
 * @returns {Promise<string>} Decrypted plaintext
 */
const decryptVersionedPayload = async (storageKey, payload, key) => {
  const encoder = new TextEncoder();
  const version = payload.version;

  // Route to version-specific decryption handler
  switch (version) {
    case 1:
      return await decryptV1(storageKey, payload, key, encoder);
    default:
      throw new Error(`Unsupported payload version: ${version}`);
  }
};

/**
 * Decrypt version 1 payloads.
 *
 * @private
 * @param {string} storageKey - The localStorage key
 * @param {Object} payload - The version 1 payload
 * @param {CryptoKey} key - The decryption key
 * @param {TextEncoder} encoder - Text encoder instance
 * @returns {Promise<string>} Decrypted plaintext
 */
const decryptV1 = async (storageKey, payload, key, encoder) => {
  const iv = Uint8Array.from(atob(payload.iv), (c) => c.charCodeAt(0));
  const ciphertext = Uint8Array.from(atob(payload.ciphertext), (c) => c.charCodeAt(0));
  const decrypted = await crypto.subtle.decrypt(
    { name: CRYPTO_ALGORITHM, iv, additionalData: encoder.encode(storageKey) },
    key,
    ciphertext,
  );
  return new TextDecoder().decode(decrypted);
};

/**
 * Migration framework for future cryptographic upgrades.
 * This provides a structured way to migrate data from older versions to newer ones.
 *
 * @private
 * @param {number} fromVersion - Source version
 * @param {number} toVersion - Target version
 * @param {string} storageKey - The localStorage key
 * @param {string} plaintext - The decrypted plaintext
 * @returns {Promise<string>} Re-encrypted value with new version
 */
// eslint-disable-next-line no-unused-vars -- Reserved for future migration implementations
const migratePayload = async (fromVersion, toVersion, storageKey, plaintext) => {
  // Future migrations can be implemented here
  // For now, v1 is current, so no migration needed
  if (fromVersion === toVersion) {
    return await encryptValue(storageKey, plaintext);
  }

  // Example future migration:
  // if (fromVersion === 1 && toVersion === 2) {
  //   return await encryptV2(storageKey, plaintext);
  // }

  throw new Error(`Migration from v${fromVersion} to v${toVersion} not implemented`);
};

/**
 * Rotate the encryption key.
 * This generates new key material while preserving the ability to decrypt
 * existing values during migration. After rotation, new writes use the new key.
 *
 * To fully migrate existing data, callers should:
 * 1. Call rotateKey()
 * 2. Read all existing values with getItemAsync()
 * 3. Re-write them with setItem()
 *
 * @returns {Promise<Object>} Metadata about the rotated key
 */
export const rotateKey = async () => {
  try {
    // Generate new key material
    const newMaterial = crypto.getRandomValues(new Uint8Array(SECRET_BYTE_LENGTH));
    const newSalt = crypto.getRandomValues(new Uint8Array(SECRET_BYTE_LENGTH));

    // Store new material
    localStorage.setItem(MATERIAL_STORAGE_KEY, btoa(String.fromCharCode(...newMaterial)));
    localStorage.setItem(SALT_STORAGE_KEY, btoa(String.fromCharCode(...newSalt)));

    // Update in-memory values
    DERIVED_KEY_MATERIAL.set(newMaterial);
    DERIVED_KEY_SALT.set(newSalt);

    // Reset key promise to force re-derivation
    _keyPromise = null;

    // Update metadata
    _keyMetadata = {
      version: CRYPTO_CONFIG.VERSION,
      createdAt: new Date().toISOString(),
      rotatedAt: new Date().toISOString(),
      iterations: CRYPTO_CONFIG.PBKDF2_ITERATIONS,
      algorithm: CRYPTO_CONFIG.ALGORITHM,
      keyLength: CRYPTO_CONFIG.KEY_LENGTH,
    };
    localStorage.setItem(KEY_METADATA_KEY, JSON.stringify(_keyMetadata));

    return _keyMetadata;
  } catch (error) {
    console.error('[secureStorage] Key rotation failed:', error);
    throw error;
  }
};

/**
 * Get the current key metadata.
 *
 * @returns {Object|null} Key metadata object or null if unavailable
 */
export const getKeyMetadata = () => {
  return _keyMetadata;
};

/**
 * Get the current crypto configuration.
 *
 * @returns {Object} Crypto configuration object
 */
export const getCryptoConfig = () => {
  return { ...CRYPTO_CONFIG };
};

/**
 * Derives an AES-256-GCM key from an explicit password and salt using PBKDF2.
 * Useful for callers (e.g. SessionRecoveryContext) that manage their own
 * key material outside the module-level DERIVED_KEY_MATERIAL / DERIVED_KEY_SALT.
 *
 * @param {string|Uint8Array} password - PBKDF2 input keying material
 * @param {Uint8Array}        salt     - PBKDF2 salt (at least 16 bytes recommended)
 * @returns {Promise<CryptoKey>}
 */
export const deriveKey = async (password, salt) => {
  const encoder = new TextEncoder();
  const material = password instanceof Uint8Array ? password : encoder.encode(password);
  const keyMaterial = await crypto.subtle.importKey("raw", material, "PBKDF2", false, ["deriveKey"]);
  return crypto.subtle.deriveKey(
    { name: "PBKDF2", salt, iterations: PBKDF2_ITERATIONS, hash: "SHA-256" },
    keyMaterial,
    { name: CRYPTO_ALGORITHM, length: KEY_LENGTH },
    false,
    ["encrypt", "decrypt"],
  );
};

/**
 * Encrypts plaintext with an already-derived AES-256-GCM key.
 * Returns ciphertext in the same `ivBase64:ctBase64` format used by the
 * module-level encryptValue, but does NOT attach additional authenticated data.
 *
 * @param {CryptoKey} key       - AES-GCM key from deriveKey()
 * @param {string}    plaintext - Value to encrypt
 * @returns {Promise<string>} `ivBase64:ctBase64`
 */
export const encryptWithKey = async (key, plaintext) => {
  const iv = crypto.getRandomValues(new Uint8Array(IV_LENGTH));
  const encrypted = await crypto.subtle.encrypt(
    { name: CRYPTO_ALGORITHM, iv },
    key,
    new TextEncoder().encode(plaintext),
  );
  return `${btoa(String.fromCharCode(...iv))}:${btoa(String.fromCharCode(...new Uint8Array(encrypted)))}`;
};

/**
 * Decrypts a ciphertext produced by encryptWithKey or the old encryptSession.
 *
 * @param {CryptoKey} key      - AES-GCM key from deriveKey()
 * @param {string}    stored   - Ciphertext string in `ivBase64:ctBase64` format
 * @returns {Promise<string>} Decrypted plaintext
 */
export const decryptWithKey = async (key, stored) => {
  const colonIdx = stored.indexOf(":");
  if (colonIdx === -1) throw new Error("Invalid ciphertext format");
  const iv = Uint8Array.from(atob(stored.slice(0, colonIdx)), (c) => c.charCodeAt(0));
  const ciphertext = Uint8Array.from(atob(stored.slice(colonIdx + 1)), (c) => c.charCodeAt(0));
  const decrypted = await crypto.subtle.decrypt({ name: CRYPTO_ALGORITHM, iv }, key, ciphertext);
  return new TextDecoder().decode(decrypted);
};

// ---------------------------------------------------------------------------
// Encrypted key-value storage wrapper (localStorage — AES-GCM encrypted)
// ---------------------------------------------------------------------------

// ---------------------------------------------------------------------------
// Legacy plaintext-fallback cleanup
// ---------------------------------------------------------------------------
// Previous versions of this module wrote `key + ':plaintext'` to localStorage
// synchronously before encryption completed so that data would survive a
// page close. This left sensitive values permanently in plaintext whenever
// the page was closed during the async encryption window.
//
// PLAINTEXT_SUFFIX is kept ONLY so that cleanupPlaintextFallbacks() can
// identify and remove those legacy keys on load. It must NOT be used for
// any new localStorage write.
// ---------------------------------------------------------------------------

const PLAINTEXT_SUFFIX = ':plaintext';

/**
 * Scans localStorage for keys ending in `':plaintext'` left behind by
 * the previous write strategy and removes them. Called once at module load.
 *
 * This is a one-time migration helper. Once all active clients have loaded
 * this version at least once, there will be no legacy keys left to clean up.
 *
 * @private
 */
const cleanupPlaintextFallbacks = () => {
  try {
    const toRemove = [];
    for (let i = 0; i < localStorage.length; i++) {
      const k = localStorage.key(i);
      if (k && k.endsWith(PLAINTEXT_SUFFIX)) toRemove.push(k);
    }
    toRemove.forEach((k) => localStorage.removeItem(k));
  } catch {
    // localStorage unavailable — nothing to clean up
  }
};

if (typeof window !== 'undefined') {
  // Best-effort: errors here must never prevent module load
  try { cleanupPlaintextFallbacks(); } catch { /* ignore */ }
}

// In-memory cache for pending writes — the sole mechanism for serving reads
// that arrive while async encryption is in progress. No plaintext is ever
// written to localStorage, so this Map is the only in-flight plaintext store.
const pendingWrites = new Map();

// Per-key write queue — chains encryption operations so concurrent writes to
// the same key complete sequentially. When a newer write is queued before the
// previous encryption finishes, the older write skips its localStorage write
// entirely, preventing stale ciphertext from overwriting newer values.
const writeQueue = new Map();
const writeCounters = new Map();

/**
 * Encrypts `value` and writes the ciphertext to localStorage under `key`.
 *
 * When Web Crypto is unavailable the raw value is written directly (the
 * caller's JSDoc documents this degraded mode explicitly).
 *
 * Errors from `encryptValue` are intentionally NOT caught here — they
 * propagate to `setItem`, which returns `false` so the caller knows the
 * write did not persist. Silently keeping a plaintext fallback on encryption
 * failure would undermine the entire security model.
 *
 * @private
 * @param {string} key   - localStorage key.
 * @param {string} value - Plaintext value to encrypt and store.
 * @returns {Promise<void>}
 */
const writeWithEncryption = async (key, value) => {
  if (!cryptoSupported) {
    localStorage.setItem(key, value);
    return;
  }
  const encrypted = await encryptValue(key, value);
  localStorage.setItem(key, encrypted);
};

const KEYS_METADATA_KEY = 'eventra:keys';

const trackKey = (key) => {
  try {
    if (key === KEYS_METADATA_KEY || key === MATERIAL_STORAGE_KEY || key === SALT_STORAGE_KEY) {
      return;
    }
    const stored = localStorage.getItem(KEYS_METADATA_KEY);
    let keys = [];
    if (stored) {
      keys = JSON.parse(stored);
      if (!Array.isArray(keys)) keys = [];
    }
    if (!keys.includes(key)) {
      keys.push(key);
      localStorage.setItem(KEYS_METADATA_KEY, JSON.stringify(keys));
    }
  } catch (e) {
    // Ignore localStorage/JSON errors
  }
};

const untrackKey = (key) => {
  try {
    const stored = localStorage.getItem(KEYS_METADATA_KEY);
    if (stored) {
      let keys = JSON.parse(stored);
      if (Array.isArray(keys)) {
        const idx = keys.indexOf(key);
        if (idx !== -1) {
          keys.splice(idx, 1);
          localStorage.setItem(KEYS_METADATA_KEY, JSON.stringify(keys));
        }
      }
    }
  } catch (e) {
    // Ignore localStorage/JSON errors
  }
};

export const syncSecureStorage = {
  /**
   * Encrypts `value` and stores it under `key` in localStorage.
   *
   * While encryption is in progress the value is held in the in-memory
   * `pendingWrites` Map so that concurrent `getItem` / `getItemAsync` calls
   * within the same page session return the correct value immediately.
   *
   * **No plaintext is written to localStorage at any point.** If the page
   * is closed or navigated away before encryption completes, the data will
   * not be persisted — this is an intentional tradeoff: data loss is
   * preferable to permanent plaintext exposure.
   *
   * When Web Crypto is unavailable (non-HTTPS / legacy browser) the raw
   * value is stored directly; `isEncryptionActive()` will return `false`
   * so callers can surface a warning to the user if needed.
   *
   * @param {string} key   - localStorage key.
   * @param {string} value - Plaintext string to encrypt and store.
   * @returns {Promise<boolean>} `true` on success; `false` when the write
   *   could not be persisted (localStorage full, encryption error, etc.).
   */
  setItem: async (key, value) => {
    try {
      pendingWrites.set(key, value);
      trackKey(key);

      const counter = (writeCounters.get(key) || 0) + 1;
      writeCounters.set(key, counter);
      const ourCounter = counter;

      const prev = (writeQueue.get(key) || Promise.resolve())
        .catch(() => {});
      const next = prev.then(async () => {
        if (writeCounters.get(key) !== ourCounter) return;
        await writeWithEncryption(key, value);
      });
      writeQueue.set(key, next);

      await next;

      if (writeCounters.get(key) !== ourCounter) return true;

      writeCounters.delete(key);
      pendingWrites.delete(key);
      writeQueue.delete(key);
      return true;
    } catch (error) {
      console.error('[secureStorage] setItem failed:', error);
      pendingWrites.delete(key);
      writeQueue.delete(key);
      writeCounters.delete(key);
      return false;
    }
  },

  /**
   * Returns the raw stored bytes for the given key without decrypting.
   *
   * If a write for this key is currently in progress, the pending
   * plaintext value is returned from the in-memory Map so callers always
   * see the latest value within a session.
   *
   * For decrypted values use `getItemAsync()`.
   *
   * @param {string} key
   * @returns {string|null} Raw ciphertext string, in-flight plaintext from
   *   `pendingWrites`, or `null` when the key does not exist.
   */
  getItem: (key) => {
    try {
      if (pendingWrites.has(key)) {
        return pendingWrites.get(key);
      }
      return localStorage.getItem(key);
    } catch (error) {
      console.error('[secureStorage] getItem failed:', error);
      return null;
    }
  },

  /**
   * Retrieves and decrypts the value stored under the given key.
   *
   * Resolution order:
   * 1. `pendingWrites` Map — returns the in-flight plaintext immediately if
   *    a `setItem` for this key is still running.
   * 2. localStorage ciphertext — decrypted with the derived AES-GCM key.
   *    If decryption fails (e.g. key material was lost between sessions) the
   *    raw stored string is returned as a best-effort fallback so callers
   *    can surface an error rather than silently returning `null`.
   * 3. When Web Crypto is unavailable the raw stored value is returned
   *    directly (plaintext was written by `setItem` in degraded mode).
   *
   * @param {string} key
   * @returns {Promise<string|null>} Decrypted value, raw fallback, or `null`
   *   when the key does not exist or an unrecoverable error occurs.
   */
  getItemAsync: async (key) => {
    try {
      if (pendingWrites.has(key)) {
        return pendingWrites.get(key);
      }

      const stored = localStorage.getItem(key);
      if (stored === null) return null;

      if (cryptoSupported) {
        try {
          return await decryptValue(key, stored);
        } catch {
          return stored;
        }
      }

      return stored;
    } catch (error) {
      console.error('[secureStorage] getItemAsync failed:', error);
      return null;
    }
  },

  /**
   * Removes the value stored under the given key.
   *
   * Also removes the legacy `key + ':plaintext'` entry if one exists on
   * disk from a previous version of this module, ensuring no stale
   * plaintext survives a targeted delete.
   *
   * @param {string} key
   */
  removeItem: (key) => {
    try {
      pendingWrites.delete(key);
      writeQueue.delete(key);
      writeCounters.delete(key);
      localStorage.removeItem(key);
      localStorage.removeItem(key + PLAINTEXT_SUFFIX);
      untrackKey(key);
    } catch (error) {
      console.error('[secureStorage] removeItem failed:', error);
    }
  },

  /**
   * Clears all Eventra-managed keys from localStorage.
   *
   * Iterates only over keys starting with the Eventra prefix ('eventra:')
   * so data from other applications on the same origin is never touched.
   */
  clear: () => {
    try {
      pendingWrites.clear();
      writeQueue.clear();
      writeCounters.clear();

      try {
        const stored = localStorage.getItem(KEYS_METADATA_KEY);
        if (stored) {
          const keys = JSON.parse(stored);
          if (Array.isArray(keys)) {
            keys.forEach((k) => {
              localStorage.removeItem(k);
              localStorage.removeItem(k + PLAINTEXT_SUFFIX);
            });
          }
        }
      } catch (e) {
        // Ignore JSON errors
      }

      const prefix = "eventra:";
      const toRemove = [];
      for (let i = 0; i < localStorage.length; i++) {
        const k = localStorage.key(i);
        if (k && k.startsWith(prefix)) toRemove.push(k);
      }
      toRemove.forEach((k) => localStorage.removeItem(k));

      _keyPromise = null;
    } catch (error) {
      console.error('[secureStorage] clear failed:', error);
    }
  },

  /**
   * Returns whether AES-GCM encryption is active in the current context.
   *
   * @returns {boolean}
   */
  isEncryptionActive: () => cryptoSupported,

  /**
   * Get the current key metadata.
   *
   * @returns {Object|null} Key metadata object or null if unavailable
   */
  getKeyMetadata: () => getKeyMetadata(),

  /**
   * Get the current crypto configuration.
   *
   * @returns {Object} Crypto configuration object
   */
  getCryptoConfig: () => getCryptoConfig(),

  /**
   * Rotate the encryption key.
   * This generates new key material while preserving the ability to decrypt
   * existing values during migration.
   *
   * @returns {Promise<Object>} Metadata about the rotated key
   */
  rotateKey: () => rotateKey(),
};

export function logSecurityEvent(eventType, data) {
  if (!eventType || typeof eventType !== "string") {
    eventType = "UNKNOWN_SECURITY_EVENT";
  }

  const formattedData = {
    timestamp: new Date().toISOString(),
    userAgent: typeof navigator !== "undefined" ? navigator.userAgent : "unknown",
    url: typeof window !== "undefined" ? window.location.href : "unknown",
    payload: data || {}
  };

  console.warn(`[SECURITY EVENT] ${eventType}`, formattedData);

  // Store in LocalStorage with logs rotation (limit to 50 logs)
  try {
    if (typeof localStorage !== "undefined") {
      const raw = localStorage.getItem("eventra_security_events");
      let logs = raw ? JSON.parse(raw) : [];
      if (!Array.isArray(logs)) logs = [];

      logs.push({ eventType, ...formattedData });
      if (logs.length > 50) {
        logs = logs.slice(-50);
      }

      localStorage.setItem("eventra_security_events", JSON.stringify(logs));
    }
  } catch (err) {
    // Ignore storage failures (e.g. QuotaExceededError or private browsing)
  }
}

export function logCspViolation(report) {
  if (report && typeof report === "object") {
    logSecurityEvent("CSP_VIOLATION", report);
  }
}

import { apiUtils } from "../config/api.js";

const DEFAULT_TIMEOUT_MS = 8000;
const DEFAULT_RETRIES = 1;
const RETRYABLE_STATUS_CODES = [408, 429, 500, 502, 503, 504];

const wait = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

/**
 * Builds the standard validation response object used across async validators.
 *
 * @param {boolean} isValid - Whether the value passed validation.
 * @param {string} [message=""] - Message shown when validation fails.
 * @param {Object} [extra={}] - Extra metadata such as API data, status, or error details.
 * @returns {{isValid: boolean, message: string, isLoading: boolean}} Normalized response.
 */
export const createValidationResponse = (
  isValid,
  message = "",
  extra = {},
) => ({
  isValid: Boolean(isValid),
  message: isValid ? "" : message,
  isLoading: false,
  ...extra,
});

/**
 * Builds a temporary response for UI states while an async validator is running.
 *
 * @param {string} [message="Validating..."] - Loading message shown to users.
 * @returns {{isValid: boolean, message: string, isLoading: boolean}}
 */
export const validationLoadingResponse = (message = "Validating...") => ({
  isValid: false,
  message,
  isLoading: true,
});

/**
 * Converts common validation API payloads into the standard response shape.
 *
 * Supported payload examples include booleans, `{ isValid: true }`,
 * `{ valid: false }`, and availability checks like `{ available: true }`.
 *
 * @param {boolean|Object} data - Raw API response data.
 * @param {Object} [options]
 * @param {string} [options.validMessage=""] - Message used for valid results.
 * @param {string} [options.invalidMessage="Validation failed"] - Message used for invalid results.
 * @param {string} [options.availabilityField="available"] - Field name to read for availability APIs.
 * @returns {{isValid: boolean, message: string, isLoading: boolean, data: *}}
 */
export const normalizeValidationApiResponse = (
  data,
  {
    validMessage = "",
    invalidMessage = "Validation failed",
    availabilityField = "available",
  } = {},
) => {
  if (typeof data === "boolean") {
    return createValidationResponse(data, data ? validMessage : invalidMessage, {
      data,
    });
  }

  const hasIsValid = typeof data?.isValid === "boolean";
  const hasValid = typeof data?.valid === "boolean";
  const hasAvailable = typeof data?.[availabilityField] === "boolean";
  const isValid = hasIsValid
    ? data.isValid
    : hasValid
      ? data.valid
      : hasAvailable
        ? data[availabilityField]
        : false;

  return createValidationResponse(
    isValid,
    data?.message || (isValid ? validMessage : invalidMessage),
    { data },
  );
};

/**
 * Sends a validation request with timeout, retry, JSON parsing, and fallback errors.
 *
 * Retryable HTTP status codes are retried with a small increasing delay. Timeout,
 * missing `fetch`, network failures, and invalid responses are converted into
 * user-safe validation responses instead of throwing.
 *
 * @param {string} endpoint - URL or path to request.
 * @param {Object} [options]
 * @param {string} [options.method="GET"] - HTTP method.
 * @param {Object} [options.body] - JSON body sent with the request.
 * @param {Object} [options.headers={}] - Extra request headers.
 * @param {number} [options.timeoutMs=8000] - Abort timeout in milliseconds.
 * @param {number} [options.retries=1] - Number of retry attempts for retryable failures.
 * @param {number} [options.retryDelayMs=300] - Base retry delay in milliseconds.
 * @param {string} [options.invalidMessage="Validation failed"] - Fallback invalid message.
 * @param {string} [options.networkMessage] - Fallback network error message.
 * @param {string} [options.validMessage=""] - Message used for valid responses.
 * @param {string} [options.availabilityField="available"] - Availability field in API payloads.
 * @returns {Promise<{isValid: boolean, message: string, isLoading: boolean}>}
 */
export const requestValidation = async (endpoint, options = {}) => {
  const {
    method = "GET",
    body,
    headers = {},
    timeoutMs = DEFAULT_TIMEOUT_MS,
    retries = DEFAULT_RETRIES,
    retryDelayMs = 300,
    invalidMessage = "Validation failed",
    networkMessage = "Unable to validate right now. Please try again.",
    validMessage = "",
    availabilityField = "available",
  } = options;

  let lastError = null;

  for (let attempt = 0; attempt <= retries; attempt += 1) {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

    try {
      const config = { headers, signal: controller.signal };
      let response;
      const uppercaseMethod = method.toUpperCase();

      if (uppercaseMethod === "GET") {
        response = await apiUtils.get(endpoint, config);
      } else if (uppercaseMethod === "POST") {
        response = await apiUtils.post(endpoint, body, config);
      } else if (uppercaseMethod === "PUT") {
        response = await apiUtils.put(endpoint, body, config);
      } else if (uppercaseMethod === "PATCH") {
        response = await apiUtils.patch(endpoint, body, config);
      } else if (uppercaseMethod === "DELETE") {
        response = await apiUtils.delete(endpoint, config);
      } else {
        response = await apiUtils.get(endpoint, config);
      }

      clearTimeout(timeoutId);

      let data = null;
      try {
        data = await response.json();
      } catch {
        data = null;
      }

      return normalizeValidationApiResponse(data, {
        validMessage,
        invalidMessage,
        availabilityField,
      });
    } catch (error) {
      clearTimeout(timeoutId);
      lastError = error;

      const status = error.status;
      const data = error.data;

      // If the API explicitly returned a validation failure (like 400, 409)
      if (status === 401 || status === 403) {
        return createValidationResponse(
          false,
          networkMessage,
          { status, data }
        );
      }

      // Retry on network errors, timeouts, or 5xx server errors
      if (attempt < retries) {
        await wait(retryDelayMs * (attempt + 1));
        continue;
      }
    }
  }

  const timedOut = lastError?.isTimeout || lastError?.name === "AbortError";
  return createValidationResponse(
    false,
    timedOut ? "Validation request timed out. Please try again." : networkMessage,
    {
      error: lastError,
      isTimeout: timedOut,
      isNetworkError: !timedOut,
    },
  );
};

/**
 * Checks whether an email is available using the configured API endpoint.
 *
 * @param {string} email - Email address to check.
 * @param {Object} [options] - `requestValidation` options plus optional `endpoint`.
 * @returns {Promise<{isValid: boolean, message: string, isLoading: boolean}>}
 */
export const checkEmailAvailability = (email, options = {}) =>
  requestValidation(
    options.endpoint || `/api/validate/email/${encodeURIComponent(email)}`,
    {
      invalidMessage: "Email is already registered",
      validMessage: "",
      ...options,
    },
  );

/**
 * Checks whether a username is available using the configured API endpoint.
 *
 * @param {string} username - Username to check.
 * @param {Object} [options] - `requestValidation` options plus optional `endpoint`.
 * @returns {Promise<{isValid: boolean, message: string, isLoading: boolean}>}
 */
export const checkUsernameAvailability = (username, options = {}) =>
  requestValidation(
    options.endpoint ||
      `/api/validate/username/${encodeURIComponent(username)}`,
    {
      invalidMessage: "Username is already taken",
      validMessage: "",
      ...options,
    },
  );

/**
 * Validates a phone number through the configured API endpoint.
 *
 * The default endpoint expects a POST body of `{ phone }` and reads the `valid`
 * response field.
 *
 * @param {string} phone - Phone number to validate.
 * @param {Object} [options] - `requestValidation` options plus optional `endpoint`.
 * @returns {Promise<{isValid: boolean, message: string, isLoading: boolean}>}
 */
export const checkPhoneValidation = (phone, options = {}) =>
  requestValidation(options.endpoint || "/api/validate/phone", {
    method: "POST",
    body: { phone },
    availabilityField: "valid",
    invalidMessage: "Phone number is invalid",
    validMessage: "",
    ...options,
  });

const validationApi = {
  checkEmailAvailability,
  checkUsernameAvailability,
  checkPhoneValidation,
  createValidationResponse,
  normalizeValidationApiResponse,
  requestValidation,
  validationLoadingResponse,
};

export default validationApi;
